# ASP.NET Core 10 — Quick Reference

## Project File (no PackageReference for framework)

```xml
<ItemGroup>
  <FrameworkReference Include="Microsoft.AspNetCore.App" />
</ItemGroup>
```

## Minimal API with Built-in Validation

```csharp
// [Required], [Range] etc. auto-validated in .NET 10
app.MapPost("/orders", ([Required] string name, [Range(1,100)] int qty) =>
    Results.Ok(new { name, qty }));
```

## Result Helpers

```csharp
Results.Ok(payload)           // 200
Results.Created("/path", obj) // 201
Results.NoContent()           // 204
Results.NotFound()            // 404
Results.BadRequest("msg")     // 400
Results.Problem(detail: "err", statusCode: 500)  // ProblemDetails RFC 9457
Results.ValidationProblem(errors)
```

## ProblemDetails Standard Error

```csharp
app.UseExceptionHandler(err => err.Run(async ctx =>
{
    ctx.Response.ContentType = "application/problem+json";
    await ctx.Response.WriteAsJsonAsync(new ProblemDetails
    {
        Title = "Server Error",
        Status = 500,
        Detail = "Unexpected error occurred"
    });
}));
```

## DI Lifetimes

```csharp
services.AddScoped<IOrderService, OrderService>();    // per HTTP request
services.AddSingleton<ICache, MemoryCache>();         // app lifetime
services.AddTransient<IEmailSender, EmailSender>();  // new each injection
```

## Options Pattern

```csharp
// appsettings.json: { "Smtp": { "Host": "...", "Port": 587 } }
services.Configure<SmtpOptions>(config.GetSection("Smtp"));

// Inject:
public class EmailSender(IOptions<SmtpOptions> opts) { }
```

## Typed HttpClient

```csharp
services.AddHttpClient<IGitHubClient, GitHubClient>(c =>
    c.BaseAddress = new Uri("https://api.github.com/"));
```

**Source:** https://learn.microsoft.com/en-us/aspnet/core/release-notes/aspnetcore-10.0


# OneOf v3.0.271 — Quick Reference

**Package:** `OneOf`
**Namespace:** `using OneOf;`

## Define Discriminated Union

```csharp
// Up to 9 type params
OneOf<User, NotFound, Error> result;

// Custom types
public record NotFound(int Id);
public record ValidationError(string[] Errors);

// Match to extract value
result.Switch(
    user => Console.WriteLine($"User: {user.Name}"),
    notFound => Console.WriteLine($"Not found: {notFound.Id}"),
    error => Console.WriteLine($"Error: {error.Message}")
);
```

## Return from Method

```csharp
public OneOf<Order, NotFound> GetOrder(int id)
{
    var order = _repository.Find(id);
    return order is null ? new NotFound(id) : order;
}
```

---

## Task: E-Commerce Order Management Controller

Create an ASP.NET Core 10 API controller for an e-commerce order management system that uses `OneOf<T>` for robust result handling.

### Requirements

**1. Domain Models (use record types):**

- `Order` with properties: `Guid Id`,

using Microsoft.AspNetCore.Mvc;
using OneOf;
using System.ComponentModel.DataAnnotations;

// Domain Models
public record Order(
    Guid Id,
    string CustomerName,
    string CustomerEmail,
    List<OrderItem> Items,
    OrderStatus Status,
    decimal Total,
    DateTime CreatedAt,
    DateTime? ShippedAt
);

public record OrderItem(
    Guid ProductId,
    string ProductName,
    int Quantity,
    decimal UnitPrice
);

public record CreateOrderRequest(
    [Required] string CustomerName,
    [Required, EmailAddress] string CustomerEmail,
    [Required, MinLength(1)] List<CreateOrderItemRequest> Items
);

public record CreateOrderItemRequest(
    [Required] Guid ProductId,
    [Range(1, 100)] int Quantity
);

public record UpdateOrderStatusRequest(
    [Required] OrderStatus Status
);

// Discriminated Union Types
public record OrderNotFound(Guid OrderId);
public record ValidationError(string[] Errors);
public record InsufficientStock(Guid ProductId, int Requested, int Available);
public record OrderAlreadyShipped(Guid OrderId);

// Enums
public enum OrderStatus
{
    Pending = 0,
    Confirmed = 1,
    Shipped = 2,
    Delivered = 3,
    Cancelled = 4
}

// DTOs
public record Product(
    Guid Id,
    string Name,
    decimal Price,
    int StockQuantity
);

// Service Interface
public interface IOrderService
{
    Task<OneOf<Order, ValidationError>> CreateOrderAsync(CreateOrderRequest request);
    Task<OneOf<Order, OrderNotFound>> GetOrderAsync(Guid id);
    Task<OneOf<Order, OrderNotFound, OrderAlreadyShipped>> UpdateOrderStatusAsync(Guid id, UpdateOrderStatusRequest request);
    Task<OneOf<List<Order>, OrderNotFound>> GetOrdersByCustomerEmailAsync(string email);
    Task<OneOf<bool, OrderNotFound, OrderAlreadyShipped>> CancelOrderAsync(Guid id);
}

// Service Implementation
public class OrderService : IOrderService
{
    private readonly Dictionary<Guid, Order> _orders = new();
    private readonly Dictionary<Guid, Product> _products;
    private int _orderCounter = 0;

    public OrderService()
    {
        // Initialize with some sample products
        _products = new Dictionary<Guid, Product>
        {
            [Guid.Parse("00000000-0000-0000-0000-000000000001")] = new(Guid.Parse("00000000-0000-0000-0000-000000000001"), "Laptop", 999.99m, 50),
            [Guid.Parse("00000000-0000-0000-0000-000000000002")] = new(Guid.Parse("00000000-0000-0000-0000-000000000002"), "Mouse", 29.99m, 200),
            [Guid.Parse("00000000-0000-0000-0000-000000000003")] = new(Guid.Parse("00000000-0000-0000-0000-000000000003"), "Keyboard", 79.99m, 150)
        };
    }

    public Task<OneOf<Order, ValidationError>> CreateOrderAsync(CreateOrderRequest request)
    {
        var errors = new List<string>();

        if (string.IsNullOrWhiteSpace(request.CustomerName))
            errors.Add("Customer name is required");

        if (string.IsNullOrWhiteSpace(request.CustomerEmail))
            errors.Add("Customer email is required");

        if (request.Items == null || request.Items.Count == 0)
            errors.Add("At least one order item is required");

        var orderItems = new List<OrderItem>();
        decimal total = 0;

        foreach (var item in request.Items ?? Enumerable.Empty<CreateOrderItemRequest>())
        {
            if (!_products.TryGetValue(item.ProductId, out var product))
            {
                errors.Add($"Product with ID {item.ProductId} not found");
                continue;
            }

            if (item.Quantity > product.StockQuantity)
            {
                errors.Add($"Insufficient stock for {product.Name}. Requested: {item.Quantity}, Available: {product.StockQuantity}");
                continue;
            }

            orderItems.Add new OrderItem(product.Id, product.Name, item.Quantity, product.Price);
            total += product.Price * item.Quantity;
        }

        if (errors.Count > 0)
            return Task.FromResult(OneOf<Order, ValidationError>.FromT1(new ValidationError(errors.ToArray())));

        var order = new Order(
            Id: Guid.NewGuid(),
            CustomerName: request.CustomerName,
            CustomerEmail: request.CustomerEmail,
            Items: orderItems,
            Status: OrderStatus.Pending,
            Total: total,
            CreatedAt: DateTime.UtcNow,
            ShippedAt: null
        );

        _orders[order.Id] = order;
        return Task.FromResult(OneOf<Order, ValidationError>.FromT0(order));
    }

    public Task<OneOf<Order, OrderNotFound>> GetOrderAsync(Guid id)
    {
        if (_orders.TryGetValue(id, out var order))
            return Task.FromResult(OneOf<Order, OrderNotFound>.FromT0(order));

        return Task.FromResult(OneOf<Order, OrderNotFound>.FromT1(new OrderNotFound(id)));
    }

    public Task<OneOf<Order, OrderNotFound, OrderAlreadyShipped>> UpdateOrderStatusAsync(Guid id, UpdateOrderStatusRequest request)
    {
        if (!_orders.TryGetValue(id, out var existingOrder))
            return Task.FromResult(OneOf<Order, OrderNotFound, OrderAlreadyShipped>.FromT1(new OrderNotFound(id)));

        if (existingOrder.Status == OrderStatus.Shipped && request.Status != OrderStatus.Delivered)
            return Task.FromResult(OneOf<Order, OrderNotFound, OrderAlreadyShipped>.FromT2(new OrderAlreadyShipped(id)));

        var updatedOrder = existingOrder with
        {
            Status = request.Status,
            ShippedAt = request.Status == OrderStatus.Shipped ? DateTime.UtcNow : existingOrder.ShippedAt
        };

        _orders[id] = updatedOrder;
        return Task.FromResult(OneOf<Order, OrderNotFound, OrderAlreadyShipped>.FromT0(updatedOrder));
    }

    public Task<OneOf<List<Order>, OrderNotFound>> GetOrdersByCustomerEmailAsync(string email)
    {
        var orders = _orders.Values
            .Where(o => o.CustomerEmail.Equals(email, StringComparison.OrdinalIgnoreCase))
            .ToList();

        if (orders.Count == 0)
            return Task.FromResult(OneOf<List<Order>, OrderNotFound>.FromT1(new OrderNotFound(Guid.Empty)));

        return Task.FromResult(OneOf<List<Order>, OrderNotFound>.FromT0(orders));
    }

    public Task<OneOf<bool, OrderNotFound, OrderAlreadyShipped>> CancelOrderAsync(Guid id)
    {
        if (!_orders.TryGetValue(id, out var order))
            return Task.FromResult(OneOf<bool, OrderNotFound, OrderAlreadyShipped>.FromT1(new OrderNotFound(id)));

        if (order.Status == OrderStatus.Shipped || order.Status == OrderStatus.Delivered)
            return Task.FromResult(OneOf<bool, OrderNotFound, OrderAlreadyShipped>.FromT2(new OrderAlreadyShipped(id)));

        var cancelledOrder = order with { Status = OrderStatus.Cancelled };
        _orders[id] = cancelledOrder;
        return Task.FromResult(OneOf<bool, OrderNotFound, OrderAlreadyShipped>.FromT0(true));
    }
}

// Minimal API Program
public class Program
{
    public static void Main(string[] args)
    {
        var builder = WebApplication.CreateBuilder(args);

        builder.Services.AddScoped<IOrderService, OrderService>();

        var app = builder.Build();

        app.UseExceptionHandler(err => err.Run(async ctx =>
        {
            ctx.Response.ContentType = "application/problem+json";
            await ctx.Response.WriteAsJsonAsync(new ProblemDetails
            {
                Title = "Server Error",
                Status = 500,
                Detail = "An unexpected error occurred"
            });
        }));

        // Create Order
        app.MapPost("/orders", async (CreateOrderRequest request, IOrderService service) =>
        {
            var result = await service.CreateOrderAsync(request);

            return result.Match<Order, ValidationError, IResult>(
                order => Results.Created($"/orders/{order.Id}", order),
                validation => Results.BadRequest(validation)
            );
        });

        // Get Order by ID
        app.MapGet("/orders/{id:guid}", async (Guid id, IOrderService service) =>
        {
            var result = await service.GetOrderAsync(id);

            return result.Match<Order, OrderNotFound, IResult>(
                order => Results.Ok(order),
                notFound => Results.NotFound(new { Error = $"Order with ID {notFound.OrderId} not found" })
            );
        });

        // Update Order Status
        app.MapPut("/orders/{id:guid}/status", async (Guid id, UpdateOrderStatusRequest request, IOrderService service) =>
        {
            var result = await service.UpdateOrderStatusAsync(id, request);

            return result.Match<Order, OrderNotFound, OrderAlreadyShipped, IResult>(
                order => Results.Ok(order),
                notFound => Results.NotFound(new { Error = $"Order with ID {notFound.OrderId} not found" }),
                alreadyShipped => Results.BadRequest(new { Error = $"Order {alreadyShipped.OrderId} is already shipped and cannot be modified" })
            );
        });

        // Get Orders by Customer Email
        app.MapGet("/orders/customer/{email}", async (string email, IOrderService service) =>
        {
            var result = await service.GetOrdersByCustomerEmailAsync(email);

            return result.Match<List<Order>, OrderNotFound, IResult>(
                orders => Results.Ok(orders),
                notFound => Results.NotFound(new { Error = $"No orders found for email" })
            );
        });

        // Cancel Order
        app.MapPost("/orders/{id:guid}/cancel", async (Guid id, IOrderService service) =>
        {
            var result = await service.CancelOrderAsync(id);

            return result.Match<bool, OrderNotFound, OrderAlreadyShipped, IResult>(
                _ => Results.NoContent(),
                notFound => Results.NotFound(new { Error = $"Order with ID {notFound.OrderId} not found" }),
                alreadyShipped => Results.BadRequest(new { Error = $"Order {alreadyShipped.OrderId} cannot be cancelled - already shipped" })
            );
        });

        app.Run();
    }
}

