public class OrderService : IOrderService
{
    private readonly Dictionary<Guid, Order> _orders = new();

    public OneOf<Order, NotFoundError> CreateOrder(CreateOrderRequest request, Guid customerId)
    {
        var items = request.Items
            .Select(i => new OrderItem(i.ProductId, i.ProductName, i.Quantity, i.UnitPrice))
            .ToList();

        var totalAmount = items.Sum(i => i.Quantity * i.UnitPrice);

        var order = new Order(
            Guid.NewGuid(),
            customerId,
            items.AsReadOnly(),
            totalAmount,
            OrderStatus.Pending,
            DateTimeOffset.UtcNow,
            request.ShippingAddress
        );

        _orders[order.OrderId] = order;
        return order;
    }

    public OneOf<Order, NotFoundError> GetOrder(Guid orderId) =>
        _orders.TryGetValue(orderId, out var order)
            ? order
            : new NotFoundError("Order not found");

    public OneOf<Order, NotFoundError, ValidationError> UpdateOrderStatus(Guid orderId, OrderStatus newStatus, CustomerRole role)
    {
        if (!_orders.TryGetValue(orderId, out var order))
            return new NotFoundError("Order not found");

        if (newStatus == OrderStatus.Shipped || newStatus == OrderStatus.Delivered)
        {
            if (role != CustomerRole.Admin)
            {
                return new ValidationError(new Dictionary<string, string[]>
                {
                    ["Status"] = new[] { "Only administrators can mark orders as shipped or delivered" }
                });
            }
        }

        if (order.Status == OrderStatus.Cancelled)
        {
            return new ValidationError(new Dictionary<string, string[]>
            {
                ["Status"] = new[] { "Cannot update status of a cancelled order" }
            });
        }

        var updatedOrder = order with { Status = newStatus };
        _orders[orderId] = updatedOrder;
        return updatedOrder;
    }

