// Service Implementation
public class TradingOrderService : ITradingOrderService
{
    private readonly Dictionary<int, Order> _orders = new();
    private int _nextId = 1;

    public Task<OneOf<Order, OrderNotFound, ValidationError>> GetOrderAsync(int orderId)
    {
        if (orderId <= 0)
            return Task.FromResult<OneOf<Order, OrderNotFound, ValidationError>>(
                new ValidationError(["OrderId must be positive"]));

        if (_orders.TryGetValue(orderId, out var order))
            return Task.FromResult<OneOf<Order, OrderNotFound, ValidationError>>(order);

        return Task.FromResult<OneOf<Order, OrderNotFound, ValidationError>>(
            new OrderNotFound(orderId));
    }

    public Task<OneOf<OrderCreated, InsufficientFunds, MarketClosed, ValidationError>> CreateOrderAsync(CreateOrderRequest request)
    {
        var errors = new List<string>();

        if (string.IsNullOrWhiteSpace(request.Symbol))
            errors.Add("Symbol is required");

        if (request.Side != "Buy" && request.Side != "Sell")
            errors.Add("Side must be 'Buy' or 'Sell'");

        if (request.OrderType != "Market" && request.OrderType != "Limit")
            errors.Add("OrderType must be 'Market' or 'Limit'");

        if (errors.Count > 0)
            return Task.FromResult<OneOf<OrderCreated, InsufficientFunds, MarketClosed, ValidationError>>(
                new ValidationError(errors.ToArray()));

        // Simulate market closed check
        if (request.Symbol.EndsWith("X", StringComparison.OrdinalIgnoreCase))
            return Task.FromResult<OneOf<OrderCreated, InsufficientFunds, MarketClosed, ValidationError>>(
                new MarketClosed(request.Symbol));

        // Simulate insufficient funds for large orders
        var orderValue = request.Quantity * request.Price;
        if (orderValue > 1_000_000)
            return Task.FromResult<OneOf<OrderCreated, InsufficientFunds, MarketClosed, ValidationError>>(
                new InsufficientFunds(available: 1_000_000, required: orderValue));

        var orderId = _nextId++;
        var order = new Order(orderId, request.Symbol, request.Side, request.Quantity, request.Price, request.OrderType, "Pending", DateTime.UtcNow);
        _orders[orderId] = order;

        return Task.FromResult<OneOf<OrderCreated, InsufficientFunds, MarketClosed, ValidationError>>(
            new OrderCreated(orderId, request.Symbol, DateTime.UtcNow));
    }

    public Task<OneOf<IEnumerable<Order>, ValidationError>> GetOrdersBySymbolAsync(string symbol)
    {
        if (string.IsNullOrWhiteSpace(symbol))
            return Task.FromResult<OneOf<IEnumerable<Order>, ValidationError>>(
                new ValidationError(["Symbol is required"]));

        var orders = _orders.Values.Where(o => o.Symbol.Equals(symbol, StringComparison.OrdinalIgnoreCase));
        return Task.FromResult<OneOf<IEnumerable<Order>, ValidationError>>(orders);
    }
}

