public class TraderService : ITraderService
{
    private readonly Dictionary<Guid, Trader> _traders = new();
    private readonly Dictionary<string, ApiKey> _apiKeys = new();

    public Task<OneOf<Trader, NotFoundError, ValidationError>> CreateTraderAsync(CreateTraderRequest request)
    {
        if (_traders.Values.Any(t => t.Email.Equals(request.Email, StringComparison.OrdinalIgnoreCase)))
            return Task.FromResult(OneOf<Trader, NotFoundError, ValidationError>
                .FromT2(new ValidationError("Email already exists")));

        if (_traders.Values.Any(t => t.Username.Equals(request.Username, StringComparison.OrdinalIgnoreCase)))
            return Task.FromResult(OneOf<Trader, NotFoundError, ValidationError>
                .FromT2(new ValidationError("Username already exists")));

        var trader = new Trader(
            Guid.NewGuid(),
            request.Username,
            request.Email,
            request.Role,
            request.TradingLimit,
            IsActive: true);

        _traders[trader.Id] = trader;
        return Task.FromResult(OneOf<Trader, NotFoundError, ValidationError>.FromT0(trader));
    }

    public Task<OneOf<Trader, NotFoundError>> GetTraderByIdAsync(Guid id)
    {
        if (_traders.TryGetValue(id, out var trader))
            return Task.FromResult(OneOf<Trader, NotFoundError>.FromT0(trader));

        return Task.FromResult(OneOf<Trader, NotFoundError>.FromT1(new NotFoundError("Trader not found")));
    }

    public Task<OneOf<ApiKey, NotFoundError>> GenerateApiKeyAsync(Guid traderId, string[] permissions)
    {
        if (!_traders.ContainsKey(traderId))
            return Task.FromResult(OneOf<ApiKey, NotFoundError>.FromT1(new NotFoundError("Trader not found")));

        var key = new ApiKey(
            Guid.NewGuid().ToString("N"),
            traderId,
            DateTime.UtcNow.AddDays(30),
            permissions);

        _apiKeys[key.Key] = key;
        return Task.FromResult(OneOf<ApiKey, NotFoundError>.FromT0(key));
    }
}

public class TradeOrderService : ITradeOrderService
{
    private readonly List<TradeOrder> _orders = new();
    private readonly ITraderService _traderService;

    public TradeOrderService(ITraderService traderService) => _traderService = traderService;

    public async Task<OneOf<TradeOrder, NotFoundError, ValidationError>> CreateOrderAsync(CreateOrderRequest request, Guid traderId)
    {
        var traderResult = await _traderService.GetTraderByIdAsync(traderId);
        if (traderResult.IsT1)
            return traderResult.AsT1;

        var trader = traderResult.AsT0;

        if (!trader.IsActive)
            return new ValidationError("Trader account is not active");

        var orderValue = request.Quantity * request.Price;
        if (orderValue > trader.TradingLimit)
            return new ValidationError($"Order value {orderValue:C} exceeds trading limit {trader.TradingLimit:C}");

        var order = new TradeOrder(
            Guid.NewGuid(),
            request.Symbol.ToUpperInvariant(),
            request.Type,
            request.Quantity,
            request.Price,
            traderId,
            DateTime.UtcNow);

        _orders.Add(order);
        return order;
    }

    public async Task<OneOf<List<TradeOrder>, NotFoundError>> GetOrdersByTraderAsync(Guid traderId)
    {
        var traderResult = await _traderService.GetTraderByIdAsync(traderId);
        if (traderResult.IsT1)
            return traderResult.AsT1;

        return _orders.Where(o => o.TraderId == traderId).ToList();
    }
}

public class ApiKeyService : IApiKeyService
{
    private readonly ITraderService _traderService;
    private readonly Dictionary<string, ApiKey> _apiKeys = new();

    public ApiKeyService(ITraderService traderService) => _traderService = traderService;

    public async Task<OneOf<(ApiKey Key, Trader Trader), NotFoundError, ExpiredKeyError, UnauthorizedError>> ValidateApiKeyAsync(string key)
    {
        if (!_apiKeys.TryGetValue(key, out var apiKey))
            return new NotFoundError("Invalid API key");

        if (apiKey.ExpiresAt < DateTime.UtcNow)
            return new ExpiredKeyError("API key has expired");

        var traderResult = await _traderService.GetTraderByIdAsync(apiKey.TraderId);
        if (traderResult.IsT1)
            return new NotFoundError("Associated trader not found");

        var trader = traderResult.AsT0;
        if (!trader.IsActive)
            return new UnauthorizedError("Trader account is inactive");

        return (apiKey, trader);
    }
}

// Authentication Middleware
public class ApiKeyAuthenticationMiddleware
{
    private readonly RequestDelegate _next;
    private readonly ILogger<ApiKeyAuthenticationMiddleware> _logger;

    public ApiKeyAuthenticationMiddleware(RequestDelegate next, ILogger<ApiKeyAuthenticationMiddleware> logger)
    {
        _next = next;
        _logger = logger;
    }

    public async Task InvokeAsync(HttpContext context, IApiKeyService apiKeyService)
    {
        var endpoint = context.GetEndpoint();
        var allowAnonymous = endpoint?.Metadata?.GetMetadata<IAllowAnonymous>() != null;

        if (allowAnonymous)
        {
            await _next(context);
            return;
        }

        if (!context.Request.Headers.TryGetValue("X-API-Key", out var apiKeyValues))
        {
            _logger.LogWarning("Request missing X-API-Key header");
            await WriteProblemResponse(context, 401, "Unauthorized", "X-API-Key header is required");
            return;
        }

        var apiKey = apiKeyValues.ToString();
        var result = await apiKeyService.ValidateApiKeyAsync(apiKey);

        if (result.TryPickT1(out var notFound, out _))
        {
            _logger.LogWarning("Invalid API key attempt: {Key}", apiKey[..8] + "...");
            await WriteProblemResponse(context, 401, "Unauthorized", notFound.Message);
            return;
        }

        if (result.TryPickT2(out var expired, out _))
        {
            _logger.LogWarning("Expired API key used: {Key}", apiKey[..8] + "...");
            await WriteProblemResponse(context, 401, "Unauthorized", expired.Message);
            return;
        }

        if (result.TryPickT3(out var unauthorized, out _))
        {
            _logger.LogWarning("Unauthorized access attempt with key: {Key}", apiKey[..8] + "...");
            await WriteProblemResponse(context, 403, "Forbidden", unauthorized.Message);
            return;
        }

        var (key, trader) = result.AsT0;
        context.Items["ApiKey"] = key;
        context.Items["Trader"] = trader;
        context.Items["TraderId"] = trader.Id;
        context.Items["Permissions"] = key.Permissions;

        context.User = new System.Security.Claims.ClaimsPrincipal(
            new System.Security.Claims.ClaimsIdentity(new[]
            {
                new System.Security.Claims.Claim("TraderId", trader.Id.ToString()),
                new System.Security.Claims.Claim("Role", trader.Role.ToString())
            }, "ApiKey"));

        _logger.LogInformation("Authenticated trader {TraderId} with permissions {Permissions}",
            trader.Id, string.Join(", ", key.Permissions));

        await _next(context);
    }

    private static async Task WriteProblemResponse(HttpContext context, int statusCode, string title, string detail)
    {
        context.Response.StatusCode = statusCode;
        context.Response.ContentType = "application/problem+json";
        await context.Response.WriteAsJsonAsync(new ProblemDetails
        {
            Title = title,
            Status = statusCode,
            Detail = detail,
            Type = $"https://httpstatuses.com/{statusCode}"
        });
    }
}

// Permission Authorization Middleware
public class PermissionAuthorizationMiddleware
{
    private readonly RequestDelegate _next;

    public PermissionAuthorizationMiddleware(RequestDelegate next) => _next = next;

    public async Task InvokeAsync(HttpContext context)
    {
        var endpoint = context.GetEndpoint();
        var requiredPermission = endpoint?.Metadata?.GetMetadata<RequirePermissionAttribute>();

        if (requiredPermission == null)
        {
            await _next(context);
            return;
        }

        var permissions = context.Items["Permissions"] as string[];
        if (permissions == null || !permissions.Contains(requiredPermission.Permission))
        {
            context.Response.StatusCode = 403;
            context.Response.ContentType = "application/problem+json";
            await context.Response.WriteAsJsonAsync(new ProblemDetails
            {
                Title = "Forbidden",
                Status = 403,
                Detail = $"Permission '{requiredPermission.Permission}' is required",
                Type = "https://httpstatuses.com/403"
            });
            return;
        }

        await _next(context);
    }
}

[AttributeUsage(AttributeTargets.Method | AttributeTargets.Class, AllowMultiple = true)]
public class RequirePermissionAttribute : Attribute
{
    public string Permission { get; }
    public RequirePermissionAttribute(string permission) => Permission = permission;
}

