    Task<OneOf<bool, NotFound, LocationAtCapacity>> CanAddItemToLocationAsync(int locationId);
}

// Service Implementation
public class InventoryService : IInventoryService
{
    private readonly Dictionary<int, InventoryItem> _items = new();
    private readonly Dictionary<int, WarehouseLocation> _locations = new();
    private readonly Dictionary<int, List<int>> _locationItems = new();
    private int _nextItemId = 1;
    private int _nextLocationId = 1;

    public Task<OneOf<ItemCreated, ValidationError, Conflict>> CreateItemAsync(InventoryItem item)
    {
        var errors = new List<string>();

        if (string.IsNullOrWhiteSpace(item.Sku))
            errors.Add("SKU is required");

        if (string.IsNullOrWhiteSpace(item.Name))
            errors.Add("Name is required");

        if (item.Quantity < 0)
            errors.Add("Quantity cannot be negative");

        if (item.UnitPrice < 0)
            errors.Add("Unit price cannot be negative");

        if (errors.Count > 0)
            return Task.FromResult<OneOf<ItemCreated, ValidationError, Conflict>>(
                new ValidationError("Validation failed", errors.ToArray()));

        if (_items.Values.Any(i => i.Sku == item.Sku))
            return Task.FromResult<OneOf<ItemCreated, ValidationError, Conflict>>(
                new Conflict($"Item with SKU '{item.Sku}' already exists"));

        if (!_locations.ContainsKey(item.WarehouseLocationId))
            return Task.FromResult<OneOf<ItemCreated, ValidationError, Conflict>>(
                new Conflict($"Warehouse location {item.WarehouseLocationId} does not exist"));

        var location = _locations[item.WarehouseLocationId];
        var itemsAtLocation = _locationItems.GetValueOrDefault(item.WarehouseLocationId, new List<int>()).Count;
        if (itemsAtLocation >= location.Capacity)
            return Task.FromResult<OneOf<ItemCreated, ValidationError, Conflict>>(
                new Conflict($"Warehouse location {item.WarehouseLocationId} is at capacity"));

        var id = _nextItemId++;
        var newItem = item with { Id = id };
        _items[id] = newItem;

        if (!_locationItems.ContainsKey(item.WarehouseLocationId))
            _locationItems[item.WarehouseLocationId] = new List<int>();
        _locationItems[item.WarehouseLocationId].Add(id);

        return Task.FromResult<OneOf<ItemCreated, ValidationError, Conflict>>(
            new ItemCreated(id, item.Sku, item.Name));
    }

    public Task<OneOf<InventoryItem, NotFound>> GetItemByIdAsync(int id)
    {
        if (_items.TryGetValue(id, out var item))
            return Task.FromResult<OneOf<InventoryItem, NotFound>>(item);

        return Task.FromResult<OneOf<InventoryItem, NotFound>>(new NotFound(id));
    }

    public Task<OneOf<InventoryItem, NotFoundBySku>> GetItemBySkuAsync(string sku)
    {
        var item = _items.Values.FirstOrDefault(i => i.Sku == sku);
        if (item != null)
            return Task.FromResult<OneOf<InventoryItem, NotFoundBySku>>(item);

        return Task.FromResult<OneOf<InventoryItem, NotFoundBySku>>(new NotFoundBySku(sku));
    }

    public Task<OneOf<ItemUpdated, NotFound, ValidationError>> UpdateQuantityAsync(int id, int newQuantity)
    {
        if (!_items.TryGetValue(id, out var item))
            return Task.FromResult<OneOf<ItemUpdated, NotFound, ValidationError>>(new NotFound(id));

        if (newQuantity < 0)
            return Task.FromResult<OneOf<ItemUpdated, NotFound, ValidationError>>(
                new ValidationError("Invalid quantity", new[] { "Quantity cannot be negative" }));

        var updatedItem = item with { Quantity = newQuantity };
        _items[id] = updatedItem;

        return Task.FromResult<OneOf<ItemUpdated, NotFound, ValidationError>>(
            new ItemUpdated(id, newQuantity));
    }

    public Task<OneOf<ItemDeleted, NotFound>> DeleteItemAsync(int id)
    {
        if (!_items.TryGetValue(id, out var item))
            return Task.FromResult<OneOf<ItemDeleted, NotFound>>(new NotFound(id));

        _items.Remove(id);
        if (_locationItems.TryGetValue(item.WarehouseLocationId, out var locationItemList))
            locationItemList.Remove(id);

        return Task.FromResult<OneOf<ItemDeleted, NotFound>>(new ItemDeleted(id));
    }

    public Task<IEnumerable<InventoryItem>> GetAllItemsAsync()
    {
        return Task.FromResult(_items.Values.AsEnumerable());
    }

    public Task<OneOf<LocationCreated, ValidationError, Conflict>> CreateLocationAsync(WarehouseLocation location)
    {
        var errors = new List<string>();

        if (string.IsNullOrWhiteSpace(location.Code))
            errors.Add("Location code is required");

        if (string.IsNullOrWhiteSpace(location.Name))
            errors.Add("Location name is required");

        if (location.Capacity <= 0)
            errors.Add("Capacity must be greater than zero");

        if (errors.Count > 0)
            return Task.FromResult<OneOf<LocationCreated, ValidationError, Conflict>>(
                new ValidationError("Validation failed", errors.ToArray()));

        if (_locations.Values.Any(l => l.Code == location.Code))
            return Task.FromResult<OneOf<LocationCreated, ValidationError, Conflict>>(
                new Conflict($"Location with code '{location.Code}' already exists"));

        var id = _nextLocationId++;
        var newLocation = location with { Id = id };
        _locations[id] = newLocation;
        _locationItems[id] = new List<int>();

        return Task.FromResult<OneOf<LocationCreated, ValidationError, Conflict>>(
            new LocationCreated(id, location.Code));
    }

    public Task<OneOf<WarehouseLocation, NotFound>> GetLocationByIdAsync(int id)
    {
        if (_locations.TryGetValue(id, out var location))
            return Task.FromResult<OneOf<WarehouseLocation, NotFound>>(location);

        return Task.FromResult<OneOf<WarehouseLocation, NotFound>>(new NotFound(id));
    }

    public Task<IEnumerable<WarehouseLocation>> GetAllLocationsAsync()
    {
        return Task.FromResult(_locations.Values.AsEnumerable());
    }

    public Task<OneOf<bool, NotFound, LocationAtCapacity>> CanAddItemToLocationAsync(int locationId)
    {
        if (!_locations.TryGetValue(locationId, out var location))
            return Task.FromResult<OneOf<bool, NotFound, LocationAtCapacity>>(new NotFound(locationId));

        var currentItems = _locationItems.GetValueOrDefault(locationId, new List<int>()).Count;
        if (currentItems >= location.Capacity)
            return Task.FromResult<OneOf<bool, NotFound, LocationAtCapacity>>(
                new LocationAtCapacity(locationId, currentItems, location.Capacity));

        return Task.FromResult<OneOf<bool, NotFound, LocationAtCapacity>>(true);
    }
}

