[ApiController]
[Route("api/[controller]")]
public class InventoryController : ControllerBase
{
    private readonly IInventoryService _service;

    public InventoryController(IInventoryService service)
    {
        _service = service;
    }

    [HttpPost("items")]
    public async Task<IActionResult> CreateItem([FromBody] InventoryItem item)
    {
        var result = await _service.CreateItemAsync(item);

        return result.Match<IActionResult>(
            created => Results.Created($"/api/inventory/items/{created.Id}", created),
            validation => Results.ValidationProblem(
                validation.Errors.ToDictionary(e => e, e => validation.Message)),
            conflict => Results.Conflict(new ProblemDetails
            {
                Title = "Conflict",
                Detail = conflict.Message,
                Status = StatusCodes.Status409Conflict
            })
        );
    }

    [HttpGet("items/{id:int}")]
    public async Task<IActionResult> GetItemById(int id)
    {
        var result = await _service.GetItemByIdAsync(id);

        return result.Match<IActionResult>(
            item => Results.Ok(item),
            notFound => Results.NotFound(new ProblemDetails
            {
                Title = "Not Found",
                Detail = $"Item with ID {notFound.Id} not found",
                Status = StatusCodes.Status404NotFound
            })
        );
    }

    [HttpGet("items/by-sku/{sku}")]
