namespace Hr.Onboarding.Api
{
    #region Records

    public record OnboardingRequest(
        Guid EmployeeId,
        [Required]
        [StringLength(100, MinimumLength = 1)]
        string FirstName,
        [Required]
        [StringLength(100, MinimumLength = 1)]
        string LastName,
        [Required]
        [EmailAddress]
        string Email,
        [Required]
        string Department,
        [Required]
        DateTime StartDate,
        string? ManagerEmail
    );

    public record OnboardingCase(
        Guid CaseId,
        Guid EmployeeId,
        string FullName,
        string Email,
        string Department,
        DateTime StartDate,
        string Status,
        DateTime CreatedAt,
        DateTime? CompletedAt
    );

    public record ValidationError(
        string Field,
        string Message
    );

    public record OnboardingNotFound(
        Guid CaseId,
        string Message
    );

    public record UpdateStatusRequest(
        [Required]
        string Status
    );

    #endregion

    #region Service Interface and Implementation

    public interface IOnboardingService
    {
        Task<OneOf<OnboardingCase, OnboardingNotFound>> GetOnboardingCaseAsync(Guid caseId);
        Task<OneOf<OnboardingCase, List<ValidationError>>> CreateOnboardingCaseAsync(OnboardingRequest request);
        Task<OneOf<OnboardingCase, List<ValidationError>, OnboardingNotFound>>> UpdateOnboardingStatusAsync(Guid caseId, string status);
    }

    public class OnboardingService : IOnboardingService
    {
        private static readonly Dictionary<Guid, OnboardingCase> _cases = new();
        private static readonly string[] ValidDepartments = { "Engineering", "Sales", "HR", "Finance", "Operations" };
        private static readonly string[] ValidStatuses = { "Pending", "InProgress", "Completed", "Failed" };

        public Task<OneOf<OnboardingCase, OnboardingNotFound>> GetOnboardingCaseAsync(Guid caseId)
        {
            if (_cases.TryGetValue(caseId, out var onboardingCase))
            {
                return Task.FromResult(OneOf<OnboardingCase, OnboardingNotFound>.FromT0(onboardingCase));
            }

            return Task.FromResult(OneOf<OnboardingCase, OnboardingNotFound>.FromT1(
                new OnboardingNotFound(caseId, $"Onboarding case with ID {caseId} was not found.")));
        }

        public Task<OneOf<OnboardingCase, List<ValidationError>>> CreateOnboardingCaseAsync(OnboardingRequest request)
        {
            var validationErrors = ValidateRequest(request);

            if (validationErrors.Count > 0)
            {
                return Task.FromResult(OneOf<OnboardingCase, List<ValidationError>>.FromT1(validationErrors));
            }

            var caseId = Guid.NewGuid();
            var onboardingCase = new OnboardingCase(
                CaseId: caseId,
                EmployeeId: request.EmployeeId,
                FullName: $"{request.FirstName} {request.LastName}",
                Email: request.Email,
                Department: request.Department,
                StartDate: request.StartDate,
                Status: "Pending",
                CreatedAt: DateTime.UtcNow,
                CompletedAt: null
            );

            _cases[caseId] = onboardingCase;

            return Task.FromResult(OneOf<OnboardingCase, List<ValidationError>>.FromT0(onboardingCase));
        }

        public Task<OneOf<OnboardingCase, List<ValidationError>, OnboardingNotFound>> UpdateOnboardingStatusAsync(Guid caseId, string status)
        {
            var validationErrors = new List<ValidationError>();

            if (!ValidStatuses.Contains(status))
            {
                validationErrors.Add(new ValidationError(
                    nameof(UpdateStatusRequest.Status),
                    $"Status must be one of: {string.Join(", ", ValidStatuses)}"));
            }

            if (validationErrors.Count > 0)
            {
                return Task.FromResult(OneOf<OnboardingCase, List<ValidationError>, OnboardingNotFound>.FromT1(validationErrors));
            }

            if (!_cases.TryGetValue(caseId, out var existingCase))
            {
                return Task.FromResult(OneOf<OnboardingCase, List<ValidationError>, OnboardingNotFound>.FromT2(
                    new OnboardingNotFound(caseId, $"Onboarding case with ID {caseId} was not found.")));
            }

            var updatedCase = existingCase with
            {
                Status = status,
                CompletedAt = status == "Completed" ? DateTime.UtcNow : existingCase.CompletedAt
            };

            _cases[caseId] = updatedCase;

            return Task.FromResult(OneOf<OnboardingCase, List<ValidationError>, OnboardingNotFound>.FromT0(updatedCase));
        }

        private List<ValidationError> ValidateRequest(OnboardingRequest request)
        {
            var errors = new List<ValidationError>();

            if (!ValidDepartments.Contains(request.Department))
            {
                errors.Add(new ValidationError(
                    nameof(request.Department),
                    $"Department must be one of: {string.Join(", ", ValidDepartments)}"));
            }

            if (request.StartDate <= DateTime.UtcNow)
            {
                errors.Add(new ValidationError(
                    nameof(request.StartDate),
                    "StartDate must be a future date"));
            }

            if (!string.IsNullOrEmpty(request.ManagerEmail))
            {
                var emailAttribute = new EmailAddressAttribute();
                if (!emailAttribute.IsValid(request.ManagerEmail))
                {
                    errors.Add(new ValidationError(
                        nameof(request.ManagerEmail),
                        "ManagerEmail must be a valid email address"));
                }
            }

            return errors;
        }
    }

    #endregion

    #region Controller

    [ApiController]
    [Route("api/[controller]")]
    public class EmployeeOnboardingController : ControllerBase
    {
        private readonly IOnboardingService _onboardingService;

        public EmployeeOnboardingController(IOnboardingService onboardingService)
        {
            _onboardingService = onboardingService;
        }

        [HttpGet("{caseId:guid}")]
        [ProducesResponseType(typeof(OnboardingCase), StatusCodes.Status200OK)]
        [ProducesResponseType(typeof(OnboardingNotFound), StatusCodes.Status404NotFound)]
        public async Task<IActionResult> GetOnboardingCase(Guid caseId)
        {
            var result = await _onboardingService.GetOnboardingCaseAsync(caseId);

            return result.Match<IActionResult>(
                onboardingCase => Ok(onboardingCase),
                notFound => NotFound(notFound)
            );
        }

        [HttpPost]
        [ProducesResponseType(typeof(OnboardingCase), StatusCodes.Status201Created)]
        [ProducesResponseType(typeof(List<ValidationError>), StatusCodes.Status400BadRequest)]
        public async Task<IActionResult> CreateOnboardingCase([FromBody] OnboardingRequest request)
        {
            if (!ModelState.IsValid)
            {
                var modelErrors = ModelState
                    .Where(kvp => kvp.Value?.Errors.Count > 0)
                    .SelectMany(kvp => kvp.Value!.Errors.Select(e => new ValidationError(kvp.Key, e.ErrorMessage)))
                    .ToList();

                return BadRequest(modelErrors);
            }

            var result = await _onboardingService.CreateOnboardingCaseAsync(request);

            return result.Match<IActionResult>(
                onboardingCase => CreatedAtAction(
                    nameof(GetOnboardingCase),
                    new { caseId = onboardingCase.CaseId },
                    onboardingCase),
