            );
        }

        [HttpPatch("{caseId:guid}/status")]
        [ProducesResponseType(typeof(OnboardingCase), StatusCodes.Status200OK)]
        [ProducesResponseType(typeof(List<ValidationError>), StatusCodes.Status400BadRequest)]
