// OneOf Result Type
public readonly struct OneOf<T0, T1>
{
    private readonly object? _value;
    private readonly int _index;

    private OneOf(T0 value) { _value = value; _index = 0; }
    private OneOf(T1 value) { _value = value; _index = 1; }

    public static implicit operator OneOf<T0, T1>(T0 value) => new(value);
    public static implicit operator OneOf<T0, T1>(T1 value) => new(value);

    public TResult Match<TResult>(Func<T0, TResult> f0, Func<T1, TResult> f1) =>
        _index switch
        {
            0 => f0((T0)_value!),
            1 => f1((T1)_value!),
            _ => throw new InvalidOperationException()
        };

    public async Task<TResult> MatchAsync<TResult>(Func<T0, Task<TResult>> f0, Func<T1, Task<TResult>> f1) =>
        _index switch
        {
            0 => await f0((T0)_value!),
            1 => await f1((T1)_value!),
            _ => throw new InvalidOperationException()
        };
}

