// Middleware
public class ApiKeyAuthenticationMiddleware
{
    private readonly RequestDelegate _next;

    public ApiKeyAuthenticationMiddleware(RequestDelegate next)
    {
        _next = next;
    }

    public async Task InvokeAsync(HttpContext context, IUserService userService)
    {
        if (!context.Request.Headers.TryGetValue("X-API-Key", out var apiKeyValues) ||
            string.IsNullOrEmpty(apiKeyValues))
        {
            await WriteProblemResponse(context, 401, "Unauthorized", "Invalid or missing API key");
            return;
        }

        var apiKey = apiKeyValues.ToString();
        var user = await userService.ValidateApiKeyAsync(apiKey);

        if (user is null)
        {
            await WriteProblemResponse(context, 401, "Unauthorized", "Invalid or missing API key");
            return;
        }

        context.Items["User"] = user;
        await _next(context);
    }

    private static async Task WriteProblemResponse(HttpContext context, int status, string title, string detail)
    {
        context.Response.StatusCode = status;
        context.Response.ContentType = "application/problem+json";
        await context.Response.WriteAsJsonAsync(new ProblemDetails
        {
            Status = status,
            Title = title,
            Detail = detail
        });
    }
}

public class RoleAuthorizationMiddleware
{
    private readonly RequestDelegate _next;
    private readonly HashSet<string> _adminOnlyEndpoints = new(StringComparer.OrdinalIgnoreCase)
    {
        "/api/orders"
    };

    public RoleAuthorizationMiddleware(RequestDelegate next)
    {
        _next = next;
    }

    public async Task InvokeAsync(HttpContext context)
    {
        var user = context.Items["User"] as User;

        if (user is null)
        {
            await WriteProblemResponse(context, 401, "Unauthorized", "Authentication required");
            return;
        }

        var path = context.Request.Path.Value ?? "";
        var method = context.Request.Method;

        if (IsAdminOnlyEndpoint(path, method) && !string.Equals(user.Role, "Admin", StringComparison.OrdinalIgnoreCase))
        {
            await WriteProblemResponse(context, 403, "Forbidden", "Admin role required for this operation");
            return;
        }

        await _next(context);
    }

    private bool IsAdminOnlyEndpoint(string path, string method)
    {
        if (string.Equals(method, "POST", StringComparison.OrdinalIgnoreCase) &&
            path.StartsWith("/orders", StringComparison.OrdinalIgnoreCase))
        {
            return true;
        }

        return false;
    }

    private static async Task WriteProblemResponse(HttpContext context, int status, string title, string detail)
    {
        context.Response.StatusCode = status;
        context.Response.ContentType = "application/problem+json";
        await context.Response.WriteAsJsonAsync(new ProblemDetails
        {
            Status = status,
            Title = title,
            Detail = detail
        });
    }
}

