    private readonly Dictionary<Guid, Patient> _patients = new();
    private readonly Dictionary<string, Guid> _mrnIndex = new();

    public Task<OneOf<PatientFound, PatientNotFound>> GetPatientByIdAsync(Guid id)
    {
        if (_patients.TryGetValue(id, out var patient))
        {
            return Task.FromResult<OneOf<PatientFound, PatientNotFound>>(new PatientFound(patient));
        }
        return Task.FromResult<OneOf<PatientFound, PatientNotFound>>(new PatientNotFound(id));
    }

    public Task<OneOf<PatientCreated, DuplicateMrn, ValidationError>> CreatePatientAsync(CreatePatientRequest request)
    {
        var validationErrors = ValidateRequest(request);
        if (validationErrors.Length > 0)
        {
            return Task.FromResult<OneOf<PatientCreated, DuplicateMrn, ValidationError>>(new ValidationError(validationErrors));
        }

        if (_mrnIndex.ContainsKey(request.MedicalRecordNumber))
        {
            return Task.FromResult<OneOf<PatientCreated, DuplicateMrn, ValidationError>>(new DuplicateMrn(request.MedicalRecordNumber));
        }

        var patient = new Patient(
            Guid.NewGuid(),
            request.FirstName,
            request.LastName,
            request.DateOfBirth,
            request.MedicalRecordNumber,
            request.InsuranceProvider
        );

        _patients[patient.Id] = patient;
        _mrnIndex[patient.MedicalRecordNumber] = patient.Id;

        return Task.FromResult<OneOf<PatientCreated, DuplicateMrn, ValidationError>>(new PatientCreated(patient));
    }

    public Task<OneOf<PatientUpdated, PatientNotFound, DuplicateMrn, ValidationError>> UpdatePatientAsync(Guid id, CreatePatientRequest request)
    {
        if (!_patients.ContainsKey(id))
        {
            return Task.FromResult<OneOf<PatientUpdated, PatientNotFound, DuplicateMrn, ValidationError>>(new PatientNotFound(id));
        }

        var validationErrors = ValidateRequest(request);
        if (validationErrors.Length > 0)
        {
            return Task.FromResult<OneOf<PatientUpdated, PatientNotFound, DuplicateMrn, ValidationError>>(new ValidationError(validationErrors));
        }

        var existingPatient = _patients[id];
        if (existingPatient.MedicalRecordNumber != request.MedicalRecordNumber && 
            _mrnIndex.ContainsKey(request.MedicalRecordNumber))
        {
            return Task.FromResult<OneOf<PatientUpdated, PatientNotFound, DuplicateMrn, ValidationError>>(new DuplicateMrn(request.MedicalRecordNumber));
        }

        _mrnIndex.Remove(existingPatient.MedicalRecordNumber);

        var updatedPatient = existingPatient with
        {
            FirstName = request.FirstName,
            LastName = request.LastName,
            DateOfBirth = request.DateOfBirth,
            MedicalRecordNumber = request.MedicalRecordNumber,
            InsuranceProvider = request.InsuranceProvider
        };

        _patients[id] = updatedPatient;
        _mrnIndex[request.MedicalRecordNumber] = id;

        return Task.FromResult<OneOf<PatientUpdated, PatientNotFound, DuplicateMrn, ValidationError>>(new PatientUpdated(updatedPatient));
    }

    public Task<OneOf<PatientDeleted, PatientNotFound>> DeletePatientAsync(Guid id)
    {
        if (!_patients.TryGetValue(id, out var patient))
        {
            return Task.FromResult<OneOf<PatientDeleted, PatientNotFound>>(new PatientNotFound(id));
        }

        _patients.Remove(id);
        _mrnIndex.Remove(patient.MedicalRecordNumber);

        return Task.FromResult<OneOf<PatientDeleted, PatientNotFound>>(new PatientDeleted(id));
    }

    public Task<IEnumerable<Patient>> GetAllPatientsAsync()
    {
        return Task.FromResult(_patients.Values.AsEnumerable());
    }

    private static string[] ValidateRequest(CreatePatientRequest request)
    {
        var errors = new List<string>();

        if (string.IsNullOrWhiteSpace(request.FirstName))
            errors.Add("FirstName is required");

        if (string.IsNullOrWhiteSpace(request.LastName))
            errors.Add("LastName is required");

        if (string.IsNullOrWhiteSpace(request.MedicalRecordNumber))
            errors.Add("MedicalRecordNumber is required");

        if (request.DateOfBirth > DateTime.Today)
            errors.Add("DateOfBirth cannot be in the future");

        return errors.ToArray();
    }
}

