public record NotFound;

public interface IPatientRepository
{
    Task<PatientRecord?> GetByIdAsync(Guid id);
    Task<List<PatientRecord>> GetAllAsync();
    Task AddAsync(PatientRecord patient);
    Task UpdateAsync(PatientRecord patient);
    Task<bool> DeleteAsync(Guid id);
}

public class InMemoryPatientRepository : IPatientRepository
{
    private readonly List<PatientRecord> _patients = new();
    private readonly object _lock = new();

    public Task<PatientRecord?> GetByIdAsync(Guid id)
    {
        lock (_lock)
        {
            return Task.FromResult(_patients.FirstOrDefault(p => p.Id == id));
        }
    }

    public Task<List<PatientRecord>> GetAllAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_patients.ToList());
        }
    }

    public Task AddAsync(PatientRecord patient)
    {
        lock (_lock)
        {
            _patients.Add(patient);
        }
        return Task.CompletedTask;
    }

    public Task UpdateAsync(PatientRecord patient)
    {
        lock (_lock)
        {
            var index = _patients.FindIndex(p => p.Id == patient.Id);
            if (index >= 0)
            {
                _patients[index] = patient;
            }
        }
        return Task.CompletedTask;
    }

    public Task<bool> DeleteAsync(Guid id)
    {
        lock (_lock)
        {
            var patient = _patients.FirstOrDefault(p => p.Id == id);
            if (patient != null)
            {
                _patients.Remove(patient);
                return Task.FromResult(true);
            }
            return Task.FromResult(false);
        }
    }
}

public interface IPatientService
{
    Task<OneOf<PatientRecord, Dictionary<string, string[]>>> CreatePatientAsync(CreatePatientRequest request);
    Task<OneOf<PatientRecord, NotFound>> GetPatientAsync(Guid id);
    Task<List<PatientRecord>> GetAllPatientsAsync();
    Task<OneOf<PatientRecord, NotFound, Dictionary<string, string[]>>> AddMedicationAsync(Guid patientId, AddMedicationRequest request);
    Task<OneOf<bool, NotFound>> DeletePatientAsync(Guid id);
}

public class PatientService : IPatientService
{
    private readonly IPatientRepository _repository;

    public PatientService(IPatientRepository repository)
    {
        _repository = repository;
    }

    public async Task<OneOf<PatientRecord, Dictionary<string, string[]>>> CreatePatientAsync(CreatePatientRequest request)
    {
        var errors = ValidateCreateRequest(request);
        if (errors.Count > 0)
        {
            return errors;
        }

        var patient = new PatientRecord(
            Guid.NewGuid(),
            request.FirstName,
            request.LastName,
            request.DateOfBirth,
            request.MedicalRecordNumber,
            request.PrimaryPhysician,
            new List<PatientMedication>()
        );

        await _repository.AddAsync(patient);
        return patient;
    }

    public async Task<OneOf<PatientRecord, NotFound>> GetPatientAsync(Guid id)
    {
        var patient = await _repository.GetByIdAsync(id);
        if (patient == null)
        {
            return new NotFound();
        }
        return patient;
    }

    public async Task<List<PatientRecord>> GetAllPatientsAsync()
    {
        return await _repository.GetAllAsync();
    }

    public async Task<OneOf<PatientRecord, NotFound, Dictionary<string, string[]>>> AddMedicationAsync(Guid patientId, AddMedicationRequest request)
    {
        var errors = ValidateMedicationRequest(request);
        if (errors.Count > 0)
        {
            return errors;
        }

        var patient = await _repository.GetByIdAsync(patientId);
        if (patient == null)
        {
            return new NotFound();
        }

        var medication = new PatientMedication(
            Guid.NewGuid(),
            request.MedicationName,
            request.Dosage,
            request.PrescribedDate,
            request.IsActive
        );

        var updatedMedications = patient.Medications.ToList();
        updatedMedications.Add(medication);

        var updatedPatient = patient with { Medications = updatedMedications };
        await _repository.UpdateAsync(updatedPatient);

        return updatedPatient;
    }

    public async Task<OneOf<bool, NotFound>> DeletePatientAsync(Guid id)
    {
        var deleted = await _repository.DeleteAsync(id);
        if (!deleted)
        {
            return new NotFound();
        }
        return true;
    }

    private Dictionary<string, string[]> ValidateCreateRequest(CreatePatientRequest request)
    {
        var errors = new Dictionary<string, string[]>();

        if (request.DateOfBirth >= DateOnly.FromDateTime(DateTime.Today))
        {
            errors[nameof(request.DateOfBirth)] = new[] { "Date of birth must be in the past" };
        }

        if (!System.Text.RegularExpressions.Regex.IsMatch(request.MedicalRecordNumber, @"^[A-Za-z0-9]{10}$"))
        {
            errors[nameof(request.MedicalRecordNumber)] = new[] { "Medical record number must be exactly 10 alphanumeric characters" };
        }

        return errors;
    }

    private Dictionary<string, string[]> ValidateMedicationRequest(AddMedicationRequest request)
    {
        var errors = new Dictionary<string, string[]>();

        if (request.PrescribedDate > DateOnly.FromDateTime(DateTime.Today))
        {
            errors[nameof(request.PrescribedDate)] = new[] { "Prescribed date must be today or in the past" };
        }

        return errors;
    }
}

