// FluentValidator
public class CreatePatientRecordCommandValidator : AbstractValidator<CreatePatientRecordCommand>
{
    public CreatePatientRecordCommandValidator()
    {
        RuleFor(x => x.PatientId)
            .NotEmpty()
            .WithMessage("PatientId is required");

        RuleFor(x => x.FirstName)
            .NotEmpty()
            .WithMessage("First name is required")
            .MaximumLength(100)
            .WithMessage("First name cannot exceed 100 characters");

        RuleFor(x => x.LastName)
            .NotEmpty()
            .WithMessage("Last name is required")
            .MaximumLength(100)
            .WithMessage("Last name cannot exceed 100 characters");

        RuleFor(x => x.DateOfBirth)
            .NotEmpty()
            .WithMessage("Date of birth is required")
            .LessThan(DateTime.Today)
            .WithMessage("Date of birth must be in the past");

        RuleFor(x => x.MedicalRecordNumber)
            .MaximumLength(50)
            .WithMessage("Medical record number cannot exceed 50 characters")
            .Matches(@"^[A-Z]{2}\d{8}$")
            .When(x => !string.IsNullOrEmpty(x.MedicalRecordNumber))
            .WithMessage("Medical record number must be in format: 2 letters followed by 8 digits");

        RuleFor(x => x.Department)
            .NotEmpty()
            .WithMessage("Department is required")
            .Must(dept => new[] { "Cardiology", "Neurology", "Oncology", "Pediatrics", "Emergency" }.Contains(dept))
            .WithMessage("Department must be one of: Cardiology, Neurology, Oncology, Pediatrics, Emergency");
    }
}

