    public async Task<IResult> CreateOrder([FromBody] CreateOrderRequest request)
    {
        var result = await _orderService.CreateOrderAsync(request);

        return result.Match<IResult>(
            created => Results.Created($"/api/tradingorders/{created.OrderId}", created),
            insufficientFunds => Results.BadRequest(new
            {
                ErrorCode = "InsufficientFunds",
                RequiredAmount = insufficientFunds.RequiredAmount,
                AvailableAmount = insufficientFunds.AvailableAmount,
                Currency = insufficientFunds.Currency
            }),
            invalid => Results.BadRequest(new { ErrorCode = invalid.ErrorCode, Description = invalid.Description }),
            marketClosed => Results.BadRequest(new
            {
                ErrorCode = "MarketClosed",
                Market = marketClosed.Market,
                OpensAt = marketClosed.OpensAt
            })
        );
    }

    [HttpDelete("{orderId:guid}")]
    public async Task<IResult> CancelOrder(Guid orderId)
    {
        var result = await _orderService.CancelOrderAsync(orderId);

        return result.Match<IResult>(
            order => Results.Ok(new { OrderId = order.OrderId, Status = order.Status, Message = "Order cancelled successfully" }),
            notFound => Results.NotFound(new { OrderId = notFound.OrderId, Reason = notFound.Reason }),
            invalid => Results.BadRequest(new { ErrorCode = invalid.ErrorCode, Description = invalid.Description })
        );
    }
}

