// Service Implementations
public class PortfolioService : IPortfolioService
{
    private readonly Dictionary<string, Portfolio> _portfolios;
    private readonly IOrderBookService _orderBookService;

    public PortfolioService(IOrderBookService orderBookService)
    {
        _orderBookService = orderBookService;
        _portfolios = new Dictionary<string, Portfolio>
        {
            ["ACC001"] = new Portfolio("ACC001", 100000m, new Dictionary<string, int>
            {
                ["AAPL"] = 100,
                ["GOOGL"] = 50,
                ["MSFT"] = 75
            }),
            ["ACC002"] = new Portfolio("ACC002", 50000m, new Dictionary<string, int>
            {
                ["TSLA"] = 25,
                ["NVDA"] = 30
            }),
            ["ACC003"] = new Portfolio("ACC003", 250000m, new Dictionary<string, int>
            {
                ["AMZN"] = 200,
                ["META"] = 150
            })
        };
    }

    public Task<PortfolioQueryResult> GetPortfolioAsync(string accountId)
    {
        if (_portfolios.TryGetValue(accountId, out var portfolio))
        {
            return Task.FromResult<PortfolioQueryResult>(new PortfolioFound(portfolio));
        }
        return Task.FromResult<PortfolioQueryResult>(new PortfolioNotFound(accountId));
    }

    public async Task<TradeExecutionResult> ExecuteTradeAsync(string accountId, CreateOrderRequest request)
    {
        if (!_portfolios.TryGetValue(accountId, out var portfolio))
        {
            return new TradeAccountNotFound(accountId);
        }

        var isValidSymbol = await _orderBookService.ValidateSymbolAsync(request.Symbol);
        if (!isValidSymbol)
        {
            return new TradeRejected($"Invalid symbol: {request.Symbol}", "INVALID_SYMBOL");
        }

        var tradeValue = request.Quantity * request.Price;

        if (request.Side == "Buy")
        {
            if (portfolio.CashBalance < tradeValue)
            {
                return new TradeRejected(
                    $"Insufficient funds. Required: {tradeValue:C}, Available: {portfolio.CashBalance:C}",
                    "INSUFFICIENT_FUNDS");
            }

            var newCashBalance = portfolio.CashBalance - tradeValue;
            var newHoldings = new Dictionary<string, int>(portfolio.Holdings);
            newHoldings.TryGetValue(request.Symbol, out var currentQty);
            newHoldings[request.Symbol] = currentQty + request.Quantity;

            var updatedPortfolio = portfolio with { CashBalance = newCashBalance, Holdings = newHoldings };
            _portfolios[accountId] = updatedPortfolio;

            return new TradeExecuted(updatedPortfolio, 
                new TradeOrder(Guid.NewGuid(), request.Symbol, request.Side, request.Quantity, 
                    request.Price, DateTimeOffset.UtcNow, "Filled"));
        }
        else
        {
            var currentHolding = portfolio.Holdings.TryGetValue(request.Symbol, out var qty) ? qty : 0;

            if (currentHolding < request.Quantity)
            {
                return new TradeRejected(
                    $"Insufficient shares of {request.Symbol}. Requested: {request.Quantity}, Available: {currentHolding}",
                    "INSUFFICIENT_SHARES");
            }

            var newCashBalance = portfolio.CashBalance + tradeValue;
            var newHoldings = new Dictionary<string, int>(portfolio.Holdings);
            newHoldings[request.Symbol] -= request.Quantity;

            if (newHoldings[request.Symbol] == 0)
            {
                newHoldings.Remove(request.Symbol);
            }

            var updatedPortfolio = portfolio with { CashBalance = newCashBalance, Holdings = newHoldings };
            _portfolios[accountId] = updatedPortfolio;

            return new TradeExecuted(updatedPortfolio,
                new TradeOrder(Guid.NewGuid(), request.Symbol, request.Side, request.Quantity,
                    request.Price, DateTimeOffset.UtcNow, "Filled"));
        }
    }
}

