using System;
using FluentValidation;
using OneOf;
using OneOf.Types;

// Command Record
public record PlaceOrderCommand(
    Guid OrderId,
    string Symbol,
    string Side,
    int Quantity,
    decimal Price,
    string AccountId
);

// FluentValidator
public class PlaceOrderCommandValidator : AbstractValidator<PlaceOrderCommand>
{
    public PlaceOrderCommandValidator()
    {
        RuleFor(x => x.OrderId)
            .NotEmpty()
            .WithMessage("OrderId must not be empty");

        RuleFor(x => x.Symbol)
            .NotEmpty()
            .Length(1, 10)
            .WithMessage("Symbol must be between 1 and 10 characters")
            .Matches("^[A-Z]+$")
            .WithMessage("Symbol must contain uppercase letters only");

        RuleFor(x => x.Side)
            .Must(side => side == "Buy" || side == "Sell")
            .WithMessage("Side must be 'Buy' or 'Sell'");

        RuleFor(x => x.Quantity)
            .GreaterThan(0)
            .WithMessage("Quantity must be greater than 0");

        RuleFor(x => x.Price)
            .GreaterThan(0)
            .WithMessage("Price must be greater than 0");

        RuleFor(x => x.AccountId)
            .NotEmpty()
            .WithMessage("AccountId must not be empty");
    }
}

// OneOf Result Types
public record OrderPlaced(
    Guid OrderId,
    string Symbol,
    string Side,
    int Quantity,
    decimal Price,
    string AccountId,
    DateTime ExecutedAt
);

public record OrderRejected(string Reason, string Code);
public record InsufficientFunds(string AccountId, decimal RequiredAmount, decimal AvailableBalance);
public record MarketClosed(string Symbol, string TradingHours);
public record DuplicateOrder(Guid OrderId);

// Service Interface
public interface IOrderExecutionService
{
    Task<OneOf<OrderPlaced, OrderRejected, InsufficientFunds, MarketClosed, DuplicateOrder>> ExecuteOrderAsync(PlaceOrderCommand command);
}

// Service Implementation
public class OrderExecutionService : IOrderExecutionService
{
    private readonly HashSet<Guid> _processedOrders = new();

    public async Task<OneOf<OrderPlaced, OrderRejected, InsufficientFunds, MarketClosed, DuplicateOrder>> ExecuteOrderAsync(PlaceOrderCommand command)
    {
        await Task.Delay(10);

        if (_processedOrders.Contains(command.OrderId))
        {
            return new DuplicateOrder(command.OrderId);
        }

        if (command.Quantity > 100000)
        {
            return new OrderRejected("Order quantity exceeds maximum allowed limit", "MAX_QUANTITY");
        }

        if (command.Price <= 0)
        {
            return new OrderRejected("Invalid price specified", "INVALID_PRICE");
        }

        var hour = DateTime.UtcNow.Hour;
        if (hour < 9 || hour >= 16)
        {
            return new MarketClosed(command.Symbol, "09:00-16:00 UTC");
        }

        _processedOrders.Add(command.OrderId);

        return new OrderPlaced(
            command.OrderId,
            command.Symbol,
            command.Side,
            command.Quantity,
            command.Price,
            command.AccountId,
            DateTime.UtcNow
        );
    }
}

// Program.cs
var builder = WebApplication.CreateBuilder(args);

builder.Services.AddScoped<IOrderExecutionService, OrderExecutionService>();
builder.Services.AddScoped<PlaceOrderCommandValidator>();

var app = builder.Build();

app.MapPost("/orders", async (
    PlaceOrderCommand command,
    PlaceOrderCommandValidator validator,
    IOrderExecutionService orderService) =>
{
    var validationResult = await validator.ValidateAsync(command);

    if (!validationResult.IsValid)
    {
        var errors = validationResult.Errors
            .GroupBy(e => e.PropertyName)
            .ToDictionary(g => g.Key, g => g.Select(e => e.ErrorMessage).ToArray());

        return Results.ValidationProblem(errors);
    }

    var result = await orderService.ExecuteOrderAsync(command);

    return result.Match<IResult>(
        orderPlaced => Results.Created($"/orders/{orderPlaced.OrderId}", orderPlaced),
        orderRejected => Results.BadRequest(orderRejected),
        insufficientFunds => Results.BadRequest(insufficientFunds),
        marketClosed => Results.BadRequest(marketClosed),
        duplicateOrder => Results.BadRequest(duplicateOrder)
    );
});

app.Run();

