    private readonly Dictionary<string, ApiKey> _apiKeys = new()
    {
        ["trader-key-001"] = new ApiKey("trader-key-001", Guid.Parse("00000000-0000-0000-0000-000000000001"), "Trader", DateTime.UtcNow.AddYears(1), new[] { "trade", "view" }),
        ["admin-key-001"] = new ApiKey("admin-key-001", Guid.Parse("00000000-0000-0000-0000-000000000002"), "Admin", DateTime.UtcNow.AddYears(1), new[] { "trade", "view", "admin", "cancel" }),
        ["viewer-key-001"] = new ApiKey("viewer-key-001", Guid.Parse("00000000-0000-0000-0000-000000000003"), "Viewer", DateTime.UtcNow.AddYears(1), new[] { "view" })
    };

    public Task<OneOf<ApiKey, ApiKeyInvalid, ApiKeyExpired>> ValidateApiKeyAsync(string apiKey)
    {
        if (string.IsNullOrWhiteSpace(apiKey))
            return Task.FromResult<OneOf<ApiKey, ApiKeyInvalid, ApiKeyExpired>>(new ApiKeyInvalid("API key is required"));

        if (!_apiKeys.TryGetValue(apiKey, out var key))
            return Task.FromResult<OneOf<ApiKey, ApiKeyInvalid, ApiKeyExpired>>(new ApiKeyInvalid("Invalid API key"));

        if (key.ExpiresAt < DateTime.UtcNow)
            return Task.FromResult<OneOf<ApiKey, ApiKeyInvalid, ApiKeyExpired>>(new ApiKeyExpired(key.ExpiresAt));

        return Task.FromResult<OneOf<ApiKey, ApiKeyInvalid, ApiKeyExpired>>(key);
    }
