public class OrderService : IOrderService
{
    private readonly ITradingAccountService _accountService;
    private readonly TradingOptions _options;
    private readonly List<TradeOrder> _orders = new();

    public OrderService(ITradingAccountService accountService, TradingOptions options)
    {
        _accountService = accountService;
        _options = options;
    }

    public async Task<OneOf<OrderCreated, OrderRejected, InsufficientFunds>> CreateOrderAsync(Guid accountId, string symbol, string side, decimal quantity, decimal price)
    {
        var accountResult = await _accountService.GetAccountAsync(accountId);

        var validation = accountResult.Match(
            found => (Success: true, Error: string.Empty),
            notFound => (Success: false, Error: $"Account not found: {notFound.AccountId}"),
            unauthorized => (Success: false, Error: $"Unauthorized: {unauthorized.Reason}")
        );

        if (!validation.Success)
            return new OrderRejected(validation.Error);

        var account = accountResult.AsT0.Account;
        var orderValue = quantity * price;

        if (orderValue < _options.MinOrderValue || orderValue > _options.MaxOrderValue)
            return new OrderRejected($"Order value must be between {_options.MinOrderValue} and {_options.MaxOrderValue}");

        if (side == "Buy" && orderValue > account.Balance)
            return new InsufficientFunds(orderValue, account.Balance);

        var order = new TradeOrder(Guid.NewGuid(), accountId, symbol, side, quantity, price, DateTime.UtcNow);
        _orders.Add(order);

        return new OrderCreated(order);
    }

    public Task<OneOf<IEnumerable<TradeOrder>, AccountNotFound>> GetOrdersAsync(Guid accountId)
    {
        var orders = _orders.Where(o => o.AccountId == accountId).ToList();
        return Task.FromResult<OneOf<IEnumerable<TradeOrder>, AccountNotFound>>(orders);
    }
