// Middleware
public class ApiKeyAuthenticationMiddleware
{
    private readonly RequestDelegate _next;
    private readonly IApiKeyService _apiKeyService;

    public ApiKeyAuthenticationMiddleware(RequestDelegate next, IApiKeyService apiKeyService)
    {
        _next = next;
        _apiKeyService = apiKeyService;
    }

    public async Task InvokeAsync(HttpContext context)
    {
        if (IsPublicEndpoint(context.Request.Path))
        {
            await _next(context);
            return;
        }

        if (!context.Request.Headers.TryGetValue("X-API-Key", out var apiKeyHeader))
        {
            await WriteProblemResponse(context, 401, "Unauthorized", "API key is missing");
            return;
        }

        var apiKey = apiKeyHeader.ToString();
        var result = await _apiKeyService.ValidateApiKeyAsync(apiKey);

        await result.Switch(
            async key =>
            {
                var claims = new List<Claim>
                {
                    new Claim(ClaimTypes.NameIdentifier, key.AccountId.ToString()),
                    new Claim(ClaimTypes.Role, key.Role)
                };

                foreach (var permission in key.Permissions)
                {
                    claims.Add(new Claim("permission", permission));
                }

                var identity = new ClaimsIdentity(claims, "ApiKey");
                var principal = new ClaimsPrincipal(identity);
                context.User = principal;

                context.Items["AccountId"] = key.AccountId;
                context.Items["ApiKey"] = key;

                await _next(context);
            },
            async invalid =>
            {
                await WriteProblemResponse(context, 401, "Unauthorized", invalid.Reason);
            },
            async expired =>
            {
                await WriteProblemResponse(context, 401, "ApiKeyExpired", $"API key expired at {expired.ExpiredAt:O}");
            }
        );
    }

    private static bool IsPublicEndpoint(PathString path) =>
        path.StartsWithSegments("/health") ||
        path.StartsWithSegments("/swagger");

    private static async Task WriteProblemResponse(HttpContext context, int statusCode, string title, string detail)
    {
        context.Response.ContentType = "application/problem+json";
        context.Response.StatusCode = statusCode;
        await context.Response.WriteAsJsonAsync(new ProblemDetails
        {
            Title = title,
            Status = statusCode,
            Detail = detail
        });
    }
}

public class RoleAuthorizationMiddleware
{
    private readonly RequestDelegate _next;
    private readonly Dictionary<string, string[]> _rolePermissions = new()
    {
        ["Admin"] = new[] { "trade", "view", "admin", "cancel" },
        ["Trader"] = new[] { "trade", "view" },
        ["Viewer"] = new[] { "view" }
    };

    public RoleAuthorizationMiddleware(RequestDelegate next)
    {
        _next = next;
    }

    public async Task InvokeAsync(HttpContext context)
    {
        if (IsPublicEndpoint(context.Request.Path))
        {
            await _next(context);
            return;
        }

        var endpoint = context.GetEndpoint();
        var requiredPermission = endpoint?.Metadata.GetMetadata<RequiredPermissionAttribute>();

        if (requiredPermission == null)
        {
            await _next(context);
            return;
        }

        var userPermissions = context.User.FindAll("permission").Select(c => c.Value).ToList();
        var userRole = context.User.FindFirst(ClaimTypes.Role)?.Value;

        if (!userPermissions.Contains(requiredPermission.Permission))
        {
            await WriteProblemResponse(context, 403, "Forbidden", $"Role '{userRole}' does not have permission '{requiredPermission.Permission}'");
            return;
        }

        await _next(context);
    }

    private static bool IsPublicEndpoint(PathString path) =>
        path.StartsWithSegments("/health") ||
        path.StartsWithSegments("/swagger");

    private static async Task WriteProblemResponse(HttpContext context, int statusCode, string title, string detail)
    {
        context.Response.ContentType = "application/problem+json";
        context.Response.StatusCode = statusCode;
        await context.Response.WriteAsJsonAsync(new ProblemDetails
        {
            Title = title,
            Status = statusCode,
            Detail = detail
        });
    }
}

