// Repository Implementation
public class InMemoryInventoryRepository : IInventoryRepository
{
    private readonly Dictionary<Guid, InventoryItem> _items = new();
    private readonly object _lock = new();

    public Task<InventoryItem?> GetByIdAsync(Guid id)
    {
        lock (_lock)
        {
            _items.TryGetValue(id, out var item);
            return Task.FromResult(item);
        }
    }

    public Task<InventoryItem?> GetBySkuAsync(string sku)
    {
        lock (_lock)
        {
            var item = _items.Values.FirstOrDefault(i => 
                i.Sku.Equals(sku, StringComparison.OrdinalIgnoreCase));
            return Task.FromResult(item);
        }
    }

    public Task<InventoryItem> CreateAsync(CreateInventoryItemRequest request)
    {
        lock (_lock)
        {
            var item = new InventoryItem(
                Guid.NewGuid(),
                request.Sku,
                request.Name,
                request.Quantity,
                request.UnitPrice,
                request.WarehouseLocation
            );
            _items[item.Id] = item;
            return Task.FromResult(item);
        }
    }

    public Task<bool> SkuExistsAsync(string sku)
    {
        lock (_lock)
        {
            return Task.FromResult(_items.Values.Any(i => 
                i.Sku.Equals(sku, StringComparison.OrdinalIgnoreCase)));
        }
    }

    public Task<IEnumerable<InventoryItem>> GetAllAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_items.Values.AsEnumerable());
        }
    }

    public Task<bool> UpdateAsync(Guid id, int quantity)
    {
        lock (_lock)
        {
            if (!_items.TryGetValue(id, out var existing))
                return Task.FromResult(false);

            _items[id] = existing with { Quantity = quantity };
            return Task.FromResult(true);
        }
    }

    public Task<bool> DeleteAsync(Guid id)
    {
        lock (_lock)
        {
            return Task.FromResult(_items.Remove(id));
        }
    }
}

