// Service Implementation
public class InventoryService : IInventoryService
{
    private readonly IInventoryRepository _repository;
    private readonly ILogger<InventoryService> _logger;

    public InventoryService(IInventoryRepository repository, ILogger<InventoryService> logger)
    {
        _repository = repository;
        _logger = logger;
    }

    public async Task<InventoryItemResult> GetByIdAsync(Guid id)
    {
        var item = await _repository.GetByIdAsync(id);

        return item is null
            ? new ItemNotFound(id, $"Inventory item with ID '{id}' was not found")
            : item;
    }

    public async Task<CreatedItemResult> CreateAsync(CreateInventoryItemRequest request)
    {
        if (await _repository.SkuExistsAsync(request.Sku))
        {
            _logger.LogWarning("Attempted to create item with duplicate SKU: {Sku}", request.Sku);
            return new DuplicateSkuError(request.Sku, $"An item with SKU '{request.Sku}' already exists");
        }

        var item = await _repository.CreateAsync(request);
        _logger.LogInformation("Created inventory item: {Id} with SKU: {Sku}", item.Id, item.Sku);

        return item;
    }

    public async Task<IEnumerable<InventoryItem>> GetAllAsync()
    {
        return await _repository.GetAllAsync();
    }

    public async Task<InventoryItemResult> UpdateQuantityAsync(Guid id, int quantity)
    {
        var item = await _repository.GetByIdAsync(id);

        if (item is null)
        {
            return new ItemNotFound(id, $"Inventory item with ID '{id}' was not found");
        }

        var updated = await _repository.UpdateAsync(id, quantity);

        if (!updated)
        {
            return new ItemNotFound(id, $"Failed to update inventory item '{id}'");
        }

        return (await _repository.GetByIdAsync(id))!;
    }

    public async Task<OneOf<bool, ItemNotFound>> DeleteAsync(Guid id)
    {
        var item = await _repository.GetByIdAsync(id);

        if (item is null)
        {
            return new ItemNotFound(id, $"Inventory item with ID '{id}' was not found");
        }

        var deleted = await _repository.DeleteAsync(id);
        _logger.LogInformation("Deleted inventory item: {Id}", id);

        return deleted;
    }
}

