// In-Memory Data Store
public class InMemoryDataStore
{
    public Dictionary<Guid, Product> Products { get; } = new();
    public Dictionary<Guid, Warehouse> Warehouses { get; } = new();
    public Dictionary<Guid, InventoryItem> InventoryItems { get; } = new();
    public Dictionary<Guid, StockMovement> StockMovements { get; } = new();

    private readonly object _lock = new();

    public void AddProduct(Product product) { lock (_lock) Products[product.Id] = product; }
    public void AddWarehouse(Warehouse warehouse) { lock (_lock) Warehouses[warehouse.Id] = warehouse; }
    public void AddInventoryItem(InventoryItem item) { lock (_lock) InventoryItems[item.Id] = item; }
    public void AddStockMovement(StockMovement movement) { lock (_lock) StockMovements[movement.Id] = movement; }
    public void UpdateInventoryItem(InventoryItem item) { lock (_lock) InventoryItems[item.Id] = item; }
    public bool RemoveProduct(Guid id) { lock (_lock) return Products.Remove(id); }
    public bool RemoveWarehouse(Guid id) { lock (_lock) return Warehouses.Remove(id); }

    public InventoryItem? GetInventory(Guid productId, Guid warehouseId)
    {
        lock (_lock)
            return InventoryItems.Values.FirstOrDefault(i => i.ProductId == productId && i.WarehouseId == warehouseId);
    }

    public int GetTotalWarehouseCapacity(Guid warehouseId)
    {
        lock (_lock)
            return InventoryItems.Values
                .Where(i => i.WarehouseId == warehouseId)
                .Sum(i => i.Quantity);
    }
}

