public class ProductService : IProductService
{
    private readonly InMemoryDataStore _store;

    public ProductService(InMemoryDataStore store) => _store = store;

    public Task<OneOf<Product, NotFoundError>> GetByIdAsync(Guid id)
    {
        if (_store.Products.TryGetValue(id, out var product))
            return Task.FromResult<OneOf<Product, NotFoundError>>(product);
        return Task.FromResult<OneOf<Product, NotFoundError>>(new NotFoundError(id, "Product"));
    }

    public Task<IEnumerable<Product>> GetAllAsync()
    {
        return Task.FromResult(_store.Products.Values.AsEnumerable());
    }

    public Task<OneOf<Product, ValidationError>> CreateAsync(CreateProductRequest request)
    {
        if (_store.Products.Values.Any(p => p.Sku.Equals(request.Sku, StringComparison.OrdinalIgnoreCase)))
        {
            return Task.FromResult<OneOf<Product, ValidationError>>(
                new ValidationError("SKU already exists", new Dictionary<string, string[]> 
                { 
                    ["Sku"] = new[] { "A product with this SKU already exists" } 
                }));
        }

        var product = new Product(
            Guid.NewGuid(),
            request.Sku,
            request.Name,
            request.Description,
            request.UnitPrice,
            request.ReorderLevel,
            DateTime.UtcNow
        );

        _store.AddProduct(product);
        return Task.FromResult<OneOf<Product, ValidationError>>(product);
    }

    public Task<OneOf<Product, NotFoundError, ValidationError>> UpdateAsync(Guid id, UpdateProductRequest request)
    {
        if (!_store.Products.TryGetValue(id, out var existing))
            return Task.FromResult<OneOf<Product, NotFoundError, ValidationError>>(new NotFoundError(id, "Product"));

        if (request.Sku != null && _store.Products.Values.Any(p => p.Id != id && p.Sku.Equals(request.Sku, StringComparison.OrdinalIgnoreCase)))
        {
            return Task.FromResult<OneOf<Product, NotFoundError, ValidationError>>(
                new ValidationError("SKU already exists", new Dictionary<string, string[]> 
                { 
                    ["Sku"] = new[] { "A product with this SKU already exists" } 
                }));
        }

        var updated = existing with
        {
            Sku = request.Sku ?? existing.Sku,
            Name = request.Name ?? existing.Name,
            Description = request.Description ?? existing.Description,
            UnitPrice = request.UnitPrice ?? existing.UnitPrice,
            ReorderLevel = request.ReorderLevel ?? existing.ReorderLevel
        };

        _store.AddProduct(updated);
        return Task.FromResult<OneOf<Product, NotFoundError, ValidationError>>(updated);
    }

    public Task<OneOf<bool, NotFoundError>> DeleteAsync(Guid id)
    {
        var result = _store.RemoveProduct(id);
        if (!result)
            return Task.FromResult<OneOf<bool, NotFoundError>>(new NotFoundError(id, "Product"));
        return Task.FromResult<OneOf<bool, NotFoundError>>(true);
    }
}

