// Service Implementation
public class EmployeeOnboardingService : IEmployeeOnboardingService
{
    private readonly Dictionary<Guid, Employee> _employees = new();
    private readonly Dictionary<Guid, List<OnboardingRequest>> _requests = new();
    private readonly List<string> _requiredSteps = new()
    {
        "DocumentSubmission",
        "BackgroundCheck",
        "EquipmentSetup",
        "SystemAccess",
        "BenefitsEnrollment",
        "Orientation"
    };

    public Task<OneOf<OnboardingStatus, NotFoundError>> GetOnboardingStatusAsync(Guid employeeId)
    {
        if (!_employees.TryGetValue(employeeId, out var employee))
        {
            return Task.FromResult<OneOf<OnboardingStatus, NotFoundError>>(
                new NotFoundError(employeeId)
            );
        }

        var completedSteps = GetCompletedSteps(employeeId);
        var pendingSteps = _requiredSteps.Except(completedSteps).ToList();
        var progress = (int)((double)completedSteps.Count / _requiredSteps.Count * 100);

        var status = new OnboardingStatus(
            employee.Id,
            employee.Name,
            employee.State.ToString(),
            progress,
            completedSteps,
            pendingSteps
        );

        return Task.FromResult<OneOf<OnboardingStatus, NotFoundError>>(status);
    }

    public Task<OneOf<Employee, ConflictError>> CreateEmployeeAsync(CreateEmployeeRequest request)
    {
        if (_employees.Values.Any(e => e.Email.Equals(request.Email, StringComparison.OrdinalIgnoreCase)))
        {
            return Task.FromResult<OneOf<Employee, ConflictError>>(
                new ConflictError($"Employee with email {request.Email} already exists")
            );
        }

        var employee = new Employee(
            Guid.NewGuid(),
            request.Name,
            request.Email,
            request.Department,
            OnboardingState.Pending,
            DateTime.UtcNow,
            null
        );

        _employees[employee.Id] = employee;
        _requests[employee.Id] = new List<OnboardingRequest>();

        return Task.FromResult<OneOf<Employee, ConflictError>>(employee);
    }

    public Task<OneOf<OnboardingStatus, NotFoundError, ValidationError>> UpdateOnboardingProgressAsync(
        Guid employeeId,
        UpdateOnboardingStepRequest request)
    {
        if (!_employees.TryGetValue(employeeId, out var employee))
        {
            return Task.FromResult<OneOf<OnboardingStatus, NotFoundError, ValidationError>>(
                new NotFoundError(employeeId)
            );
        }

        if (!_requiredSteps.Contains(request.StepName))
        {
            var errors = new Dictionary<string, string[]>
            {
                { nameof(request.StepName), new[] { $"Invalid step: {request.StepName}. Valid steps are: {string.Join(", ", _requiredSteps)}" } }
            };
            return Task.FromResult<OneOf<OnboardingStatus, NotFoundError, ValidationError>>(
                new ValidationError(errors)
            );
        }

        var employeeRequests = _requests[employeeId];
        var existingRequest = employeeRequests.FirstOrDefault(r => r.RequestType == request.StepName);

        if (existingRequest == null)
        {
            var newRequest = new OnboardingRequest(
                Guid.NewGuid(),
                employeeId,
                request.StepName,
                "Completed",
                DateTime.UtcNow
            );
            employeeRequests.Add(newRequest);
        }

        var completedSteps = GetCompletedSteps(employeeId);
        var allStepsCompleted = _requiredSteps.All(s => completedSteps.Contains(s));

        if (allStepsCompleted && employee.State != OnboardingState.Completed)
        {
            employee = employee with 
            { 
                State = OnboardingState.Completed,
                OnboardingCompletedAt = DateTime.UtcNow
            };
            _employees[employeeId] = employee;
        }
        else if (employee.State == OnboardingState.Pending)
        {
            employee = employee with { State = OnboardingState.InProgress };
            _employees[employeeId] = employee;
        }

        return GetOnboardingStatusAsync(employeeId)
            .ContinueWith(t => (OneOf<OnboardingStatus, NotFoundError, ValidationError>)t.Result);
    }

    public Task<OneOf<Employee, NotFoundError, ConflictError>> CompleteOnboardingAsync(
        Guid employeeId,
        CompleteOnboardingRequest request)
    {
        if (!_employees.TryGetValue(employeeId, out var employee))
        {
            return Task.FromResult<OneOf<Employee, NotFoundError, ConflictError>>(
                new NotFoundError(employeeId)
            );
        }

        if (employee.State == OnboardingState.Completed)
        {
            return Task.FromResult<OneOf<Employee, NotFoundError, ConflictError>>(
                new ConflictError("Onboarding already completed")
            );
        }

        var completedSteps = GetCompletedSteps(employeeId);
        var allStepsCompleted = _requiredSteps.All(s => completedSteps.Contains(s));

        if (!allStepsCompleted)
        {
            return Task.FromResult<OneOf<Employee, NotFoundError, ConflictError>>(
                new ConflictError("Cannot complete onboarding: not all required steps are completed")
            );
        }

        employee = employee with
        {
            State = OnboardingState.Completed,
            OnboardingCompletedAt = DateTime.UtcNow
        };
        _employees[employeeId] = employee;

        return Task.FromResult<OneOf<Employee, NotFoundError, ConflictError>>(employee);
    }

    public Task<OneOf<IEnumerable<OnboardingRequest>, NotFoundError>> GetOnboardingRequestsAsync(Guid employeeId)
    {
        if (!_employees.ContainsKey(employeeId))
        {
            return Task.FromResult<OneOf<IEnumerable<OnboardingRequest>, NotFoundError>>(
                new NotFoundError(employeeId)
            );
        }

        var requests = _requests.TryGetValue(employeeId, out var req) ? req : Enumerable.Empty<OnboardingRequest>();
        return Task.FromResult<OneOf<IEnumerable<OnboardingRequest>, NotFoundError>>(requests);
    }

    private List<string> GetCompletedSteps(Guid employeeId)
    {
        if (!_requests.TryGetValue(employeeId, out var requests))
            return new List<string>();

        return requests
            .Where(r => r.Status == "Completed")
            .Select(r => r.RequestType)
            .ToList();
    }
}

