// Controller
[ApiController]
[Route("api/onboarding")]
public class EmployeeOnboardingController : ControllerBase
{
    private readonly IEmployeeOnboardingService _service;
    private readonly IOptions<HrOnboardingOptions> _options;

    public EmployeeOnboardingController(
        IEmployeeOnboardingService service,
        IOptions<HrOnboardingOptions> options)
    {
        _service = service;
        _options = options;
    }

    /// <summary>
    /// Retrieves the onboarding status for a specific employee.
    /// </summary>
    [HttpGet("{employeeId}")]
    [ProducesResponseType(typeof(OnboardingStatus), StatusCodes.Status200OK)]
    [ProducesResponseType(StatusCodes.Status404NotFound)]
    public async Task<IActionResult> GetOnboardingStatus(Guid employeeId)
    {
        var result = await _service.GetOnboardingStatusAsync(employeeId);

        return result.Match<IActionResult>(
            status => Results.Ok(status),
            notFound => Results.NotFound(new ProblemDetails
            {
                Title = "Employee Not Found",
                Status = StatusCodes.Status404NotFound,
                Detail = $"Employee with ID {notFound.EmployeeId} was not found"
            })
        );
    }

    /// <summary>
    /// Creates a new employee onboarding request.
    /// </summary>
    [HttpPost]
    [ProducesResponseType(typeof(Employee), StatusCodes.Status201Created)]
    [ProducesResponseType(StatusCodes.Status409Conflict)]
    public async Task<IActionResult> CreateEmployee([FromBody] CreateEmployeeRequest request)
    {
        var result = await _service.CreateEmployeeAsync(request);

        return result.Match<IActionResult>(
            employee => Results.Created($"api/onboarding/{employee.Id}", employee),
            conflict => Results.Conflict(new ProblemDetails
            {
                Title = "Conflict",
                Status = StatusCodes.Status409Conflict,
                Detail = conflict.Message
            })
        );
    }

    /// <summary>
    /// Updates the onboarding progress by completing a step.
    /// </summary>
    [HttpPut("{employeeId}/progress")]
    [ProducesResponseType(typeof(OnboardingStatus), StatusCodes.Status200OK)]
    [ProducesResponseType(StatusCodes.Status404NotFound)]
    [ProducesResponseType(StatusCodes.Status400BadRequest)]
    public async Task<IActionResult> UpdateOnboardingProgress(
        Guid employeeId,
        [FromBody] UpdateOnboardingStepRequest request)
    {
        var result = await _service.UpdateOnboardingProgressAsync(employeeId, request);

        return result.Match<IActionResult>(
            status => Results.Ok(status),
            notFound => Results.NotFound(new ProblemDetails
            {
                Title = "Employee Not Found",
                Status = StatusCodes.Status404NotFound,
                Detail = $"Employee with ID {notFound.EmployeeId} was not found"
            }),
            validationError => Results.BadRequest(new ProblemDetails
            {
                Title = "Validation Error",
                Status = StatusCodes.Status400BadRequest,
                Detail = "One or more validation errors occurred",
                Extensions = validationError.Errors.ToDictionary(kvp => kvp.Key, kvp => (object?)kvp.Value)
            })
        );
    }

    /// <summary>
    /// Marks onboarding as completed for an employee.
    /// </summary>
    [HttpPut("{employeeId}/complete")]
    [ProducesResponseType(typeof(Employee), StatusCodes.Status200OK)]
    [ProducesResponseType(StatusCodes.Status404NotFound)]
    [ProducesResponseType(StatusCodes.Status409Conflict)]
    public async Task<IActionResult> CompleteOnboarding(
        Guid employeeId,
        [FromBody] CompleteOnboardingRequest request)
    {
        var result = await _service.CompleteOnboardingAsync(employeeId, request);

        return result.Match<IActionResult>(
            employee => Results.Ok(employee),
            notFound => Results.NotFound(new ProblemDetails
            {
                Title = "Employee Not Found",
                Status = StatusCodes.Status404NotFound,
                Detail = $"Employee with ID {notFound.EmployeeId} was not found"
            }),
            conflict => Results.Conflict(new ProblemDetails
            {
                Title = "Conflict",
                Status = StatusCodes.Status409Conflict,
                Detail = conflict.Message
            })
        );
    }

    /// <summary>
    /// Gets all onboarding requests for an employee.
    /// </summary>
    [HttpGet("{employeeId}/requests")]
    [ProducesResponseType(typeof(IEnumerable<OnboardingRequest>), StatusCodes.Status200OK)]
    [ProducesResponseType(StatusCodes.Status404NotFound)]
    public async Task<IActionResult> GetOnboardingRequests(Guid employeeId)
    {
        var result = await _service.GetOnboardingRequestsAsync(employeeId);

        return result.Match<IActionResult>(
            requests => Results.Ok(requests),
            notFound => Results.NotFound(new ProblemDetails
            {
                Title = "Employee Not Found",
                Status = StatusCodes.Status404NotFound,
                Detail = $"Employee with ID {notFound.EmployeeId} was not found"
            })
        );
    }
}

