// Service Implementation
public class SensorService : ISensorService
{
    private readonly Dictionary<Guid, Sensor> _sensors = new();
    private readonly List<SensorReading> _readings = new();
    private readonly object _lock = new();

    public Task<OneOf<Sensor, NotFound, DatabaseError>> GetSensorByIdAsync(Guid id)
    {
        lock (_lock)
        {
            if (_sensors.TryGetValue(id, out var sensor))
            {
                return Task.FromResult<OneOf<Sensor, NotFound, DatabaseError>>(sensor);
            }
            return Task.FromResult<OneOf<Sensor, NotFound, DatabaseError>>(new NotFound(id));
        }
    }

    public Task<OneOf<List<Sensor>, DatabaseError>> GetAllSensorsAsync(bool? isActive = null)
    {
        lock (_lock)
        {
            var query = _sensors.Values.AsEnumerable();
            if (isActive.HasValue)
            {
                query = query.Where(s => s.IsActive == isActive.Value);
            }
            return Task.FromResult<OneOf<List<Sensor>, DatabaseError>>(query.ToList());
        }
    }

    public Task<OneOf<Sensor, SensorAlreadyExists, ValidationError, DatabaseError>> CreateSensorAsync(string name, string location, SensorType type)
    {
        lock (_lock)
        {
            if (string.IsNullOrWhiteSpace(name))
            {
                return Task.FromResult<OneOf<Sensor, SensorAlreadyExists, ValidationError, DatabaseError>>(
                    new ValidationError("Name is required", nameof(name)));
            }

            if (string.IsNullOrWhiteSpace(location))
            {
                return Task.FromResult<OneOf<Sensor, SensorAlreadyExists, ValidationError, DatabaseError>>(
                    new ValidationError("Location is required", nameof(location)));
            }

            if (_sensors.Values.Any(s => s.Name.Equals(name, StringComparison.OrdinalIgnoreCase)))
            {
                return Task.FromResult<OneOf<Sensor, SensorAlreadyExists, ValidationError, DatabaseError>>(
                    new SensorAlreadyExists(name));
            }

            var sensor = new Sensor(
                Guid.NewGuid(),
                name,
                location,
                type,
                IsActive: true,
                DateTime.UtcNow
            );

            _sensors[sensor.Id] = sensor;
            return Task.FromResult<OneOf<Sensor, SensorAlreadyExists, ValidationError, DatabaseError>>(sensor);
        }
    }

    public Task<OneOf<Sensor, NotFound, DatabaseError>> UpdateSensorAsync(Guid id, string? name, string? location, bool? isActive)
    {
        lock (_lock)
        {
            if (!_sensors.TryGetValue(id, out var existing))
            {
                return Task.FromResult<OneOf<Sensor, NotFound, DatabaseError>>(new NotFound(id));
            }

            var updated = existing with
            {
                Name = name ?? existing.Name,
                Location = location ?? existing.Location,
                IsActive = isActive ?? existing.IsActive
            };

            _sensors[id] = updated;
            return Task.FromResult<OneOf<Sensor, NotFound, DatabaseError>>(updated);
        }
    }

    public Task<OneOf<bool, NotFound, DatabaseError>> DeleteSensorAsync(Guid id)
    {
        lock (_lock)
        {
            if (!_sensors.ContainsKey(id))
            {
                return Task.FromResult<OneOf<bool, NotFound, DatabaseError>>(new NotFound(id));
            }

            _sensors.Remove(id);
            _readings.RemoveAll(r => r.SensorId == id);
            return Task.FromResult<OneOf<bool, NotFound, DatabaseError>>(true);
        }
    }

