public enum ArticleStatus { Draft, Published, Archived }

public record Article(
    Guid Id,
    string Title,
    string Content,
    string Author,
    ArticleStatus Status,
    DateTimeOffset CreatedAt,
    DateTimeOffset? PublishedAt
);

public record CreateArticleRequest(
    [Required][MinLength(5)][MaxLength(200)] string Title,
    [Required][MinLength(10)] string Content,
    [Required][MaxLength(100)] string Author,
    ArticleStatus Status = ArticleStatus.Draft
);

public record UpdateArticleRequest(
    [MinLength(5)][MaxLength(200)] string? Title,
    [MinLength(10)] string? Content,
    ArticleStatus? Status
);

public record NotFound();
public record ValidationError(string Message, Dictionary<string, string[]>? Errors = null);

public interface IArticleService
{
    Task<OneOf<Article, NotFound, ValidationError>> GetByIdAsync(Guid id);
    Task<OneOf<Article, NotFound, ValidationError>> UpdateAsync(Guid id, UpdateArticleRequest request);
    Task<OneOf<bool, NotFound, ValidationError>> DeleteAsync(Guid id);
    Task<Article> CreateAsync(CreateArticleRequest request);
    Task<IEnumerable<Article>> GetAllAsync();
}

public class ArticleService : IArticleService
{
    private readonly Dictionary<Guid, Article> _articles = new();

    public Task<Article> CreateAsync(CreateArticleRequest request)
    {
        var article = new Article(
            Guid.NewGuid(),
            request.Title,
            request.Content,
            request.Author,
            request.Status,
            DateTimeOffset.UtcNow,
            request.Status == ArticleStatus.Published ? DateTimeOffset.UtcNow : null
        );
        _articles[article.Id] = article;
        return Task.FromResult(article);
    }

    public Task<IEnumerable<Article>> GetAllAsync()
    {
        return Task.FromResult(_articles.Values.AsEnumerable());
    }

    public Task<OneOf<Article, NotFound, ValidationError>> GetByIdAsync(Guid id)
    {
        if (!_articles.TryGetValue(id, out var article))
        {
            return Task.FromResult<OneOf<Article, NotFound, ValidationError>>(new NotFound());
        }
        return Task.FromResult<OneOf<Article, NotFound, ValidationError>>(article);
    }

    public Task<OneOf<Article, NotFound, ValidationError>> UpdateAsync(Guid id, UpdateArticleRequest request)
    {
        if (!_articles.TryGetValue(id, out var existing))
        {
            return Task.FromResult<OneOf<Article, NotFound, ValidationError>>(new NotFound());
        }

        var updatedArticle = existing with
        {
            Title = request.Title ?? existing.Title,
            Content = request.Content ?? existing.Content,
            Status = request.Status ?? existing.Status,
            PublishedAt = request.Status == ArticleStatus.Published && existing.PublishedAt == null
                ? DateTimeOffset.UtcNow
                : existing.PublishedAt
        };

        _articles[id] = updatedArticle;
        return Task.FromResult<OneOf<Article, NotFound, ValidationError>>(updatedArticle);
    }

    public Task<OneOf<bool, NotFound, ValidationError>> DeleteAsync(Guid id)
    {
        if (!_articles.Remove(id))
        {
            return Task.FromResult<OneOf<bool, NotFound, ValidationError>>(new NotFound());
        }
        return Task.FromResult<OneOf<bool, NotFound, ValidationError>>(true);
    }
}

