namespace ArticleManagement;

// Domain Models
public enum ArticleStatus
{
    Draft = 0,
    Published = 1,
    Archived = 2
}

public record Article(
    Guid Id,
    [Required] [StringLength(200)] string Title,
    string Content,
    string Author,
    ArticleStatus Status,
    string Category,
    DateTimeOffset CreatedAt,
    DateTimeOffset UpdatedAt,
    int ViewCount
);

// DTOs
public record ArticleCreateRequest(
    [Required] [StringLength(200)] string Title,
    string Content,
    [Required] string Author,
    string Category,
    ArticleStatus Status = ArticleStatus.Draft
);

public record ArticleUpdateRequest(
    [StringLength(200)] string? Title,
    string? Content,
    string? Category,
    ArticleStatus? Status
);

public record ArticleFilterRequest(
    string? Author,
    ArticleStatus? Status,
    string? Category,
    DateTimeOffset? CreatedFrom,
    DateTimeOffset? CreatedTo,
    string? SearchTerm,
    int Page = 1,
    int PageSize = 10,
    string? SortBy = "CreatedAt",
    string? SortOrder = "desc"
);

public record PagedResult<T>(
    IReadOnlyList<T> Items,
    int TotalCount,
    int Page,
    int PageSize,
    int TotalPages
);

// Service Interface
public interface IArticleService
{
    Task<OneOf<Article, NotFound>> GetByIdAsync(Guid id);
    Task<PagedResult<Article>> GetFilteredAsync(ArticleFilterRequest filter);
    Task<OneOf<Article, ValidationError>> CreateAsync(ArticleCreateRequest request);
    Task<OneOf<Article, NotFound, ValidationError>> UpdateAsync(Guid id, ArticleUpdateRequest request);
    Task<OneOf<Success, NotFound>> DeleteAsync(Guid id);
    Task<OneOf<Success, NotFound>> IncrementViewCountAsync(Guid id);
}

public record Success;
public record ValidationError(Dictionary<string, string[]> Errors);

// In-memory Repository for demo
public interface IArticleRepository
{
    Task<Article?> GetByIdAsync(Guid id);
    Task<PagedResult<Article>> GetFilteredAsync(ArticleFilterRequest filter);
    Task<Article> AddAsync(Article article);
    Task<Article?> UpdateAsync(Guid id, Func<Article, Article> updateFunc);
    Task<bool> DeleteAsync(Guid id);
    Task<bool> IncrementViewCountAsync(Guid id);
}

public class InMemoryArticleRepository : IArticleRepository
{
    private readonly List<Article> _articles = new();
    private int _viewCountConcurrency = 0;

    public Task<Article?> GetByIdAsync(Guid id)
    {
        var article = _articles.FirstOrDefault(a => a.Id == id);
        return Task.FromResult(article);
    }

    public Task<PagedResult<Article>> GetFilteredAsync(ArticleFilterRequest filter)
    {
        var query = _articles.AsQueryable();

        // Apply filters
        if (!string.IsNullOrWhiteSpace(filter.Author))
        {
            query = query.Where(a => a.Author.Contains(filter.Author, StringComparison.OrdinalIgnoreCase));
        }

        if (filter.Status.HasValue)
        {
            query = query.Where(a => a.Status == filter.Status.Value);
        }

        if (!string.IsNullOrWhiteSpace(filter.Category))
        {
            query = query.Where(a => a.Category.Equals(filter.Category, StringComparison.OrdinalIgnoreCase));
        }

        if (filter.CreatedFrom.HasValue)
        {
            query = query.Where(a => a.CreatedAt >= filter.CreatedFrom.Value);
        }

        if (filter.CreatedTo.HasValue)
        {
            query = query.Where(a => a.CreatedAt <= filter.CreatedTo.Value);
        }

        if (!string.IsNullOrWhiteSpace(filter.SearchTerm))
        {
            query = query.Where(a => 
                a.Title.Contains(filter.SearchTerm, StringComparison.OrdinalIgnoreCase) ||
                a.Content.Contains(filter.SearchTerm, StringComparison.OrdinalIgnoreCase));
        }

        // Apply sorting
        var sortBy = filter.SortBy?.ToLowerInvariant() ?? "createdat";
        var ascending = filter.SortOrder?.ToLowerInvariant() != "desc";

        query = (sortBy, ascending) switch
        {
            ("title", true) => query.OrderBy(a => a.Title),
            ("title", false) => query.OrderByDescending(a => a.Title),
            ("author", true) => query.OrderBy(a => a.Author),
            ("author", false) => query.OrderByDescending(a => a.Author),
            ("category", true) => query.OrderBy(a => a.Category),
            ("category", false) => query.OrderByDescending(a => a.Category),
            ("status", true) => query.OrderBy(a => a.Status),
            ("status", false) => query.OrderByDescending(a => a.Status),
            ("viewcount", true) => query.OrderBy(a => a.ViewCount),
            ("viewcount", false) => query.OrderByDescending(a => a.ViewCount),
            ("updatedat", true) => query.OrderBy(a => a.UpdatedAt),
            ("updatedat", false) => query.OrderByDescending(a => a.UpdatedAt),
            (_, true) => query.OrderBy(a => a.CreatedAt),
            (_, false) => query.OrderByDescending(a => a.CreatedAt)
        };

        var totalCount = query.Count();
        var totalPages = (int)Math.Ceiling(totalCount / (double)filter.PageSize);

        var items = query
            .Skip((filter.Page - 1) * filter.PageSize)
            .Take(filter.PageSize)
            .ToList();

        return Task.FromResult(new PagedResult<Article>(items, totalCount, filter.Page, filter.PageSize, totalPages));
    }

    public Task<Article> AddAsync(Article article)
    {
        _articles.Add(article);
        return Task.FromResult(article);
    }

    public Task<Article?> UpdateAsync(Guid id, Func<Article, Article> updateFunc)
    {
        var index = _articles.FindIndex(a => a.Id == id);
        if (index == -1)
            return Task.FromResult<Article?>(null);

        _articles[index] = updateFunc(_articles[index]);
        return Task.FromResult(_articles[index])!;
    }

    public Task<bool> DeleteAsync(Guid id)
    {
        var removed = _articles.RemoveAll(a => a.Id == id);
        return Task.FromResult(removed > 0);
    }

    public Task<bool> IncrementViewCountAsync(Guid id)
    {
        var index = _articles.FindIndex(a => a.Id == id);
        if (index == -1)
            return Task.FromResult(false);

        var article = _articles[index];
        _articles[index] = article with { ViewCount = article.ViewCount + 1 };
        return Task.FromResult(true);
    }
}

// Service Implementation
public class ArticleService : IArticleService
{
    private readonly IArticleRepository _repository;

    public ArticleService(IArticleRepository repository)
    {
        _repository = repository;
    }

    public async Task<OneOf<Article, NotFound>> GetByIdAsync(Guid id)
    {
        var article = await _repository.GetByIdAsync(id);
        return article is null 
            ? new NotFound() 
            : article;
    }

    public async Task<PagedResult<Article>> GetFilteredAsync(ArticleFilterRequest filter)
    {
        ValidatePagination(filter);
        return await _repository.GetFilteredAsync(filter);
    }

    public async Task<OneOf<Article, ValidationError>> CreateAsync(ArticleCreateRequest request)
    {
        var validationErrors = ValidateCreateRequest(request);
        if (validationErrors is not null)
            return new ValidationError(validationErrors);

        var article = new Article(
            Id: Guid.NewGuid(),
            Title: request.Title,
            Content: request.Content ?? string.Empty,
            Author: request.Author,
            Status: request.Status,
            Category: request.Category ?? "Uncategorized",
            CreatedAt: DateTimeOffset.UtcNow,
            UpdatedAt: DateTimeOffset.UtcNow,
            ViewCount: 0
        );

        return await _repository.AddAsync(article);
    }

    public async Task<OneOf<Article, NotFound, ValidationError>> UpdateAsync(Guid id, ArticleUpdateRequest request)
    {
        var validationErrors = ValidateUpdateRequest(request);
        if (validationErrors is not null)
            return new ValidationError(validationErrors);

        var existing = await _repository.GetByIdAsync(id);
        if (existing is null)
            return new NotFound();

        var updated = await _repository.UpdateAsync(id, a => a with
        {
            Title = request.Title ?? a.Title,
            Content = request.Content ?? a.Content,
            Category = request.Category ?? a.Category,
            Status = request.Status ?? a.Status,
            UpdatedAt = DateTimeOffset.UtcNow
        });

        return updated!;
    }

    public async Task<OneOf<Success, NotFound>> DeleteAsync(Guid id)
    {
        var deleted = await _repository.DeleteAsync(id);
        return deleted 
            ? new Success() 
            : new NotFound();
    }

    public async Task<OneOf<Success, NotFound>> IncrementViewCountAsync(Guid id)
    {
        var incremented = await _repository.IncrementViewCountAsync(id);
        return incremented 
            ? new Success() 
            : new NotFound();
    }

    private static void ValidatePagination(ArticleFilterRequest filter)
    {
        if (filter.Page < 1)
            throw new ArgumentException("Page must be at least 1");
        if (filter.PageSize < 1 || filter.PageSize > 100)
            throw new ArgumentException("PageSize must be between 1 and 100");
    }

    private static Dictionary<string, string[]>? ValidateCreateRequest(ArticleCreateRequest request)
    {
        var errors = new Dictionary<string, List<string>>();

        if (string.IsNullOrWhiteSpace(request.Title))
            errors.Add(nameof(request.Title), ["Title is required"]);
        else if (request.Title.Length > 200)
            errors.Add(nameof(request.Title), ["Title cannot exceed 200 characters"]);

        if (string.IsNullOrWhiteSpace(request.Author))
            errors.Add(nameof(request.Author), ["Author is required"]);

        if (!Enum.IsDefined(typeof(ArticleStatus), request.Status))
            errors.Add(nameof(request.Status), ["Invalid status value"]);

        return errors.Count == 0 ? null : errors.ToDictionary(k => k.Key, v => v.Value.ToArray());
    }

    private static Dictionary<string, string[]>? ValidateUpdateRequest(ArticleUpdateRequest request)
    {
        var errors = new Dictionary<string, List<string>>();

        if (request.Title is not null && request.Title.Length > 200)
            errors.Add(nameof(request.Title), ["Title cannot exceed 200 characters"]);

        if (request.Status.HasValue && !Enum.IsDefined(typeof(ArticleStatus), request.Status.Value))
            errors.Add(nameof(request.Status), ["Invalid status value"]);

        return errors.Count == 0 ? null : errors.ToDictionary(k => k.Key, v => v.Value.ToArray());
    }
}

