// Records
public record CmsUser(Guid Id, string Username, string Email, string Role);
public record CmsContent(Guid Id, string Title, string Body, Guid AuthorId, DateTime CreatedAt, string Status);
public record AuthCredentials(string Username, string Password);
public record AuthError(string Code, string Message);
