// Options
public class CmsAuthOptions
{
    public const string SectionName = "CmsAuth";
    public string ApiKeyHeader { get; set; } = "X-CMS-API-Key";
    public string MasterKey { get; set; } = "cms-master-2024";
}

// Interface
public interface ICmsAuthService
{
    OneOf<CmsUser, AuthError> Authenticate(AuthCredentials credentials);
    bool ValidateApiKey(string apiKey);
    bool HasPermission(CmsUser user, string requiredRole);
}

// Service Implementation
public class CmsAuthService : ICmsAuthService
{
    private readonly CmsAuthOptions _options;
    private readonly Dictionary<string, (CmsUser User, string Password)> _users;

    public CmsAuthService(IOptions<CmsAuthOptions> options)
    {
        _options = options.Value;
        _users = new Dictionary<string, (CmsUser, string)>
        {
            ["admin"] = (new CmsUser(Guid.Parse("00000000-0000-0000-0000-000000000001"), "admin", "admin@cms.local", "Admin"), "admin123"),
            ["editor"] = (new CmsUser(Guid.Parse("00000000-0000-0000-0000-000000000002"), "editor", "editor@cms.local", "Editor"), "editor123"),
            ["viewer"] = (new CmsUser(Guid.Parse("00000000-0000-0000-0000-000000000003"), "viewer", "viewer@cms.local", "Viewer"), "viewer123")
        };
    }

    public OneOf<CmsUser, AuthError> Authenticate(AuthCredentials credentials)
    {
        if (string.IsNullOrWhiteSpace(credentials.Username))
            return new AuthError("AUTH001", "Username is required");

        if (string.IsNullOrWhiteSpace(credentials.Password))
            return new AuthError("AUTH002", "Password is required");

        if (!_users.TryGetValue(credentials.Username, out var userData))
            return new AuthError("AUTH003", "User not found");

        if (userData.Password != credentials.Password)
            return new AuthError("AUTH004", "Invalid credentials");

        return userData.User;
    }

    public bool ValidateApiKey(string apiKey)
    {
        return !string.IsNullOrEmpty(apiKey) && apiKey == _options.MasterKey;
    }

    public bool HasPermission(CmsUser user, string requiredRole)
    {
        var roleHierarchy = new Dictionary<string, int>
        {
            ["Admin"] = 3,
            ["Editor"] = 2,
            ["Viewer"] = 1
        };

        if (!roleHierarchy.TryGetValue(user.Role, out var userLevel))
            return false;

        if (!roleHierarchy.TryGetValue(requiredRole, out var requiredLevel))
            return false;

        return userLevel >= requiredLevel;
    }
}

