// Content Service Implementation
public class CmsContentService : ICmsContentService
{
    private readonly Dictionary<Guid, CmsContent> _storage = new();

    public OneOf<CmsContent, NotFound> GetById(Guid id)
    {
        return _storage.TryGetValue(id, out var content)
            ? content
            : new NotFound($"Content with ID {id} not found");
    }

    public IEnumerable<CmsContent> GetAll() => _storage.Values.OrderByDescending(c => c.CreatedAt);

    public CmsContent Create(CmsContent content)
    {
        var newContent = content with { Id = Guid.NewGuid(), CreatedAt = DateTime.UtcNow };
        _storage[newContent.Id] = newContent;
        return newContent;
    }

    public OneOf<CmsContent, NotFound> Update(CmsContent content)
    {
        if (!_storage.ContainsKey(content.Id))
            return new NotFound($"Content with ID {content.Id} not found");

        _storage[content.Id] = content;
        return content;
    }

    public OneOf<bool, NotFound> Delete(Guid id)
    {
        if (!_storage.ContainsKey(id))
            return new NotFound($"Content with ID {id} not found");

        _storage.Remove(id);
        return true;
    }
}

// Authentication Middleware
public class CmsAuthenticationMiddleware
{
    private readonly RequestDelegate _next;

    public CmsAuthenticationMiddleware(RequestDelegate next)
    {
        _next = next;
    }

    public async Task InvokeAsync(HttpContext context, ICmsAuthService authService, IOptions<CmsAuthOptions> options)
    {
        var opts = options.Value;

        // Check for API Key header
        if (context.Request.Headers.TryGetValue(opts.ApiKeyHeader, out var apiKeyHeader))
        {
            var apiKey = apiKeyHeader.ToString();
            if (authService.ValidateApiKey(apiKey))
            {
                context.Items["ApiKeyValidated"] = true;
                context.Items["User"] = new CmsUser(Guid.Empty, "api-user", "api@cms.local", "Admin");
            }
        }

        // Check for Authorization header with Bearer token (simplified - token is username)
        var authHeader = context.Request.Headers.Authorization.ToString();
        if (authHeader.StartsWith("Bearer ", StringComparison.OrdinalIgnoreCase))
        {
            var token = authHeader["Bearer ".Length..].Trim();
            var parts = token.Split(':', 2);
            if (parts.Length == 2)
            {
                var credentials = new AuthCredentials(parts[0], parts[1]);
                var result = authService.Authenticate(credentials);

                result.Switch(
                    user => context.Items["User"] = user,
                    error => { /* Authentication failed, continue without user */ }
                );
            }
        }

        await _next(context);
    }
}

