using Microsoft.Extensions.Hosting;
using OneOf;

// Domain Models
public enum ShipmentStatus
{
    Pending = 0,
    InTransit = 1,
    Delivered = 2,
    Cancelled = 3
}

public record Shipment
{
    public Guid Id { get; init; } = Guid.NewGuid();
    public string TrackingNumber { get; init; } = null!;
    public string Origin { get; init; } = null!;
    public string Destination { get; init; } = null!;
    public decimal Weight { get; init; }
    public ShipmentStatus Status { get; init; } = ShipmentStatus.Pending;
    public DateTime CreatedAt { get; init; } = DateTime.UtcNow;
    public DateTime? EstimatedDelivery { get; init; }
}

// DTOs
public record CreateShipmentRequest(
    [Required][RegularExpression(@"^[A-Za-z0-9]{10}$", ErrorMessage = "TrackingNumber must be exactly 10 alphanumeric characters")] 
    string TrackingNumber,
    [Required][MaxLength(200)] string Origin,
    [Required][MaxLength(200)] string Destination,
    [Required][Range(0.01, 10000.00)] decimal Weight,
    DateTime? EstimatedDelivery = null
);

public record UpdateShipmentStatusRequest(
    [Required] ShipmentStatus Status
);

// OneOf Result Types
public record ShipmentNotFound(Guid Id);
public record DuplicateTrackingNumber(string TrackingNumber);
public record InvalidStatusTransition(string Message);

// Service Interface
public interface IShipmentService
{
    Task<OneOf<Shipment, ShipmentNotFound>> GetByIdAsync(Guid id);
    Task<OneOf<Shipment, DuplicateTrackingNumber>> CreateAsync(CreateShipmentRequest request);
    Task<OneOf<Shipment, ShipmentNotFound, InvalidStatusTransition>> UpdateStatusAsync(Guid id, ShipmentStatus newStatus);
    Task<IEnumerable<Shipment>> GetAllAsync();
    Task<OneOf<Shipment, ShipmentNotFound>> GetByTrackingNumberAsync(string trackingNumber);
}

// Service Implementation
public class ShipmentService : IShipmentService
{
    private readonly Dictionary<Guid, Shipment> _shipments = new();
    private readonly Dictionary<string, Shipment> _byTrackingNumber = new();

    public Task<OneOf<Shipment, ShipmentNotFound>> GetByIdAsync(Guid id)
    {
        return _shipments.TryGetValue(id, out var shipment)
            ? Task.FromResult<OneOf<Shipment, ShipmentNotFound>>(shipment)
            : Task.FromResult<OneOf<Shipment, ShipmentNotFound>>(new ShipmentNotFound(id));
    }

    public Task<OneOf<Shipment, DuplicateTrackingNumber>> CreateAsync(CreateShipmentRequest request)
    {
        if (_byTrackingNumber.ContainsKey(request.TrackingNumber))
        {
            return Task.FromResult<OneOf<Shipment, DuplicateTrackingNumber>>(
                new DuplicateTrackingNumber(request.TrackingNumber));
        }

        var shipment = new Shipment
        {
            Id = Guid.NewGuid(),
            TrackingNumber = request.TrackingNumber,
            Origin = request.Origin,
            Destination = request.Destination,
            Weight = request.Weight,
            Status = ShipmentStatus.Pending,
            CreatedAt = DateTime.UtcNow,
            EstimatedDelivery = request.EstimatedDelivery
        };

        _shipments[shipment.Id] = shipment;
        _byTrackingNumber[shipment.TrackingNumber] = shipment;

        return Task.FromResult<OneOf<Shipment, DuplicateTrackingNumber>>(shipment);
    }

    public Task<OneOf<Shipment, ShipmentNotFound, InvalidStatusTransition>> UpdateStatusAsync(Guid id, ShipmentStatus newStatus)
    {
        if (!_shipments.TryGetValue(id, out var existing))
        {
            return Task.FromResult<OneOf<Shipment, ShipmentNotFound, InvalidStatusTransition>>(
                new ShipmentNotFound(id));
        }

        if (!IsValidTransition(existing.Status, newStatus))
        {
            return Task.FromResult<OneOf<Shipment, ShipmentNotFound, InvalidStatusTransition>>(
                new InvalidStatusTransition($"Cannot transition from {existing.Status} to {newStatus}"));
        }

        var updated = existing with { Status = newStatus };
        _shipments[id] = updated;
        _byTrackingNumber[updated.TrackingNumber] = updated;

        return Task.FromResult<OneOf<Shipment, ShipmentNotFound, InvalidStatusTransition>>(updated);
    }

    public Task<IEnumerable<Shipment>> GetAllAsync()
    {
        return Task.FromResult(_shipments.Values.AsEnumerable());
    }

    public Task<OneOf<Shipment, ShipmentNotFound>> GetByTrackingNumberAsync(string trackingNumber)
    {
        return _byTrackingNumber.TryGetValue(trackingNumber, out var shipment)
            ? Task.FromResult<OneOf<Shipment, ShipmentNotFound>>(shipment)
            : Task.FromResult<OneOf<Shipment, ShipmentNotFound>>(new ShipmentNotFound(Guid.Empty));
    }

    private static bool IsValidTransition(ShipmentStatus from, ShipmentStatus to)
    {
        return from switch
        {
            ShipmentStatus.Pending => to == ShipmentStatus.InTransit || to == ShipmentStatus.Cancelled,
            ShipmentStatus.InTransit => to == ShipmentStatus.Delivered || to == ShipmentStatus.Cancelled,
            ShipmentStatus.Delivered => false,
            ShipmentStatus.Cancelled => false,
            _ => false
        };
    }
}

