namespace LogisticsApi.Services
{
    using LogisticsApi.Models;
    using OneOf;

    public record ShipmentNotFound(Guid Id);
    public record ValidationError(string Message);
    public record DuplicateTrackingNumber(string TrackingNumber);

    public interface IShipmentService
    {
        Task<OneOf<ShipmentDto, ValidationError>> CreateShipmentAsync(CreateShipmentRequest request);
        Task<OneOf<ShipmentDto, ShipmentNotFound, ValidationError>> UpdateShipmentAsync(Guid id, UpdateShipmentRequest request);
        Task<OneOf<bool, ShipmentNotFound>> DeleteShipmentAsync(Guid id);
        Task<OneOf<ShipmentDto, ShipmentNotFound>> GetShipmentByIdAsync(Guid id);
        Task<OneOf<ShipmentDto, ShipmentNotFound>> GetShipmentByTrackingNumberAsync(string trackingNumber);
        Task<PagedResult<ShipmentDto>> GetShipmentsAsync(
            int pageNumber,
            int pageSize,
            ShipmentFilter? filter = null,
            ShipmentSort? sort = null
        );
    }

    public class ShipmentService : IShipmentService
    {
        private readonly Dictionary<Guid, Shipment> _shipments = new();
        private readonly Dictionary<string, Guid> _trackingNumberIndex = new();

        public Task<OneOf<ShipmentDto, ValidationError>> CreateShipmentAsync(CreateShipmentRequest request)
        {
            if (_trackingNumberIndex.ContainsKey(request.TrackingNumber))
            {
                return Task.FromResult<OneOf<ShipmentDto, ValidationError>>(
                    new ValidationError($"Tracking number '{request.TrackingNumber}' already exists")
                );
            }

            var shipment = new Shipment
            {
                Id = Guid.NewGuid(),
                TrackingNumber = request.TrackingNumber,
                Origin = request.Origin,
                Destination = request.Destination,
                Status = ShipmentStatus.Pending,
                WeightKg = request.WeightKg,
                CreatedAt = DateTime.UtcNow,
                DeliveredAt = null
            };

            _shipments[shipment.Id] = shipment;
            _trackingNumberIndex[shipment.TrackingNumber] = shipment.Id;

            return Task.FromResult<OneOf<ShipmentDto, ValidationError>>(ToDto(shipment));
        }

        public Task<OneOf<ShipmentDto, ShipmentNotFound, ValidationError>> UpdateShipmentAsync(Guid id, UpdateShipmentRequest request)
        {
            if (!_shipments.TryGetValue(id, out var existingShipment))
            {
                return Task.FromResult<OneOf<ShipmentDto, ShipmentNotFound, ValidationError>>(
                    new ShipmentNotFound(id)
                );
            }

            if (existingShipment.TrackingNumber != request.TrackingNumber &&
                _trackingNumberIndex.ContainsKey(request.TrackingNumber))
            {
                return Task.FromResult<OneOf<ShipmentDto, ShipmentNotFound, ValidationError>>(
                    new ValidationError($"Tracking number '{request.TrackingNumber}' already exists")
                );
            }

            var updatedShipment = existingShipment with
            {
                TrackingNumber = request.TrackingNumber,
                Origin = request.Origin,
                Destination = request.Destination,
                Status = request.Status,
                WeightKg = request.WeightKg,
                DeliveredAt = request.Status == ShipmentStatus.Delivered && existingShipment.Status != ShipmentStatus.Delivered
                    ? DateTime.UtcNow
                    : existingShipment.DeliveredAt
            };

            if (existingShipment.TrackingNumber != request.TrackingNumber)
            {
                _trackingNumberIndex.Remove(existingShipment.TrackingNumber);
                _trackingNumberIndex[request.TrackingNumber] = id;
            }

            _shipments[id] = updatedShipment;

            return Task.FromResult<OneOf<ShipmentDto, ShipmentNotFound, ValidationError>>(ToDto(updatedShipment));
        }

        public Task<OneOf<bool, ShipmentNotFound>> DeleteShipmentAsync(Guid id)
        {
            if (!_shipments.TryGetValue(id, out var shipment))
            {
                return Task.FromResult<OneOf<bool, ShipmentNotFound>>(new ShipmentNotFound(id));
            }

            _trackingNumberIndex.Remove(shipment.TrackingNumber);
            _shipments.Remove(id);

            return Task.FromResult<OneOf<bool, ShipmentNotFound>>(true);
        }

        public Task<OneOf<ShipmentDto, ShipmentNotFound>> GetShipmentByIdAsync(Guid id)
        {
            if (!_shipments.TryGetValue(id, out var shipment))
            {
                return Task.FromResult<OneOf<ShipmentDto, ShipmentNotFound>>(new ShipmentNotFound(id));
            }

            return Task.FromResult<OneOf<ShipmentDto, ShipmentNotFound>>(ToDto(shipment));
        }

        public Task<OneOf<ShipmentDto, ShipmentNotFound>> GetShipmentByTrackingNumberAsync(string trackingNumber)
        {
            if (!_trackingNumberIndex.TryGetValue(trackingNumber, out var id) ||
                !_shipments.TryGetValue(id, out var shipment))
            {
                return Task.FromResult<OneOf<ShipmentDto, ShipmentNotFound>>(
                    new ShipmentNotFound(Guid.Empty)
                );
            }

            return Task.FromResult<OneOf<ShipmentDto, ShipmentNotFound>>(ToDto(shipment));
        }

        public Task<PagedResult<ShipmentDto>> GetShipmentsAsync(
            int pageNumber,
            int pageSize,
            ShipmentFilter? filter = null,
            ShipmentSort? sort = null
        )
        {
            var query = _shipments.Values.AsQueryable();

            if (filter != null)
            {
                if (filter.Status.HasValue)
                {
                    query = query.Where(s => s.Status == filter.Status.Value);
                }

                if (!string.IsNullOrWhiteSpace(filter.Origin))
                {
                    query = query.Where(s => s.Origin.Contains(filter.Origin, StringComparison.OrdinalIgnoreCase));
                }

                if (!string.IsNullOrWhiteSpace(filter.Destination))
                {
                    query = query.Where(s => s.Destination.Contains(filter.Destination, StringComparison.OrdinalIgnoreCase));
                }

                if (filter.CreatedFrom.HasValue)
                {
                    query = query.Where(s => s.CreatedAt >= filter.CreatedFrom.Value);
                }

                if (filter.CreatedTo.HasValue)
                {
                    query = query.Where(s => s.CreatedAt <= filter.CreatedTo.Value);
                }
            }

            var sortBy = sort?.SortBy?.ToLowerInvariant() ?? "createdat";
            var isDescending = sort?.IsDescending ?? false;

            query = (sortBy, isDescending) switch
            {
                ("trackingnumber", false) => query.OrderBy(s => s.TrackingNumber),
                ("trackingnumber", true) => query.OrderByDescending(s => s.TrackingNumber),
                ("origin", false) => query.OrderBy(s => s.Origin),
                ("origin", true) => query.OrderByDescending(s => s.Origin),
                ("destination", false) => query.OrderBy(s => s.Destination),
                ("destination", true) => query.OrderByDescending(s => s.Destination),
                ("status", false) => query.OrderBy(s => s.Status),
                ("status", true) => query.OrderByDescending(s => s.Status),
                ("weightkg", false) => query.OrderBy(s => s.WeightKg),
                ("weightkg", true) => query.OrderByDescending(s => s.WeightKg),
                ("createdat", false) => query.OrderBy(s => s.CreatedAt),
                ("createdat", true) => query.OrderByDescending(s => s.CreatedAt),
                _ => query.OrderByDescending(s => s.CreatedAt)
            };

            var totalCount = query.Count();
            var totalPages = (int)Math.Ceiling(totalCount / (double)pageSize);

            var items = query
                .Skip((pageNumber - 1) * pageSize)
                .Take(pageSize)
                .Select(ToDto)
                .ToList();

            var result = new PagedResult<ShipmentDto>(items, totalCount, pageNumber, pageSize, totalPages);

            return Task.FromResult(result);
        }

        private static ShipmentDto ToDto(Shipment shipment) => new(
            shipment.Id,
            shipment.TrackingNumber,
            shipment.Origin,
            shipment.Destination,
            shipment.Status,
            shipment.WeightKg,
            shipment.CreatedAt,
            shipment.DeliveredAt
        );
    }
}

namespace LogisticsApi.Controllers
{
    using LogisticsApi.Models;
    using LogisticsApi.Services;
    using Microsoft.AspNetCore.Mvc;
    using OneOf;

    [ApiController]
    [Route("api/[controller]")]
    public class ShipmentsController : ControllerBase
    {
        private readonly IShipmentService _shipmentService;

        public ShipmentsController(IShipmentService shipmentService)
        {
            _shipmentService = shipmentService;
        }

        [HttpGet]
        [ProducesResponseType(typeof(PagedResult<ShipmentDto>), StatusCodes.Status200OK)]
        public async Task<ActionResult<PagedResult<ShipmentDto>>> GetShipments(
            [FromQuery] int pageNumber = 1,
            [FromQuery] int pageSize = 10,
            [FromQuery] ShipmentStatus? status = null,
            [FromQuery] string? origin = null,
            [FromQuery] string? destination = null,
            [FromQuery] DateTime? createdFrom = null,
            [FromQuery] DateTime? createdTo = null,
            [FromQuery] string? sortBy = null,
            [FromQuery] bool? sortDescending = null)
        {
            if (pageNumber < 1) pageNumber = 1;
            if (pageSize < 1) pageSize = 10;
            if (pageSize > 100) pageSize = 100;

