    Task<OneOf<PropertyListing, DatabaseError>> CreateAsync(CreatePropertyListing request);
    Task<OneOf<PropertyListing, NotFound, DatabaseError>> UpdateAsync(Guid id, UpdatePropertyListing request);
    Task<OneOf<bool, NotFound, DatabaseError>> DeleteAsync(Guid id);
}

// Repository Implementation
public class PropertyListingRepository : IPropertyListingRepository
{
    private readonly Dictionary<Guid, PropertyListing> _storage = new();

    public Task<OneOf<PropertyListing, NotFound, DatabaseError>> GetByIdAsync(Guid id)
    {
        if (_storage.TryGetValue(id, out var listing))
        {
            return Task.FromResult(OneOf<PropertyListing, NotFound, DatabaseError>.FromT0(listing));
        }
        return Task.FromResult(OneOf<PropertyListing, NotFound, DatabaseError>.FromT1(new NotFound(id)));
    }

    public Task<OneOf<IEnumerable<PropertyListing>, DatabaseError>> GetAllAsync()
    {
        return Task.FromResult(OneOf<IEnumerable<PropertyListing>, DatabaseError>.FromT0(_storage.Values.AsEnumerable()));
    }

    public Task<OneOf<PropertyListing, DatabaseError>> CreateAsync(CreatePropertyListing request)
    {
        var listing = new PropertyListing(
            Guid.NewGuid(),
            request.Address,
            request.City,
            request.State,
            request.Price,
            request.Bedrooms,
            request.Bathrooms,
            request.SquareFeet,
            request.Type,
            DateTimeOffset.UtcNow
        );
        _storage[listing.Id] = listing;
        return Task.FromResult(OneOf<PropertyListing, DatabaseError>.FromT0(listing));
    }

    public Task<OneOf<PropertyListing, NotFound, DatabaseError>> UpdateAsync(Guid id, UpdatePropertyListing request)
    {
        if (!_storage.TryGetValue(id, out var existing))
        {
            return Task.FromResult(OneOf<PropertyListing, NotFound, DatabaseError>.FromT1(new NotFound(id)));
        }

        var updated = existing with
        {
            Address = request.Address,
            City = request.City,
            State = request.State,
            Price = request.Price,
            Bedrooms = request.Bedrooms,
            Bathrooms = request.Bathrooms,
            SquareFeet = request.SquareFeet,
            Type = request.Type
        };
        _storage[id] = updated;
        return Task.FromResult(OneOf<PropertyListing, NotFound, DatabaseError>.FromT0(updated));
    }

    public Task<OneOf<bool, NotFound, DatabaseError>> DeleteAsync(Guid id)
    {
        if (!_storage.ContainsKey(id))
        {
            return Task.FromResult(OneOf<bool, NotFound, DatabaseError>.FromT1(new NotFound(id)));
        }
        _storage.Remove(id);
        return Task.FromResult(OneOf<bool, NotFound, DatabaseError>.FromT0(true));
    }
}

