public enum PropertyType
{
    House,
    Condo,
    Townhouse,
    Apartment,
    Land
}

public record CreatePropertyListingCommand(
    string Title,
    string Description,
    decimal Price,
    string StreetAddress,
    string City,
    string State,
    string ZipCode,
    PropertyType PropertyType,
    int Bedrooms,
    decimal Bathrooms,
    int SquareFeet,
    Guid ListingAgentId
);

public class CreatePropertyListingCommandValidator : AbstractValidator<CreatePropertyListingCommand>
{
    public CreatePropertyListingCommandValidator()
    {
        RuleFor(x => x.Title)
            .NotEmpty().WithMessage("Title is required")
            .MaximumLength(200).WithMessage("Title must not exceed 200 characters");

        RuleFor(x => x.Description)
            .NotEmpty().WithMessage("Description is required")
            .MaximumLength(5000).WithMessage("Description must not exceed 5000 characters");

        RuleFor(x => x.Price)
            .GreaterThan(0).WithMessage("Price must be greater than 0");

        RuleFor(x => x.StreetAddress)
            .NotEmpty().WithMessage("Street address is required")
            .MaximumLength(200).WithMessage("Street address must not exceed 200 characters");

        RuleFor(x => x.City)
            .NotEmpty().WithMessage("City is required")
            .MaximumLength(100).WithMessage("City must not exceed 100 characters");

        RuleFor(x => x.State)
            .NotEmpty().WithMessage("State is required")
            .Length(2).WithMessage("State must be exactly 2 characters")
            .Matches("^[A-Z]{2}$").WithMessage("State must be a valid two-letter uppercase state code");

        RuleFor(x => x.ZipCode)
            .NotEmpty().WithMessage("ZIP code is required")
            .Matches(@"^\d{5}(-\d{4})?$").WithMessage("ZIP code must be 5 digits or 9 digits in format XXXXX-XXXX");

        RuleFor(x => x.PropertyType)
            .IsInEnum().WithMessage("Invalid property type");

        RuleFor(x => x.Bedrooms)
            .InclusiveBetween(0, 20).WithMessage("Bedrooms must be between 0 and 20");

        RuleFor(x => x.Bathrooms)
            .InclusiveBetween(0m, 10m).WithMessage("Bathrooms must be between 0.0 and 10.0");

        RuleFor(x => x.SquareFeet)
            .GreaterThan(0).WithMessage("Square footage must be greater than 0");

        RuleFor(x => x.ListingAgentId)
            .NotEqual(Guid.Empty).WithMessage("Valid listing agent ID is required");
    }
}

