public static class ValidationExtensions
{
    public static IResult ToValidationProblem(this ValidationResult result)
    {
        if (result.IsValid)
            return Results.Ok();

        var errors = result.Errors
            .GroupBy(e => e.PropertyName)
            .ToDictionary(
                g => g.Key,
                g => g.Select(e => e.ErrorMessage).ToArray()
            );

        return Results.ValidationProblem(errors);
    }
}

public class Program
{
    public static void Main(string[] args)
    {
        var builder = WebApplication.CreateBuilder(args);

        builder.Services.AddValidatorsFromAssemblyContaining<CreatePropertyListingCommandValidator>();

        var app = builder.Build();

        app.MapPost("/api/properties", async (
            CreatePropertyListingCommand command,
            IValidator<CreatePropertyListingCommand> validator) =>
        {
            var validationResult = await validator.ValidateAsync(command);

            if (!validationResult.IsValid)
            {
                return validationResult.ToValidationProblem();
            }

            var propertyId = Guid.NewGuid();

            var response = new PropertyListingResponse
            {
                Id = propertyId,
                Title = command.Title,
                Description = command.Description,
                Price = command.Price,
                StreetAddress = command.StreetAddress,
                City = command.City,
                State = command.State,
                ZipCode = command.ZipCode,
                PropertyType = command.PropertyType,
                Bedrooms = command.Bedrooms,
                Bathrooms = command.Bathrooms,
                SquareFeet = command.SquareFeet,
                ListingAgentId = command.ListingAgentId,
                CreatedAt = DateTime.UtcNow
            };

            return Results.Created($"/api/properties/{propertyId}", response);
        });

        app.Run();
    }
}

