// Domain Models
public record Course(Guid Id, string Title, int Capacity, int EnrolledCount);
public record Student(Guid Id, string FirstName, string LastName, string Email);
public record Enrollment(Guid Id, Guid CourseId, Guid StudentId, DateTime EnrolledAt);

// Request/Response DTOs
public record EnrollStudentRequest(Guid CourseId, Guid StudentId);
public record EnrollmentResponse(Guid EnrollmentId, string CourseTitle, string StudentName, DateTime EnrolledAt);

// Result Types (Error types)
public record CourseNotFound(Guid CourseId);
public record StudentNotFound(Guid StudentId);
public record CourseFull(Guid CourseId, int Capacity, int CurrentEnrolled);

// Service Interface
public interface IEnrollmentService
{
    Task<OneOf<EnrollmentResponse, CourseNotFound, StudentNotFound, CourseFull>> EnrollStudentAsync(EnrollStudentRequest request);
    Task<OneOf<Course, CourseNotFound>> GetCourseAsync(Guid courseId);
    Task<OneOf<Student, StudentNotFound>> GetStudentAsync(Guid studentId);
}

// Service Implementation
public class EnrollmentService : IEnrollmentService
{
    private readonly Dictionary<Guid, Course> _courses = new();
    private readonly Dictionary<Guid, Student> _students = new();
    private readonly List<Enrollment> _enrollments = new();

    public EnrollmentService()
    {
        var courseId1 = Guid.Parse("11111111-1111-1111-1111-111111111111");
        var courseId2 = Guid.Parse("22222222-2222-2222-2222-222222222222");
        var studentId1 = Guid.Parse("aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa");
        var studentId2 = Guid.Parse("bbbbbbbb-bbbb-bbbb-bbbb-bbbbbbbbbbbb");

        _courses[courseId1] = new Course(courseId1, "Introduction to C#", 30, 28);
        _courses[courseId2] = new Course(courseId2, "Advanced ASP.NET Core", 25, 10);
        _students[studentId1] = new Student(studentId1, "John", "Doe", "john.doe@email.com");
        _students[studentId2] = new Student(studentId2, "Jane", "Smith", "jane.smith@email.com");
    }

    public Task<OneOf<Course, CourseNotFound>> GetCourseAsync(Guid courseId)
    {
        if (_courses.TryGetValue(courseId, out var course))
            return Task.FromResult<OneOf<Course, CourseNotFound>>(course);

        return Task.FromResult<OneOf<Course, CourseNotFound>>(new CourseNotFound(courseId));
    }

    public Task<OneOf<Student, StudentNotFound>> GetStudentAsync(Guid studentId)
    {
        if (_students.TryGetValue(studentId, out var student))
            return Task.FromResult<OneOf<Student, StudentNotFound>>(student);

        return Task.FromResult<OneOf<Student, StudentNotFound>>(new StudentNotFound(studentId));
    }

    public async Task<OneOf<EnrollmentResponse, CourseNotFound, StudentNotFound, CourseFull>> EnrollStudentAsync(EnrollStudentRequest request)
    {
        if (!_courses.TryGetValue(request.CourseId, out var course))
            return new CourseNotFound(request.CourseId);

        if (!_students.TryGetValue(request.StudentId, out var student))
            return new StudentNotFound(request.StudentId);

        if (course.EnrolledCount >= course.Capacity)
            return new CourseFull(request.CourseId, course.Capacity, course.EnrolledCount);

        var enrollment = new Enrollment(
            Guid.NewGuid(),
            request.CourseId,
            request.StudentId,
            DateTime.UtcNow);

        _enrollments.Add(enrollment);
        _courses[request.CourseId] = course with { EnrolledCount = course.EnrolledCount + 1 };

        var response = new EnrollmentResponse(
            enrollment.Id,
            course.Title,
            $"{student.FirstName} {student.LastName}",
            enrollment.EnrolledAt);

        return response;
    }
}

