    Task<OneOf<CourseEnrollment, ValidationError>> CreateAsync(CreateEnrollmentRequest request);
    Task<OneOf<CourseEnrollment, EnrollmentNotFoundError>> GetByIdAsync(Guid id);
    Task<PagedResult<CourseEnrollment>> GetPagedAsync(EnrollmentQueryParameters parameters);
    Task<OneOf<CourseEnrollment, EnrollmentNotFoundError>> UpdateAsync(Guid id, UpdateEnrollmentRequest request);
    Task<OneOf<bool, EnrollmentNotFoundError>> DeleteAsync(Guid id);
}

// In-Memory Repository for demonstration
public class InMemoryEnrollmentRepository
{
    private readonly Dictionary<Guid, CourseEnrollment> _enrollments = new();

    public Task<CourseEnrollment?> GetByIdAsync(Guid id)
    {
        _enrollments.TryGetValue(id, out var enrollment);
        return Task.FromResult(enrollment);
    }

    public Task<IEnumerable<CourseEnrollment>> GetAllAsync()
    {
        return Task.FromResult(_enrollments.Values.AsEnumerable());
    }

    public Task<CourseEnrollment> AddAsync(CourseEnrollment enrollment)
    {
        _enrollments[enrollment.Id] = enrollment;
        return Task.FromResult(enrollment);
    }

    public Task<CourseEnrollment?> UpdateAsync(Guid id, CourseEnrollment enrollment)
    {
        if (!_enrollments.ContainsKey(id))
            return Task.FromResult<CourseEnrollment?>(null);

        _enrollments[id] = enrollment;
        return Task.FromResult<CourseEnrollment?>(enrollment);
    }

    public Task<bool> DeleteAsync(Guid id)
    {
        return Task.FromResult(_enrollments.Remove(id));
    }

    public Task<bool> ExistsAsync(Guid studentId, Guid courseId)
    {
        return Task.FromResult(_enrollments.Values.Any(e => e.StudentId == studentId && e.CourseId == courseId));
    }
}

// Service Implementation
public class EnrollmentService : IEnrollmentService
{
    private readonly InMemoryEnrollmentRepository _repository;

    public EnrollmentService(InMemoryEnrollmentRepository repository)
    {
        _repository = repository;
    }

    public async Task<OneOf<CourseEnrollment, ValidationError>> CreateAsync(CreateEnrollmentRequest request)
    {
        var exists = await _repository.ExistsAsync(request.StudentId, request.CourseId);
        if (exists)
            return new ValidationError("Enrollment already exists for this student and course.");

        var enrollment = new CourseEnrollment
        {
            Id = Guid.NewGuid(),
            StudentId = request.StudentId,
            CourseId = request.CourseId,
            StudentName = request.StudentName,
            CourseName = request.CourseName,
            Status = EnrollmentStatus.Pending,
            Notes = request.Notes,
            EnrolledAt = DateTimeOffset.UtcNow
        };

        await _repository.AddAsync(enrollment);
        return enrollment;
    }

    public async Task<OneOf<CourseEnrollment, EnrollmentNotFoundError>> GetByIdAsync(Guid id)
    {
        var enrollment = await _repository.GetByIdAsync(id);
        if (enrollment is null)
            return new EnrollmentNotFoundError(id);

        return enrollment;
    }

    public async Task<PagedResult<CourseEnrollment>> GetPagedAsync(EnrollmentQueryParameters parameters)
    {
        var query = (await _repository.GetAllAsync()).AsQueryable();

        // Filtering
        if (parameters.StudentId.HasValue)
            query = query.Where(e => e.StudentId == parameters.StudentId.Value);

        if (parameters.CourseId.HasValue)
            query = query.Where(e => e.CourseId == parameters.CourseId.Value);

        if (parameters.Status.HasValue)
            query = query.Where(e => e.Status == parameters.Status.Value);

        if (!string.IsNullOrWhiteSpace(parameters.StudentNameContains))
            query = query.Where(e => e.StudentName.Contains(parameters.StudentNameContains, StringComparison.OrdinalIgnoreCase));

        if (!string.IsNullOrWhiteSpace(parameters.CourseNameContains))
            query = query.Where(e => e.CourseName.Contains(parameters.CourseNameContains, StringComparison.OrdinalIgnoreCase));

        if (parameters.EnrolledAfter.HasValue)
            query = query.Where(e => e.EnrolledAt >= parameters.EnrolledAfter.Value);

        if (parameters.EnrolledBefore.HasValue)
            query = query.Where(e => e.EnrolledAt <= parameters.EnrolledBefore.Value);

        // Sorting
        query = parameters.SortBy?.ToLowerInvariant() switch
        {
            "studentname" => parameters.SortDescending 
                ? query.OrderByDescending(e => e.StudentName) 
                : query.OrderBy(e => e.StudentName),
            "coursename" => parameters.SortDescending 
                ? query.OrderByDescending(e => e.CourseName) 
                : query.OrderBy(e => e.CourseName),
            "status" => parameters.SortDescending 
                ? query.OrderByDescending(e => e.Status) 
                : query.OrderBy(e => e.Status),
            "enrolledat" => parameters.SortDescending 
                ? query.OrderByDescending(e => e.EnrolledAt) 
                : query.OrderBy(e => e.EnrolledAt),
            "progress" => parameters.SortDescending 
                ? query.OrderByDescending(e => e.ProgressPercentage ?? 0) 
                : query.OrderBy(e => e.ProgressPercentage ?? 0),
            _ => parameters.SortDescending 
                ? query.OrderByDescending(e => e.EnrolledAt) 
                : query.OrderBy(e => e.EnrolledAt)
        };

        var totalCount = query.Count();

        var items = query
            .Skip((parameters.PageNumber - 1) * parameters.PageSize)
            .Take(parameters.PageSize)
            .ToList();

        return new PagedResult<CourseEnrollment>
        {
            Items = items,
            TotalCount = totalCount,
            PageNumber = parameters.PageNumber,
            PageSize = parameters.PageSize
        };
    }

    public async Task<OneOf<CourseEnrollment, EnrollmentNotFoundError>> UpdateAsync(Guid id, UpdateEnrollmentRequest request)
    {
        var existing = await _repository.GetByIdAsync(id);
        if (existing is null)
            return new EnrollmentNotFoundError(id);

        var updated = existing with
        {
            Status = request.Status,
            ProgressPercentage = request.ProgressPercentage,
            Notes = request.Notes,
            CompletedAt = request.Status == EnrollmentStatus.Completed 
                ? DateTimeOffset.UtcNow 
                : existing.CompletedAt
        };

        await _repository.UpdateAsync(id, updated);
        return updated;
    }

    public async Task<OneOf<bool, EnrollmentNotFoundError>> DeleteAsync(Guid id)
    {
        var existing = await _repository.GetByIdAsync(id);
        if (existing is null)
            return new EnrollmentNotFoundError(id);

        await _repository.DeleteAsync(id);
        return true;
    }
}

