[ApiController]
[Route("api/[controller]")]
public class EnrollmentsController : ControllerBase
{
    private readonly IEnrollmentService _service;

    public EnrollmentsController(IEnrollmentService service)
    {
        _service = service;
    }

    /// <summary>
    /// Creates a new course enrollment
    /// </summary>
    [HttpPost]
    [ProducesResponseType(typeof(CourseEnrollment), StatusCodes.Status201Created)]
    [ProducesResponseType(typeof(ValidationProblemDetails), StatusCodes.Status400BadRequest)]
    [ProducesResponseType(typeof(ProblemDetails), StatusCodes.Status409Conflict)]
    public async Task<IActionResult> Create([FromBody] CreateEnrollmentRequest request)
    {
        var result = await _service.CreateAsync(request);

        return result.Match<IActionResult>(
            enrollment => Results.Created($"/api/enrollments/{enrollment.Id}", enrollment),
            error => Results.Conflict(new ProblemDetails
            {
                Title = "Duplicate Enrollment",
                Status = StatusCodes.Status409Conflict,
                Detail = error.Message
            })
        );
    }

    /// <summary>
    /// Gets a paginated list of enrollments with filtering and sorting
    /// </summary>
    [HttpGet]
    [ProducesResponseType(typeof(PagedResult<CourseEnrollment>), StatusCodes.Status200OK)]
    public async Task<IActionResult> GetAll([FromQuery] EnrollmentQueryParameters parameters)
    {
        var result = await _service.GetPagedAsync(parameters);
        return Ok(result);
    }

    /// <summary>
    /// Gets a specific enrollment by ID
    /// </summary>
    [HttpGet("{id:guid}")]
    [ProducesResponseType(typeof(CourseEnrollment), StatusCodes.Status200OK)]
    [ProducesResponseType(typeof(ProblemDetails), StatusCodes.Status404NotFound)]
