    {
        var result = await _service.GetByIdAsync(id);

        return result.Match<IActionResult>(
            enrollment => Ok(enrollment),
            error => Results.NotFound(new ProblemDetails
            {
                Title = "Enrollment Not Found",
                Status = StatusCodes.Status404NotFound,
                Detail = $"Enrollment with ID {error.Id} was not found."
            })
        );
    }

    /// <summary>
    /// Updates an existing enrollment
    /// </summary>
    [HttpPut("{id:guid}")]
    [ProducesResponseType(typeof(CourseEnrollment), StatusCodes.Status200OK)]
    [ProducesResponseType(typeof(ValidationProblemDetails), StatusCodes.Status400BadRequest)]
    [ProducesResponseType(typeof(ProblemDetails), StatusCodes.Status404NotFound)]
    public async Task<IActionResult> Update(Guid id, [FromBody] UpdateEnrollmentRequest request)
    {
        var result = await _service.UpdateAsync(id, request);

        return result.Match<IActionResult>(
            enrollment => Ok(enrollment),
            error => Results.NotFound(new ProblemDetails
            {
                Title = "Enrollment Not Found",
                Status = StatusCodes.Status404NotFound,
                Detail = $"Enrollment with ID {error.Id} was not found."
            })
        );
    }

    /// <summary>
    /// Deletes an enrollment
    /// </summary>
    [HttpDelete("{id:guid}")]
    [ProducesResponseType(StatusCodes.Status204NoContent)]
    [ProducesResponseType(typeof(ProblemDetails), StatusCodes.Status404NotFound)]
    public async Task<IActionResult> Delete(Guid id)
    {
        var result = await _service.DeleteAsync(id);

        return result.Match<IActionResult>(
            _ => NoContent(),
            error => Results.NotFound(new ProblemDetails
            {
                Title = "Enrollment Not Found",
                Status = StatusCodes.Status404NotFound,
                Detail = $"Enrollment with ID {error.Id} was not found."
            })
        );
    }
}

