public record EnrollmentCommand(
    Guid StudentId,
    Guid CourseId,
    string CourseCode,
    DateTime EnrollmentDate,
    string PaymentMethod
);

public record EnrollmentResult(
    Guid EnrollmentId,
    Guid StudentId,
    Guid CourseId,
    string Status,
    DateTime EnrolledAt
);

public class EnrollmentCommandValidator : AbstractValidator<EnrollmentCommand>
{
    private static readonly string[] ValidPaymentMethods =
        { "CreditCard", "DebitCard", "BankTransfer", "Scholarship" };

    public EnrollmentCommandValidator()
    {
        RuleFor(x => x.StudentId)
            .NotEqual(Guid.Empty)
            .WithMessage("StudentId must not be empty");

        RuleFor(x => x.CourseId)
            .NotEqual(Guid.Empty)
            .WithMessage("CourseId must not be empty");

        RuleFor(x => x.CourseCode)
            .NotEmpty()
            .WithMessage("CourseCode must not be empty")
            .Length(4, 10)
            .WithMessage("CourseCode must be between 4 and 10 characters")
            .Matches(@"^[A-Z]{2,4}[0-9]{3,4}$")
            .WithMessage("CourseCode must match pattern [A-Z]{2,4}[0-9]{3,4}");

        RuleFor(x => x.EnrollmentDate)
            .Must(date => date <= DateTime.UtcNow)
            .WithMessage("EnrollmentDate must not be in the future")
            .Must(date => date >= DateTime.UtcNow.AddDays(-30))
            .WithMessage("EnrollmentDate must not be more than 30 days in the past");

        RuleFor(x => x.PaymentMethod)
            .NotEmpty()
            .WithMessage("PaymentMethod must not be empty")
            .Must(method => ValidPaymentMethods.Contains(method))
            .WithMessage("PaymentMethod must be one of: CreditCard, DebitCard, BankTransfer, Scholarship");
    }
}

