var builder = WebApplication.CreateBuilder(args);

builder.Services.AddScoped<IEnrollmentService, EnrollmentService>();
builder.Services.AddValidatorsFromAssemblyContaining<EnrollmentCommandValidator>();

var app = builder.Build();

app.MapPost("/api/enrollments", async (
    EnrollmentCommand command,
    IValidator<EnrollmentCommand> validator,
    IEnrollmentService enrollmentService) =>
{
    var validationResult = await validator.ValidateAsync(command);

    if (!validationResult.IsValid)
    {
        return Results.ValidationProblem(validationResult.ToDictionary());
    }

    var result = await enrollmentService.EnrollAsync(command);
    return Results.Created($"/api/enrollments/{result.EnrollmentId}", result);
});

