public interface IReservationService
{
    Task<OneOf<Reservation, NotFound>> GetReservationAsync(Guid id);
    Task<OneOf<Reservation, ValidationError, Conflict>> CreateReservationAsync(CreateReservationRequest request);
    Task<OneOf<Reservation, NotFound, ValidationError>> UpdateReservationAsync(Guid id, UpdateReservationRequest request);
    Task<OneOf<Success, NotFound>> DeleteReservationAsync(Guid id);
}

public class ReservationService : IReservationService
{
    private readonly Dictionary<Guid, Reservation> _reservations = new();

    public Task<OneOf<Reservation, NotFound>> GetReservationAsync(Guid id)
    {
        if (_reservations.TryGetValue(id, out var reservation))
        {
            return Task.FromResult<OneOf<Reservation, NotFound>>(reservation);
        }
        return Task.FromResult<OneOf<Reservation, NotFound>>(new NotFound(id));
    }

    public Task<OneOf<Reservation, ValidationError, Conflict>> CreateReservationAsync(CreateReservationRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.CustomerName))
        {
            return Task.FromResult<OneOf<Reservation, ValidationError, Conflict>>(
                new ValidationError(["CustomerName is required"]));
        }

        if (request.PartySize < 1 || request.PartySize > 20)
        {
            return Task.FromResult<OneOf<Reservation, ValidationError, Conflict>>(
                new ValidationError(["PartySize must be between 1 and 20"]));
        }

        var conflictingReservation = _reservations.Values.FirstOrDefault(r => 
            r.ReservationDate == request.ReservationDate && 
            r.TableNumber == request.TableNumber);

        if (conflictingReservation != null)
        {
            return Task.FromResult<OneOf<Reservation, ValidationError, Conflict>>(
                new Conflict("Table is already reserved for this time slot"));
        }

        var reservation = new Reservation(
            Guid.NewGuid(),
            request.CustomerName,
            request.PartySize,
            request.ReservationDate,
            request.TableNumber
        );

        _reservations[reservation.Id] = reservation;
        return Task.FromResult<OneOf<Reservation, ValidationError, Conflict>>(reservation);
    }

    public Task<OneOf<Reservation, NotFound, ValidationError>> UpdateReservationAsync(Guid id, UpdateReservationRequest request)
    {
        if (!_reservations.TryGetValue(id, out var existing))
        {
            return Task.FromResult<OneOf<Reservation, NotFound, ValidationError>>(new NotFound(id));
        }

        if (string.IsNullOrWhiteSpace(request.CustomerName))
        {
            return Task.FromResult<OneOf<Reservation, NotFound, ValidationError>>(
                new ValidationError(["CustomerName is required"]));
        }

        var updated = existing with { CustomerName = request.CustomerName, PartySize = request.PartySize };
        _reservations[id] = updated;

        return Task.FromResult<OneOf<Reservation, NotFound, ValidationError>>(updated);
    }

    public Task<OneOf<Success, NotFound>> DeleteReservationAsync(Guid id)
    {
        if (!_reservations.Remove(id))
        {
            return Task.FromResult<OneOf<Success, NotFound>>(new NotFound(id));
        }
        return Task.FromResult<OneOf<Success, NotFound>>(new Success());
    }
}

