    public Customer Add(Customer customer)
    {
        _customers[customer.Id] = customer;
        return customer;
    }

    public OneOf<Customer, EntityNotFound> Update(Customer customer)
    {
        if (!_customers.ContainsKey(customer.Id))
            return new EntityNotFound(customer.Id);

        _customers[customer.Id] = customer;
        return customer;
    }

    public OneOf<bool, EntityNotFound> Delete(Guid id)
    {
        if (!_customers.ContainsKey(id))
            return new EntityNotFound(id);

        _customers.Remove(id);
        return true;
    }

    public bool Exists(Guid id) => _customers.ContainsKey(id);
}

