    private static readonly int[] ValidBillingCycles = { 1, 3, 6, 12 };
    private static readonly Regex PlanIdPattern = new(@"^[a-z0-9-]+$", RegexOptions.Compiled);
    private static readonly Regex CurrencyPattern = new(@"^[A-Z]{3}$", RegexOptions.Compiled);

    public CreateSubscriptionCommandValidator()
    {
        RuleFor(x => x.SubscriptionId)
            .NotEmpty().WithMessage("SubscriptionId must not be empty");

        RuleFor(x => x.CustomerId)
            .NotEmpty().WithMessage("CustomerId must not be empty");

        RuleFor(x => x.PlanId)
            .NotEmpty().WithMessage("PlanId must not be empty")
            .Matches(PlanIdPattern).WithMessage("PlanId must contain only lowercase letters, numbers, and hyphens");

        RuleFor(x => x.PlanName)
            .NotEmpty().WithMessage("PlanName must not be empty");

        RuleFor(x => x.MonthlyAmount)
            .GreaterThan(0).WithMessage("MonthlyAmount must be positive");

        RuleFor(x => x.BillingCycleMonths)
            .Must(x => ValidBillingCycles.Contains(x))
            .WithMessage("BillingCycleMonths must be 1, 3, 6, or 12 months");

        RuleFor(x => x.StartDate)
            .Must(x => x > DateTimeOffset.UtcNow)
            .WithMessage("StartDate must be in the future");

        RuleFor(x => x.Currency)
            .NotEmpty().WithMessage("Currency must not be empty")
            .Length(3).WithMessage("Currency must be exactly 3 characters")
            .Matches(CurrencyPattern).WithMessage("Currency must be a valid 3-letter ISO currency code");

        RuleFor(x => x.Features)
            .NotNull().WithMessage("Features must not be null")
            .Must(x => x != null && x.Count > 0).WithMessage("At least one feature is required");

        When(x => !string.IsNullOrEmpty(x.PromoCode), () =>
        {
            RuleFor(x => x.PromoCode!)
                .MinimumLength(3).WithMessage("PromoCode must be at least 3 characters")
                .MaximumLength(20).WithMessage("PromoCode must not exceed 20 characters");
        });
    }
}

public static class ValidationExtensions
{
    public static IDictionary<string, string[]> ToValidationErrors(this IEnumerable<ValidationFailure> failures)
    {
        return failures
            .GroupBy(f => f.PropertyName)
            .ToDictionary(
                g => g.Key,
                g => g.Select(f => f.ErrorMessage).ToArray()
            );
    }
}

