public class Program
{
    public static void Main(string[] args)
    {
        var builder = WebApplication.CreateBuilder(args);

        builder.Services.AddValidatorsFromAssemblyContaining<CreateSubscriptionCommandValidator>();
        builder.Services.AddScoped<ISubscriptionService, SubscriptionService>();

        var app = builder.Build();

        app.UseExceptionHandler(err => err.Run(async ctx =>
        {
            ctx.Response.ContentType = "application/problem+json";
            await ctx.Response.WriteAsJsonAsync(new ProblemDetails
            {
                Title = "Server Error",
                Status = 500,
                Detail = "An unexpected error occurred while processing the subscription request"
            });
        }));

        app.MapPost("/api/subscriptions", async (
            CreateSubscriptionCommand command,
            IValidator<CreateSubscriptionCommand> validator,
            ISubscriptionService subscriptionService) =>
        {
            var validationResult = await validator.ValidateAsync(command);

            if (!validationResult.IsValid)
            {
                var errorResponse = new SubscriptionValidationErrorResponse(
                    ErrorCode: "VALIDATION_ERROR",
                    Message: "One or more validation errors occurred",
                    ValidationErrors: validationResult.Errors.ToValidationErrors()
                );
                return Results.BadRequest(errorResponse);
            }

            var response = await subscriptionService.CreateSubscriptionAsync(command);
            return Results.Created($"/api/subscriptions/{response.SubscriptionId}", response);
        });

        app.Run();
    }
}

