// Enums
public enum TaskStatus { Backlog, InProgress, InReview, Done }
public enum TaskPriority { Low, Medium, High, Critical }

// Domain Models
public record ProjectTask
{
    public Guid Id { get; init; }
    public string Title { get; init; } = string.Empty;
    public string Description { get; init; } = string.Empty;
    public TaskStatus Status { get; init; }
    public TaskPriority Priority { get; init; }
    public Guid ProjectId { get; init; }
    public Guid? AssignedToUserId { get; init; }
    public DateTimeOffset CreatedAt { get; init; }
    public DateTimeOffset? DueDate { get; init; }
}

// DTOs
public record PagedResult<T>(
    IReadOnlyList<T> Items,
    int TotalCount,
    int PageNumber,
    int PageSize,
    int TotalPages
);

public record CreateTaskRequest(
    [Required][StringLength(200)] string Title,
    [StringLength(2000)] string Description,
    TaskStatus Status,
    TaskPriority Priority,
    Guid ProjectId,
    Guid? AssignedToUserId,
    DateTimeOffset? DueDate
);

public record UpdateTaskRequest(
    [Required][StringLength(200)] string Title,
    [StringLength(2000)] string Description,
    TaskStatus Status,
    TaskPriority Priority,
    Guid? AssignedToUserId,
    DateTimeOffset? DueDate
);

public record TaskFilterRequest
{
    public Guid? ProjectId { get; init; }
    public TaskStatus? Status { get; init; }
    public TaskPriority? Priority { get; init; }
    public Guid? AssignedToUserId { get; init; }
    public string? SearchTerm { get; init; }
}

public record TaskSortRequest
{
    public string SortBy { get; init; } = "CreatedAt";
    public bool SortDescending { get; init; } = true;
}

// Service Interface
public interface IProjectTaskService
{
    Task<PagedResult<ProjectTask>> GetTasksAsync(
        int pageNumber,
        int pageSize,
        TaskFilterRequest filter,
        TaskSortRequest sort,
        CancellationToken cancellationToken = default);

    Task<ProjectTask?> GetTaskByIdAsync(Guid id, CancellationToken cancellationToken = default);
    Task<ProjectTask> CreateTaskAsync(CreateTaskRequest request, CancellationToken cancellationToken = default);
    Task<ProjectTask?> UpdateTaskAsync(Guid id, UpdateTaskRequest request, CancellationToken cancellationToken = default);
    Task<bool> DeleteTaskAsync(Guid id, CancellationToken cancellationToken = default);
}

// Service Implementation
public class ProjectTaskService : IProjectTaskService
{
    private readonly List<ProjectTask> _tasks = new();
    private int _totalPages;

    public Task<PagedResult<ProjectTask>> GetTasksAsync(
        int pageNumber,
        int pageSize,
        TaskFilterRequest filter,
        TaskSortRequest sort,
        CancellationToken cancellationToken = default)
    {
        var query = _tasks.AsEnumerable();

        // Apply filters
        if (filter.ProjectId.HasValue)
            query = query.Where(t => t.ProjectId == filter.ProjectId.Value);

        if (filter.Status.HasValue)
            query = query.Where(t => t.Status == filter.Status.Value);

        if (filter.Priority.HasValue)
            query = query.Where(t => t.Priority == filter.Priority.Value);

        if (filter.AssignedToUserId.HasValue)
            query = query.Where(t => t.AssignedToUserId == filter.AssignedToUserId.Value);

        if (!string.IsNullOrWhiteSpace(filter.SearchTerm))
            query = query.Where(t => t.Title.Contains(filter.SearchTerm, StringComparison.OrdinalIgnoreCase) ||
                                     t.Description.Contains(filter.SearchTerm, StringComparison.OrdinalIgnoreCase));

        // Apply sorting
        query = sort.SortBy.ToLowerInvariant() switch
        {
            "title" => sort.SortDescending ? query.OrderByDescending(t => t.Title) : query.OrderBy(t => t.Title),
            "status" => sort.SortDescending ? query.OrderByDescending(t => t.Status) : query.OrderBy(t => t.Status),
            "priority" => sort.SortDescending ? query.OrderByDescending(t => t.Priority) : query.OrderBy(t => t.Priority),
            "duedate" => sort.SortDescending ? query.OrderByDescending(t => t.DueDate) : query.OrderBy(t => t.DueDate),
            _ => sort.SortDescending ? query.OrderByDescending(t => t.CreatedAt) : query.OrderBy(t => t.CreatedAt)
        };

        var totalCount = query.Count();
        var totalPages = (int)Math.Ceiling(totalCount / (double)pageSize);

        var items = query
            .Skip((pageNumber - 1) * pageSize)
            .Take(pageSize)
            .ToList();

        return Task.FromResult(new PagedResult<ProjectTask>(items, totalCount, pageNumber, pageSize, totalPages));
    }

    public Task<ProjectTask?> GetTaskByIdAsync(Guid id, CancellationToken cancellationToken = default)
    {
        var task = _tasks.FirstOrDefault(t => t.Id == id);
        return Task.FromResult(task);
    }

    public Task<ProjectTask> CreateTaskAsync(CreateTaskRequest request, CancellationToken cancellationToken = default)
    {
        var task = new ProjectTask
        {
            Id = Guid.NewGuid(),
            Title = request.Title,
            Description = request.Description ?? string.Empty,
            Status = request.Status,
            Priority = request.Priority,
            ProjectId = request.ProjectId,
            AssignedToUserId = request.AssignedToUserId,
            CreatedAt = DateTimeOffset.UtcNow,
            DueDate = request.DueDate
        };

        _tasks.Add(task);
        return Task.FromResult(task);
    }

    public Task<ProjectTask?> UpdateTaskAsync(Guid id, UpdateTaskRequest request, CancellationToken cancellationToken = default)
    {
        var index = _tasks.FindIndex(t => t.Id == id);
        if (index == -1)
            return Task.FromResult<ProjectTask?>(null);

        var existing = _tasks[index];
        var updated = existing with
        {
            Title = request.Title,
            Description = request.Description ?? string.Empty,
            Status = request.Status,
            Priority = request.Priority,
            AssignedToUserId = request.AssignedToUserId,
            DueDate = request.DueDate
        };

        _tasks[index] = updated;
        return Task.FromResult<ProjectTask?>(updated);
    }

    public Task<bool> DeleteTaskAsync(Guid id, CancellationToken cancellationToken = default)
    {
        var removed = _tasks.RemoveAll(t => t.Id == id);
        return Task.FromResult(removed > 0);
    }
}

