[ApiController]
[Route("api/projects/{projectId:guid}/tasks")]
public class ProjectTasksController : ControllerBase
{
    private readonly IProjectTaskService _taskService;

    public ProjectTasksController(IProjectTaskService taskService)
    {
        _taskService = taskService;
    }

    [HttpGet]
    public async Task<ActionResult<PagedResult<ProjectTask>>> GetTasks(
        Guid projectId,
        [FromQuery] int pageNumber = 1,
        [FromQuery] int pageSize = 10,
        [FromQuery] TaskStatus? status = null,
        [FromQuery] TaskPriority? priority = null,
        [FromQuery] Guid? assignedToUserId = null,
        [FromQuery] string? searchTerm = null,
        [FromQuery] string sortBy = "CreatedAt",
        [FromQuery] bool sortDescending = true,
        CancellationToken cancellationToken = default)
    {
        if (pageNumber < 1) pageNumber = 1;
        if (pageSize < 1) pageSize = 10;
        if (pageSize > 100) pageSize = 100;

        var filter = new TaskFilterRequest
        {
            ProjectId = projectId,
            Status = status,
            Priority = priority,
            AssignedToUserId = assignedToUserId,
            SearchTerm = searchTerm
        };

        var sort = new TaskSortRequest
        {
            SortBy = sortBy,
            SortDescending = sortDescending
        };

        var result = await _taskService.GetTasksAsync(pageNumber, pageSize, filter, sort, cancellationToken);
        return Ok(result);
    }

    [HttpGet("{id:guid}")]
    public async Task<ActionResult<ProjectTask>> GetTask(Guid id, CancellationToken cancellationToken = default)
    {
        var task = await _taskService.GetTaskByIdAsync(id, cancellationToken);
        if (task == null)
            return NotFound();

        return Ok(task);
    }

    [HttpPost]
    public async Task<ActionResult<ProjectTask>> CreateTask(
        Guid projectId,
        [FromBody] CreateTaskRequest request,
        CancellationToken cancellationToken = default)
    {
        if (request.ProjectId != projectId)
            return BadRequest("ProjectId in request body must match route parameter.");

        var task = await _taskService.CreateTaskAsync(request, cancellationToken);
        return CreatedAtAction(nameof(GetTask), new { projectId = task.ProjectId, id = task.Id }, task);
    }

    [HttpPut("{id:guid}")]
    public async Task<ActionResult<ProjectTask>> UpdateTask(
        Guid projectId,
        Guid id,
        [FromBody] UpdateTaskRequest request,
        CancellationToken cancellationToken = default)
    {
        var task = await _taskService.UpdateTaskAsync(id, request, cancellationToken);
        if (task == null)
            return NotFound();

        return Ok(task);
    }

    [HttpDelete("{id:guid}")]
    public async Task<ActionResult> DeleteTask(Guid id, CancellationToken cancellationToken = default)
    {
        var deleted = await _taskService.DeleteTaskAsync(id, cancellationToken);
        if (!deleted)
            return NotFound();

        return NoContent();
    }
}

