public class ApiKeyValidator : IApiKeyValidator
{
    private readonly Dictionary<Guid, ApiKey> _apiKeys = new();

    public ApiKeyValidator()
    {
        var testKey = new ApiKey(
            Guid.Parse("00000000-0000-0000-0000-000000000001"),
            "test@example.com",
            DateTime.UtcNow,
            true);
        _apiKeys[testKey.Id] = testKey;

        var inactiveKey = new ApiKey(
            Guid.Parse("00000000-0000-0000-0000-000000000002"),
            "inactive@example.com",
            DateTime.UtcNow.AddDays(-30),
            false);
        _apiKeys[inactiveKey.Id] = inactiveKey;
    }

    public Task<OneOf<ApiKey, ApiKeyInvalid, ApiKeyInactive>> ValidateAsync(Guid apiKeyId)
    {
        if (!_apiKeys.TryGetValue(apiKeyId, out var apiKey))
        {
            return Task.FromResult<OneOf<ApiKey, ApiKeyInvalid, ApiKeyInactive>>(
                new ApiKeyInvalid(apiKeyId));
        }

        if (!apiKey.IsActive)
        {
            return Task.FromResult<OneOf<ApiKey, ApiKeyInvalid, ApiKeyInactive>>(
                new ApiKeyInactive(apiKeyId));
        }

        return Task.FromResult<OneOf<ApiKey, ApiKeyInvalid, ApiKeyInactive>>(apiKey);
    }
}

