        _memberships.Add(new ProjectMembership(adminProjectId, "test@example.com", ProjectRole.Viewer));
        _memberships.Add(new ProjectMembership(adminProjectId, "admin@example.com", ProjectRole.Admin));
    }

    public Task<OneOf<ProjectMembership, MembershipNotFound>> GetMembershipAsync(Guid projectId, string email)
    {
        var membership = _memberships.FirstOrDefault(m => m.ProjectId == projectId && m.UserEmail == email);
        if (membership == null)
        {
            return Task.FromResult<OneOf<ProjectMembership, MembershipNotFound>>(
                new MembershipNotFound(projectId, email));
        }
        return Task.FromResult<OneOf<ProjectMembership, MembershipNotFound>>(membership);
    }

    public Task<OneOf<bool, ProjectNotFound>> HasPermissionAsync(Guid projectId, string email, ProjectRole requiredRole)
    {
        if (!_projects.ContainsKey(projectId))
        {
            return Task.FromResult<OneOf<bool, ProjectNotFound>>(new ProjectNotFound(projectId));
