        var membership = _memberships.FirstOrDefault(m => m.ProjectId == projectId && m.UserEmail == email);
        if (membership == null)
        {
            return Task.FromResult<OneOf<bool, ProjectNotFound>>(false);
        }

        var hasPermission = membership.Role >= requiredRole;
        return Task.FromResult<OneOf<bool, ProjectNotFound>>(hasPermission);
    }
}

