// Repository Interface
public interface ITicketRepository
{
    Task<OneOf<Ticket, Error>> AddAsync(Ticket ticket);
    Task<OneOf<Ticket, NotFoundResult, Error>> GetByIdAsync(Guid id);
    Task<OneOf<IEnumerable<Ticket>, Error>> GetAllAsync();
    Task<OneOf<Ticket, NotFoundResult, Error>> UpdateAsync(Ticket ticket);
    Task<OneOf<bool, NotFoundResult, Error>> DeleteAsync(Guid id);
}

// In-Memory Repository Implementation
public class InMemoryTicketRepository : ITicketRepository
{
    private readonly Dictionary<Guid, Ticket> _tickets = new();

    public async Task<OneOf<Ticket, Error>> AddAsync(Ticket ticket)
    {
        await Task.CompletedTask;
        try
        {
            _tickets[ticket.Id] = ticket;
            return ticket;
        }
        catch (Exception ex)
        {
            return new Error($"Failed to create ticket: {ex.Message}");
        }
    }

    public async Task<OneOf<Ticket, NotFoundResult, Error>> GetByIdAsync(Guid id)
    {
        await Task.CompletedTask;
        try
        {
            if (_tickets.TryGetValue(id, out var ticket))
                return ticket;
            return new NotFoundResult(id);
        }
        catch (Exception ex)
        {
            return new Error($"Failed to retrieve ticket: {ex.Message}");
        }
    }

    public async Task<OneOf<IEnumerable<Ticket>, Error>> GetAllAsync()
    {
        await Task.CompletedTask;
        try
        {
            return _tickets.Values.AsEnumerable();
        }
        catch (Exception ex)
        {
            return new Error($"Failed to retrieve tickets: {ex.Message}");
        }
    }

    public async Task<OneOf<Ticket, NotFoundResult, Error>> UpdateAsync(Ticket ticket)
    {
        await Task.CompletedTask;
        try
        {
            if (!_tickets.ContainsKey(ticket.Id))
                return new NotFoundResult(ticket.Id);

            _tickets[ticket.Id] = ticket;
            return ticket;
        }
        catch (Exception ex)
        {
            return new Error($"Failed to update ticket: {ex.Message}");
        }
    }

    public async Task<OneOf<bool, NotFoundResult, Error>> DeleteAsync(Guid id)
    {
        await Task.CompletedTask;
        try
        {
            if (!_tickets.ContainsKey(id))
                return new NotFoundResult(id);

            _tickets.Remove(id);
            return true;
        }
        catch (Exception ex)
        {
            return new Error($"Failed to delete ticket: {ex.Message}");
        }
    }
}

