    public async Task<OneOf<Ticket, ValidationError, Error>> CreateAsync(CreateTicketRequest request)
    {
        var errors = new List<string>();

        if (string.IsNullOrWhiteSpace(request.Subject))
            errors.Add("Subject is required");

        if (string.IsNullOrWhiteSpace(request.Description))
            errors.Add("Description is required");

        if (string.IsNullOrWhiteSpace(request.CustomerEmail))
            errors.Add("Customer email is required");
        else if (!request.CustomerEmail.Contains('@'))
            errors.Add("Invalid email format");

        if (errors.Count > 0)
            return new ValidationError("Validation failed", errors.ToArray());

        var ticket = new Ticket(
            Id: Guid.NewGuid(),
            Subject: request.Subject.Trim(),
            Description: request.Description.Trim(),
            CustomerEmail: request.CustomerEmail.Trim(),
            Priority: request.Priority,
            Status: TicketStatus.Open,
            CreatedAt: DateTime.UtcNow,
            UpdatedAt: null
        );

        return await _repository.AddAsync(ticket);
    }

    public async Task<OneOf<Ticket, NotFoundResult, Error>> GetByIdAsync(Guid id)
    {
        return await _repository.GetByIdAsync(id);
    }

    public async Task<OneOf<IEnumerable<Ticket>, Error>> GetAllAsync()
    {
        return await _repository.GetAllAsync();
    }

    public async Task<OneOf<Ticket, NotFoundResult, ValidationError, Error>> UpdateStatusAsync(Guid id, TicketStatus newStatus)
    {
        var result = await _repository.GetByIdAsync(id);

        return await result.Match<Task<OneOf<Ticket, NotFoundResult, ValidationError, Error>>>(
            async ticket =>
            {
                var errors = new List<string>();

                if (ticket.Status == TicketStatus.Closed)
                    errors.Add("Cannot update a closed ticket");

                if (ticket.Status == TicketStatus.Resolved && newStatus != TicketStatus.Closed)
                    errors.Add("Resolved tickets can only be closed");

                if (newStatus == TicketStatus.Open && ticket.Status != TicketStatus.Open)
                    errors.Add("Cannot reopen tickets");

                if (errors.Count > 0)
                    return new ValidationError("Validation failed", errors.ToArray());

                var updatedTicket = ticket with
                {
                    Status = newStatus,
                    UpdatedAt = DateTime.UtcNow
                };

                var updateResult = await _repository.UpdateAsync(updatedTicket);
                return updateResult.Match<OneOf<Ticket, NotFoundResult, ValidationError, Error>>(
                    t => t,
                    nf => nf,
                    err => err
                );
            },
            async notFound => await Task.FromResult<OneOf<Ticket, NotFoundResult, ValidationError, Error>>(notFound)),
            async error => await Task.FromResult<OneOf<Ticket, NotFoundResult, ValidationError, Error>>(error)
        );
    }

    public async Task<OneOf<bool, NotFoundResult, Error>> DeleteAsync(Guid id)
    {
        return await _repository.DeleteAsync(id);
    }
}

