public record UpdateLikesRequest
{
    [Range(0, int.MaxValue)]
    public int LikeCount { get; init; }
}

// OneOf Result Types
public readonly struct NotFound { }
public readonly struct ValidationError 
{ 
    public string[] Errors { get; init; } 
}
public readonly struct DuplicatePost 
{ 
    public Guid ExistingId { get; init; } 
}

// Service Interface
public interface IPostService
{
    Task<OneOf<SocialMediaPost, NotFound>> GetByIdAsync(Guid id);
    Task<OneOf<List<SocialMediaPost>, ValidationError>> GetByPlatformAsync(string platform);
    Task<OneOf<SocialMediaPost, ValidationError, DuplicatePost>> CreateAsync(CreatePostRequest request);
    Task<OneOf<SocialMediaPost, NotFound>> UpdateLikesAsync(Guid id, int likeCount);
    Task<OneOf<bool, NotFound>> DeleteAsync(Guid id);
    Task<List<SocialMediaPost>> GetAllAsync();
    Task<List<SocialMediaPost>> GetByTagAsync(string tag);
    Task<OneOf<SocialMediaPost, NotFound>> UpdateSharesAsync(Guid id, int shareCount);
}

// Service Implementation
public class PostService : IPostService
{
    private readonly Dictionary<Guid, SocialMediaPost> _posts = new();

    public Task<OneOf<SocialMediaPost, NotFound>> GetByIdAsync(Guid id)
    {
        if (_posts.TryGetValue(id, out var post))
        {
            return Task.FromResult<OneOf<SocialMediaPost, NotFound>>(post);
        }
        return Task.FromResult<OneOf<SocialMediaPost, NotFound>>(new NotFound());
    }

    public Task<OneOf<List<SocialMediaPost>, ValidationError>> GetByPlatformAsync(string platform)
    {
        if (string.IsNullOrWhiteSpace(platform))
        {
            return Task.FromResult<OneOf<List<SocialMediaPost>, ValidationError>>(
                new ValidationError { Errors = new[] { "Platform is required" } });
        }

        var posts = _posts.Values
            .Where(p => p.Platform.Equals(platform, StringComparison.OrdinalIgnoreCase))
            .ToList();

        return Task.FromResult<OneOf<List<SocialMediaPost>, ValidationError>>(posts);
    }

    public Task<OneOf<SocialMediaPost, ValidationError, DuplicatePost>> CreateAsync(CreatePostRequest request)
    {
        var errors = new List<string>();

        if (string.IsNullOrWhiteSpace(request.Platform))
            errors.Add("Platform is required");
        if (string.IsNullOrWhiteSpace(request.Author))
            errors.Add("Author is required");
        if (string.IsNullOrWhiteSpace(request.Content))
            errors.Add("Content is required");
        else if (request.Content.Length > 500)
            errors.Add("Content must be 500 characters or less");
        if (request.LikeCount < 0)
            errors.Add("LikeCount must be >= 0");
        if (request.ShareCount < 0)
            errors.Add("ShareCount must be >= 0");

        if (errors.Any())
        {
            return Task.FromResult<OneOf<SocialMediaPost, ValidationError, DuplicatePost>>(
                new ValidationError { Errors = errors.ToArray() });
        }

        var duplicate = _posts.Values.FirstOrDefault(p => 
            p.Platform.Equals(request.Platform, StringComparison.OrdinalIgnoreCase) &&
            p.Author.Equals(request.Author, StringComparison.OrdinalIgnoreCase) &&
            p.Content == request.Content);

        if (duplicate != null)
        {
            return Task.FromResult<OneOf<SocialMediaPost, ValidationError, DuplicatePost>>(
                new DuplicatePost { ExistingId = duplicate.Id });
        }

        var post = new SocialMediaPost
        {
            Id = Guid.NewGuid(),
            Platform = request.Platform,
            Author = request.Author,
            Content = request.Content,
            PostedAt = DateTimeOffset.UtcNow,
            LikeCount = request.LikeCount,
            ShareCount = request.ShareCount,
            Tags = request.Tags
        };

        _posts[post.Id] = post;

        return Task.FromResult<OneOf<SocialMediaPost, ValidationError, DuplicatePost>>(post);
    }

    public Task<OneOf<SocialMediaPost, NotFound>> UpdateLikesAsync(Guid id, int likeCount)
    {
        if (!_posts.TryGetValue(id, out var existing))
        {
            return Task.FromResult<OneOf<SocialMediaPost, NotFound>>(new NotFound());
        }

        var updated = existing with { LikeCount = likeCount };
        _posts[id] = updated;

        return Task.FromResult<OneOf<SocialMediaPost, NotFound>>(updated);
    }

    public Task<OneOf<SocialMediaPost, NotFound>> UpdateSharesAsync(Guid id, int shareCount)
    {
        if (!_posts.TryGetValue(id, out var existing))
        {
            return Task.FromResult<OneOf<SocialMediaPost, NotFound>>(new NotFound());
        }

        var updated = existing with { ShareCount = shareCount };
        _posts[id] = updated;

        return Task.FromResult<OneOf<SocialMediaPost, NotFound>>(updated);
    }

    public Task<OneOf<bool, NotFound>> DeleteAsync(Guid id)
    {
        if (!_posts.ContainsKey(id))
        {
            return Task.FromResult<OneOf<bool, NotFound>>(new NotFound());
        }

        _posts.Remove(id);
        return Task.FromResult<OneOf<bool, NotFound>>(true);
    }

    public Task<List<SocialMediaPost>> GetAllAsync()
    {
        return Task.FromResult(_posts.Values.ToList());
    }

    public Task<List<SocialMediaPost>> GetByTagAsync(string tag)
    {
        var posts = _posts.Values
            .Where(p => p.Tags.Any(t => t.Equals(tag, StringComparison.OrdinalIgnoreCase)))
            .ToList();

        return Task.FromResult(posts);
    }
}

