using System.ComponentModel.DataAnnotations;
using Microsoft.AspNetCore.Mvc;
using OneOf;

// Domain Models
public record VehicleId(Guid Value);

public record Vehicle(
    VehicleId Id,
    string Make,
    string Model,
    int Year,
    string LicensePlate,
    VehicleStatus Status,
    decimal Mileage,
    DateTimeOffset CreatedAt
);

public record CreateVehicleRequest(
    [Required(ErrorMessage = "Make is required")]
    [StringLength(50, MinimumLength = 1)]
    string Make,

    [Required(ErrorMessage = "Model is required")]
    [StringLength(50, MinimumLength = 1)]
    string Model,

    [Range(1900, 2100, ErrorMessage = "Year must be between 1900 and 2100")]
    int Year,

    [Required(ErrorMessage = "License plate is required")]
    [RegularExpression(@"^[A-Z0-9\-]+$", ErrorMessage = "License plate must contain only uppercase letters, numbers, and hyphens")]
    string LicensePlate,

    VehicleStatus Status = VehicleStatus.Active,

    [Range(0, double.MaxValue, ErrorMessage = "Mileage cannot be negative")]
    decimal Mileage = 0
);

public record UpdateVehicleRequest(
    [StringLength(50, MinimumLength = 1)]
    string? Make,

    [StringLength(50, MinimumLength = 1)]
    string? Model,

    [Range(1900, 2100)]
    int? Year,

    [RegularExpression(@"^[A-Z0-9\-]+$")]
    string? LicensePlate,

    VehicleStatus? Status,

    [Range(0, double.MaxValue)]
    decimal? Mileage
);

public enum VehicleStatus
{
    Active = 0,
    InMaintenance = 1,
    Retired = 2
}

// OneOf Result Types
public record VehicleNotFound(VehicleId Id);

public record DuplicateLicensePlate(string LicensePlate);

public record ValidationError(Dictionary<string, string[]> Errors);

// Service Interface
public interface IVehicleService
{
    OneOf<Vehicle, VehicleNotFound> GetById(VehicleId id);
    IEnumerable<Vehicle> GetAll(VehicleStatus? status = null);
    OneOf<Vehicle, DuplicateLicensePlate> Create(CreateVehicleRequest request);
    OneOf<Vehicle, VehicleNotFound, DuplicateLicensePlate> Update(VehicleId id, UpdateVehicleRequest request);
    OneOf<bool, VehicleNotFound> Delete(VehicleId id);
}

// Service Implementation
public class VehicleService : IVehicleService
{
    private readonly Dictionary<VehicleId, Vehicle> _vehicles = new();
    private readonly object _lock = new();

    public OneOf<Vehicle, VehicleNotFound> GetById(VehicleId id)
    {
        lock (_lock)
        {
            return _vehicles.TryGetValue(id, out var vehicle)
                ? vehicle
                : new VehicleNotFound(id);
        }
    }

    public IEnumerable<Vehicle> GetAll(VehicleStatus? status = null)
    {
        lock (_lock)
        {
            var query = _vehicles.Values.AsEnumerable();
            if (status.HasValue)
                query = query.Where(v => v.Status == status.Value);
            return query.OrderBy(v => v.CreatedAt).ToList();
        }
    }

    public OneOf<Vehicle, DuplicateLicensePlate> Create(CreateVehicleRequest request)
    {
        lock (_lock)
        {
            var normalizedPlate = request.LicensePlate.ToUpperInvariant();
            if (_vehicles.Values.Any(v => v.LicensePlate.Equals(normalizedPlate, StringComparison.OrdinalIgnoreCase)))
                return new DuplicateLicensePlate(request.LicensePlate);

            var vehicle = new Vehicle(
                Id: new VehicleId(Guid.NewGuid()),
                Make: request.Make,
                Model: request.Model,
                Year: request.Year,
                LicensePlate: normalizedPlate,
                Status: request.Status,
                Mileage: request.Mileage,
                CreatedAt: DateTimeOffset.UtcNow
            );

            _vehicles[vehicle.Id] = vehicle;
            return vehicle;
        }
    }

    public OneOf<Vehicle, VehicleNotFound, DuplicateLicensePlate> Update(VehicleId id, UpdateVehicleRequest request)
    {
        lock (_lock)
        {
            if (!_vehicles.TryGetValue(id, out var existing))
                return new VehicleNotFound(id);

            if (request.LicensePlate is not null)
            {
                var normalizedPlate = request.LicensePlate.ToUpperInvariant();
                if (_vehicles.Values.Any(v => v.Id != id && v.LicensePlate.Equals(normalizedPlate, StringComparison.OrdinalIgnoreCase)))
                    return new DuplicateLicensePlate(request.LicensePlate);
            }

            var updated = existing with
            {
                Make = request.Make ?? existing.Make,
                Model = request.Model ?? existing.Model,
                Year = request.Year ?? existing.Year,
                LicensePlate = request.LicensePlate?.ToUpperInvariant() ?? existing.LicensePlate,
                Status = request.Status ?? existing.Status,
                Mileage = request.Mileage ?? existing.Mileage
            };

            _vehicles[id] = updated;
            return updated;
        }
    }

    public OneOf<bool, VehicleNotFound> Delete(VehicleId id)
    {
        lock (_lock)
        {
            if (!_vehicles.ContainsKey(id))
                return new VehicleNotFound(id);

            _vehicles.Remove(id);
            return true;
        }
    }
}

// Controller
[ApiController]
[Route("api/[controller]")]
public class VehiclesController : ControllerBase
{
    private readonly IVehicleService _vehicleService;

    public VehiclesController(IVehicleService vehicleService)
    {
        _vehicleService = vehicleService;
    }

    [HttpGet("{id:guid}")]
    [ProducesResponseType(typeof(Vehicle), StatusCodes.Status200OK)]
    [ProducesResponseType(StatusCodes.Status404NotFound)]
    public IActionResult GetById(Guid id)
    {
        var vehicleId = new VehicleId(id);
        var result = _vehicleService.GetById(vehicleId);

        return result.Match<IActionResult>(
            vehicle => Ok(vehicle),
            notFound => NotFound(new ProblemDetails
            {
                Title = "Vehicle Not Found",
                Status = StatusCodes.Status404NotFound,
                Detail = $"Vehicle with ID {notFound.Id.Value} was not found."
            })
        );
    }

    [HttpGet]
    [ProducesResponseType(typeof(IEnumerable<Vehicle>), StatusCodes.Status200OK)]
    public IActionResult GetAll([FromQuery] VehicleStatus? status)
    {
        var vehicles = _vehicleService.GetAll(status);
        return Ok(vehicles);
    }

    [HttpPost]
    [ProducesResponseType(typeof(Vehicle), StatusCodes.Status201Created)]
    [ProducesResponseType(StatusCodes.Status400BadRequest)]
    [ProducesResponseType(StatusCodes.Status409Conflict)]
    public IActionResult Create([FromBody] CreateVehicleRequest request)
    {
        if (!ModelState.IsValid)
            return BadRequest(ModelState);

        var result = _vehicleService.Create(request);

        return result.Match<IActionResult>(
            vehicle => CreatedAtAction(
                nameof(GetById),
                new { id = vehicle.Id.Value },
                vehicle
            ),
            duplicate => Conflict(new ProblemDetails
            {
                Title = "Duplicate License Plate",
                Status = StatusCodes.Status409Conflict,
                Detail = $"A vehicle with license plate '{duplicate.LicensePlate}' already exists."
            })
        );
    }

    [HttpPut("{id:guid}")]
    [ProducesResponseType(typeof(Vehicle), StatusCodes.Status200OK)]
    [ProducesResponseType(StatusCodes.Status404NotFound)]
    [ProducesResponseType(StatusCodes.Status409Conflict)]
    public IActionResult Update(Guid id, [FromBody] UpdateVehicleRequest request)
    {
        if (!ModelState.IsValid)
            return BadRequest(ModelState);

        var vehicleId = new VehicleId(id);
        var result = _vehicleService.Update(vehicleId, request);

        return result.Match<IActionResult>(
            vehicle => Ok(vehicle),
            notFound => NotFound(new ProblemDetails
            {
                Title = "Vehicle Not Found",
                Status = StatusCodes.Status404NotFound,
                Detail = $"Vehicle with ID {notFound.Id.Value} was not found."
            }),
            duplicate => Conflict(new ProblemDetails
            {
                Title = "Duplicate License Plate",
                Status = StatusCodes.Status409Conflict,
                Detail = $"A vehicle with license plate '{duplicate.LicensePlate}' already exists."
            })
        );
    }

    [HttpDelete("{id:guid}")]
    [ProducesResponseType(StatusCodes.Status204NoContent)]
    [ProducesResponseType(StatusCodes.Status404NotFound)]
    public IActionResult Delete(Guid id)
    {
        var vehicleId = new VehicleId(id);
        var result = _vehicleService.Delete(vehicleId);

        return result.Match<IActionResult>(
            _ => NoContent(),
            notFound => NotFound(new ProblemDetails
            {
                Title = "Vehicle Not Found",
                Status = StatusCodes.Status404NotFound,
                Detail = $"Vehicle with ID {notFound.Id.Value} was not found."
            })
        );
    }
}

