// Service Interface
public interface IVehicleService
{
    Task<OneOf<Vehicle, ValidationError>> CreateAsync(CreateVehicleRequest request);
    Task<OneOf<Vehicle, NotFoundError>> GetByIdAsync(Guid id);
    Task<OneOf<List<Vehicle>, None>> GetAllAsync();
    Task<OneOf<Vehicle, NotFoundError, ValidationError>> UpdateAsync(Guid id, UpdateVehicleRequest request);
    Task<OneOf<bool, NotFoundError>> DeleteAsync(Guid id);
}

// Service Implementation
public class VehicleService : IVehicleService
{
    private readonly Dictionary<Guid, Vehicle> _vehicles = new();

    public async Task<OneOf<Vehicle, ValidationError>> CreateAsync(CreateVehicleRequest request)
    {
        var vehicle = new Vehicle(
            Guid.NewGuid(),
            request.Make,
            request.Model,
            request.Year,
            request.LicensePlate.ToUpper(),
            request.Type,
            request.Status,
            request.Mileage,
            DateTime.UtcNow
        );

        if (_vehicles.Values.Any(v => v.LicensePlate.Equals(vehicle.LicensePlate, StringComparison.OrdinalIgnoreCase)))
        {
            return new ValidationError(new Dictionary<string, string[]>
            {
                [nameof(request.LicensePlate)] = new[] { "License plate already exists" }
            });
        }

        _vehicles[vehicle.Id] = vehicle;
        return vehicle;
    }

    public async Task<OneOf<Vehicle, NotFoundError>> GetByIdAsync(Guid id)
    {
        if (_vehicles.TryGetValue(id, out var vehicle))
            return vehicle;
        return new NotFoundError(id);
    }

    public async Task<OneOf<List<Vehicle>, None>> GetAllAsync()
    {
        return _vehicles.Values.ToList();
    }

    public async Task<OneOf<Vehicle, NotFoundError, ValidationError>> UpdateAsync(Guid id, UpdateVehicleRequest request)
    {
        if (!_vehicles.TryGetValue(id, out var existing))
            return new NotFoundError(id);

        var updated = existing with
        {
            Make = request.Make ?? existing.Make,
            Model = request.Model ?? existing.Model,
            Year = request.Year ?? existing.Year,
            LicensePlate = request.LicensePlate?.ToUpper() ?? existing.LicensePlate,
            Type = request.Type ?? existing.Type,
            Status = request.Status ?? existing.Status,
            Mileage = request.Mileage ?? existing.Mileage
        };

        if (request.LicensePlate != null && 
            _vehicles.Values.Any(v => v.Id != id && v.LicensePlate.Equals(request.LicensePlate, StringComparison.OrdinalIgnoreCase)))
        {
            return new ValidationError(new Dictionary<string, string[]>
            {
                [nameof(request.LicensePlate)] = new[] { "License plate already exists" }
            });
        }

        _vehicles[id] = updated;
        return updated;
    }

    public async Task<OneOf<bool, NotFoundError>> DeleteAsync(Guid id)
    {
        if (!_vehicles.ContainsKey(id))
            return new NotFoundError(id);

        _vehicles.Remove(id);
        return true;
    }
}

