// Domain Models
public record Claim(
    Guid Id,
    string ClaimNumber,
    string PolicyNumber,
    Guid ClaimantId,
    string ClaimantName,
    ClaimType Type,
    ClaimStatus Status,
    decimal ClaimedAmount,
    decimal? ApprovedAmount,
    DateTimeOffset DateFiled,
    DateTimeOffset? DateResolved,
    string Description
);

// DTOs
public record ClaimCreateRequest(
    [Required] string PolicyNumber,
    [Required] Guid ClaimantId,
    [Required] string ClaimantName,
    [Required] ClaimType Type,
    [Required][Range(0.01, 10_000_000)] decimal ClaimedAmount,
    [Required][StringLength(2000)] string Description
);

public record ClaimUpdateRequest(
    ClaimStatus? Status,
    [Range(0, 10_000_000)] decimal? ApprovedAmount,
