}

public record PaginationParameters
{
    private int _pageNumber = 1;
    private int _pageSize = 10;

    public int PageNumber
    {
        get => _pageNumber;
        init => _pageNumber = value < 1 ? 1 : value;
    }

    public int PageSize
    {
        get => _pageSize;
        init => _pageSize = value < 1 ? 10 : value > 100 ? 100 : value;
    }

    public string? SortBy { get; init; }
    public string? SortOrder { get; init; }
}

public record PagedResult<T>(
    IReadOnlyList<T> Items,
    int TotalCount,
    int PageNumber,
    int PageSize,
    int TotalPages
);

// OneOf Result Types
public readonly struct ClaimNotFound { public Guid Id { get; init; } }
public readonly struct ValidationError { public Dictionary<string, string[]> Errors { get; init; } }
public readonly struct DuplicateClaimNumber { public string ClaimNumber { get; init; } }

// Service Interface
public interface IClaimService
{
    Task<OneOf<Claim, ValidationError>> CreateClaimAsync(ClaimCreateRequest request);
    Task<OneOf<Claim, ClaimNotFound>> GetClaimByIdAsync(Guid id);
    Task<OneOf<Claim, ClaimNotFound, ValidationError>> UpdateClaimAsync(Guid id, ClaimUpdateRequest request);
    Task<OneOf<bool, ClaimNotFound>> DeleteClaimAsync(Guid id);
    Task<PagedResult<Claim>> GetClaimsAsync(ClaimsQueryParameters parameters);
}

// Service Implementation
public class ClaimService : IClaimService
{
    private readonly Dictionary<Guid, Claim> _claims = new();
    private int _claimCounter = 1;

    public Task<OneOf<Claim, ValidationError>> CreateClaimAsync(ClaimCreateRequest request)
    {
        var claimNumber = $"CLM-{DateTimeOffset.UtcNow.Year}-{_claimCounter:D6}";
        _claimCounter++;

        var claim = new Claim(
            Id: Guid.NewGuid(),
            ClaimNumber: claimNumber,
            PolicyNumber: request.PolicyNumber,
            ClaimantId: request.ClaimantId,
            ClaimantName: request.ClaimantName,
            Type: request.Type,
            Status: ClaimStatus.Filed,
            ClaimedAmount: request.ClaimedAmount,
            ApprovedAmount: null,
            DateFiled: DateTimeOffset.UtcNow,
            DateResolved: null,
            Description: request.Description
        );

        _claims[claim.Id] = claim;
        return Task.FromResult<OneOf<Claim, ValidationError>>(claim);
    }

    public Task<OneOf<Claim, ClaimNotFound>> GetClaimByIdAsync(Guid id)
    {
        if (_claims.TryGetValue(id, out var claim))
            return Task.FromResult<OneOf<Claim, ClaimNotFound>>(claim);

        return Task.FromResult<OneOf<Claim, ClaimNotFound>>(new ClaimNotFound { Id = id });
    }

    public Task<OneOf<Claim, ClaimNotFound, ValidationError>> UpdateClaimAsync(Guid id, ClaimUpdateRequest request)
    {
        if (!_claims.TryGetValue(id, out var existingClaim))
            return Task.FromResult<OneOf<Claim, ClaimNotFound, ValidationError>>(new ClaimNotFound { Id = id });

        var errors = new Dictionary<string, List<string>>();

        if (request.Status == ClaimStatus.Approved && request.ApprovedAmount == null)
            errors.Add(nameof(request.ApprovedAmount), new List<string> { "ApprovedAmount is required when status is Approved" });

        if (request.ApprovedAmount > existingClaim.ClaimedAmount)
            errors.Add(nameof(request.ApprovedAmount), new List<string> { "ApprovedAmount cannot exceed ClaimedAmount" });

        if (errors.Count > 0)
        {
            return Task.FromResult<OneOf<Claim, ClaimNotFound, ValidationError>>(
                new ValidationError { Errors = errors.ToDictionary(k => k.Key, v => v.Value.ToArray()) });
        }

        var updatedClaim = existingClaim with
        {
            Status = request.Status ?? existingClaim.Status,
            ApprovedAmount = request.ApprovedAmount ?? existingClaim.ApprovedAmount,
            DateResolved = request.Status == ClaimStatus.Paid ? DateTimeOffset.UtcNow : existingClaim.DateResolved
        };

        _claims[id] = updatedClaim;
        return Task.FromResult<OneOf<Claim, ClaimNotFound, ValidationError>>(updatedClaim);
    }

    public Task<OneOf<bool, ClaimNotFound>> DeleteClaimAsync(Guid id)
    {
        if (!_claims.ContainsKey(id))
            return Task.FromResult<OneOf<bool, ClaimNotFound>>(new ClaimNotFound { Id = id });

        _claims.Remove(id);
        return Task.FromResult<OneOf<bool, ClaimNotFound>>(true);
    }

    public Task<PagedResult<Claim>> GetClaimsAsync(ClaimsQueryParameters parameters)
    {
        var query = _claims.Values.AsQueryable();

        if (parameters.Status.HasValue)
            query = query.Where(c => c.Status == parameters.Status);

        if (parameters.Type.HasValue)
            query = query.Where(c => c.Type == parameters.Type);

        if (!string.IsNullOrEmpty(parameters.PolicyNumber))
            query = query.Where(c => c.PolicyNumber.Contains(parameters.PolicyNumber));

        if (parameters.ClaimantId.HasValue)
            query = query.Where(c => c.ClaimantId == parameters.ClaimantId);

        if (parameters.MinAmount.HasValue)
            query = query.Where(c => c.ClaimedAmount >= parameters.MinAmount);

        if (parameters.MaxAmount.HasValue)
            query = query.Where(c => c.ClaimedAmount <= parameters.MaxAmount);

        if (parameters.FromDate.HasValue)
            query = query.Where(c => c.DateFiled >= parameters.FromDate);

        if (parameters.ToDate.HasValue)
            query = query.Where(c => c.DateFiled <= parameters.ToDate);

        if (!string.IsNullOrEmpty(parameters.SearchTerm))
            query = query.Where(c => 
                c.ClaimantName.Contains(parameters.SearchTerm) || 
                c.ClaimNumber.Contains(parameters.SearchTerm) ||
                c.Description.Contains(parameters.SearchTerm));

        query = ApplySorting(query, parameters.SortBy, parameters.SortOrder);

        var totalCount = query.Count();
        var totalPages = (int)Math.Ceiling(totalCount / (double)parameters.PageSize);

        var items = query
            .Skip((parameters.PageNumber - 1) * parameters.PageSize)
            .Take(parameters.PageSize)
            .ToList();

        return Task.FromResult(new PagedResult<Claim>(items, totalCount, parameters.PageNumber, parameters.PageSize, totalPages));
    }

    private static IQueryable<Claim> ApplySorting(IQueryable<Claim> query, string? sortBy, string? sortOrder)
    {
        var isDescending = string.Equals(sortOrder, "desc", StringComparison.OrdinalIgnoreCase);

        return sortBy?.ToLowerInvariant() switch
        {
            "claimnumber" => isDescending ? query.OrderByDescending(c => c.ClaimNumber) : query.OrderBy(c => c.ClaimNumber),
            "claimantname" => isDescending ? query.OrderByDescending(c => c.ClaimantName) : query.OrderBy(c => c.ClaimantName),
            "claimedamount" => isDescending ? query.OrderByDescending(c => c.ClaimedAmount) : query.OrderBy(c => c.ClaimedAmount),
            "datefiled" => isDescending ? query.OrderByDescending(c => c.DateFiled) : query.OrderBy(c => c.DateFiled),
            "status" => isDescending ? query.OrderByDescending(c => c.Status) : query.OrderBy(c => c.Status),
            "type" => isDescending ? query.OrderByDescending(c => c.Type) : query.OrderBy(c => c.Type),
            _ => query.OrderBy(c => c.DateFiled)
        };
    }
}

