}

// Command Record
public record ProcessInsuranceClaimCommand(
    Guid ClaimId,
    string PolicyNumber,
    ClaimType ClaimType,
    decimal ClaimAmount,
    DateTime IncidentDate,
    string ClaimantName,
    string ClaimantEmail,
    string Description,
    IReadOnlyList<Guid> SupportingDocumentIds
);

// Result Types
public record ClaimProcessed(Guid ClaimId, string PolicyNumber, decimal ApprovedAmount, DateTime ProcessedAt);
public record ClaimRejected(Guid ClaimId, string Reason);
public record ClaimPendingReview(Guid ClaimId, string Reason, decimal EstimatedAmount);

// FluentValidator
public class ProcessInsuranceClaimCommandValidator : AbstractValidator<ProcessInsuranceClaimCommand>
{
    public ProcessInsuranceClaimCommandValidator()
    {
        RuleFor(x => x.PolicyNumber)
            .NotEmpty().WithMessage("Policy number is required")
            .Matches(@"^POL-\d{6}$").WithMessage("Policy number must match format POL-XXXXXX (e.g., POL-123456)");

        RuleFor(x => x.ClaimType)
            .IsInEnum().WithMessage("Invalid claim type");

        RuleFor(x => x.ClaimAmount)
            .GreaterThan(0).WithMessage("Claim amount must be greater than zero")
            .LessThanOrEqualTo(1_000_000).WithMessage("Claim amount cannot exceed $1,000,000");

        RuleFor(x => x.IncidentDate)
            .NotEmpty().WithMessage("Incident date is required")
            .LessThanOrEqualTo(DateTime.UtcNow).WithMessage("Incident date cannot be in the future")
            .GreaterThanOrEqualTo(DateTime.UtcNow.AddYears(-5)).WithMessage("Incident date cannot be more than 5 years old");

        RuleFor(x => x.ClaimantName)
            .NotEmpty().WithMessage("Claimant name is required")
            .MaximumLength(200).WithMessage("Claimant name cannot exceed 200 characters");

        RuleFor(x => x.ClaimantEmail)
            .NotEmpty().WithMessage("Claimant email is required")
            .EmailAddress().WithMessage("Invalid email format");

        RuleFor(x => x.Description)
            .NotEmpty().WithMessage("Description is required")
            .MinimumLength(50).WithMessage("Description must be at least 50 characters")
            .MaximumLength(5000).WithMessage("Description cannot exceed 5000 characters");

        RuleFor(x => x.SupportingDocumentIds)
            .NotNull().WithMessage("Supporting documents are required")
            .Must(docs => docs!.Count >= 1).WithMessage("At least one supporting document is required")
            .Must(docs => docs!.All(id => id != Guid.Empty)).WithMessage("All document IDs must be valid GUIDs");
    }
}

// Service Interface and Implementation
public interface IInsuranceClaimService
{
    Task<OneOf<ClaimProcessed, ClaimRejected, ClaimPendingReview>> ProcessClaimAsync(ProcessInsuranceClaimCommand command);
}

public class InsuranceClaimService : IInsuranceClaimService
{
    public async Task<OneOf<ClaimProcessed, ClaimRejected, ClaimPendingReview>> ProcessClaimAsync(ProcessInsuranceClaimCommand command)
    {
        await Task.Delay(50);

        if (command.ClaimAmount <= 5000)
        {
            return new ClaimProcessed(command.ClaimId, command.PolicyNumber, command.ClaimAmount, DateTime.UtcNow);
        }

        if (command.ClaimAmount > 500000)
        {
            return new ClaimRejected(command.ClaimId, "Claim amount exceeds automatic approval threshold. Manual underwriting required.");
        }

        return new ClaimPendingReview(command.ClaimId, "Claim requires manual review due to amount threshold.", command.ClaimAmount);
    }
}

