// Models
public record Hotel(int Id, string Name, string Location, int TotalRooms);
public record Room(int Id, int HotelId, string RoomNumber, decimal PricePerNight, bool IsAvailable);
public record Booking(int Id, int HotelId, int RoomId, string GuestName, DateTime CheckIn, DateTime CheckOut, decimal TotalPrice);
public record CreateBookingRequest(int HotelId, int RoomId, string GuestName, DateTime CheckIn, DateTime CheckOut);

// OneOf result types
public record BookingNotFound(int BookingId);
public record RoomNotAvailable(int RoomId, string Reason);

// Service Interface
public interface IBookingService
{
    OneOf<Booking, BookingNotFound, RoomNotAvailable> CreateBooking(CreateBookingRequest request);
    OneOf<Booking, BookingNotFound> GetBooking(int id);
    OneOf<bool, BookingNotFound> CancelBooking(int id);
}

// Service Implementation
public class BookingService : IBookingService
{
    private readonly List<Hotel> _hotels = new();
    private readonly List<Room> _rooms = new();
    private readonly List<Booking> _bookings = new();
    private int _nextBookingId = 1;

    public BookingService()
    {
        // Seed data
        _hotels.Add(new Hotel(1, "Grand Palace", "New York", 100));
        _hotels.Add(new Hotel(2, "Ocean View", "Miami", 50));

        _rooms.Add(new Room(1, 1, "101", 150.00m, true));
        _rooms.Add(new Room(2, 1, "102", 180.00m, true));
        _rooms.Add(new Room(3, 2, "201", 220.00m, false));
    }

    public OneOf<Booking, BookingNotFound, RoomNotAvailable> CreateBooking(CreateBookingRequest request)
    {
        var room = _rooms.FirstOrDefault(r => r.Id == request.RoomId && r.HotelId == request.HotelId);

        if (room == null)
        {
            return new RoomNotAvailable(request.RoomId, "Room not found in the specified hotel");
        }

        if (!room.IsAvailable)
        {
            return new RoomNotAvailable(room.Id, "Room is currently unavailable");
        }

        if (request.CheckOut <= request.CheckIn)
        {
            return new RoomNotAvailable(request.RoomId, "Check-out date must be after check-in date");
        }

        var nights = (request.CheckOut - request.CheckIn).Days;
        var totalPrice = nights * room.PricePerNight;

        var booking = new Booking(
            _nextBookingId++,
            request.HotelId,
            request.RoomId,
            request.GuestName,
            request.CheckIn,
            request.CheckOut,
            totalPrice
        );

        _bookings.Add(booking);

        // Mark room as unavailable
        var roomIndex = _rooms.FindIndex(r => r.Id == room.Id);
        _rooms[roomIndex] = room with { IsAvailable = false };

        return booking;
    }

    public OneOf<Booking, BookingNotFound> GetBooking(int id)
    {
        var booking = _bookings.FirstOrDefault(b => b.Id == id);

        if (booking == null)
        {
            return new BookingNotFound(id);
        }

        return booking;
    }

    public OneOf<bool, BookingNotFound> CancelBooking(int id)
    {
        var booking = _bookings.FirstOrDefault(b => b.Id == id);

        if (booking == null)
        {
            return new BookingNotFound(id);
        }

        _bookings.Remove(booking);

        // Mark room as available again
        var roomIndex = _rooms.FindIndex(r => r.Id == booking.RoomId);
        if (roomIndex >= 0)
        {
            _rooms[roomIndex] = _rooms[roomIndex] with { IsAvailable = true };
        }

        return true;
    }
}

