);

public class CreateBookingCommandValidator : AbstractValidator<CreateBookingCommand>
{
    public CreateBookingCommandValidator()
    {
        RuleFor(x => x.HotelId)
            .NotEmpty().WithMessage("Hotel ID is required");

        RuleFor(x => x.RoomId)
            .NotEmpty().WithMessage("Room ID is required");

        RuleFor(x => x.GuestName)
            .NotEmpty().WithMessage("Guest name is required")
            .Length(2, 100).WithMessage("Guest name must be between 2 and 100 characters");

        RuleFor(x => x.GuestEmail)
            .NotEmpty().WithMessage("Guest email is required")
            .EmailAddress().WithMessage("Invalid email format");

        RuleFor(x => x.GuestPhone)
            .NotEmpty().WithMessage("Guest phone is required")
            .Length(10, 15).WithMessage("Phone number must be between 10 and 15 characters");

        RuleFor(x => x.CheckInDate)
            .GreaterThanOrEqualTo(DateOnly.FromDateTime(DateTime.Today))
            .WithMessage("Check-in date must be today or in the future");

        RuleFor(x => x.CheckOutDate)
            .GreaterThan(x => x.CheckInDate)
            .WithMessage("Check-out date must be after check-in date");

        RuleFor(x => x.NumberOfGuests)
            .InclusiveBetween(1, 10).WithMessage("Number of guests must be between 1 and 10");

        RuleFor(x => x.SpecialRequests)
            .MaximumLength(500).WithMessage("Special requests must not exceed 500 characters")
            .When(x => x.SpecialRequests != null);
    }
}

