// Service Interface
public interface IGymMembershipService
{
    Task<OneOf<Membership, ValidationError>> CreateAsync(CreateMembershipRequest request);
    Task<OneOf<Membership, MembershipNotFound>> GetByIdAsync(int id);
    Task<IEnumerable<Membership>> GetAllAsync();
}

// Controller
[ApiController]
[Route("api/gym/memberships")]
public class GymMembershipsController : ControllerBase
{
    private readonly IGymMembershipService _service;

    public GymMembershipsController(IGymMembershipService service)
    {
        _service = service;
    }

    [HttpGet("{id:int}")]
    public async Task<IActionResult> GetMembership(int id)
    {
        var result = await _service.GetByIdAsync(id);

        return result.Match(
            membership => Results.Ok(membership),
            notFound => Results.NotFound(notFound)
        );
    }

    [HttpGet]
    public async Task<IActionResult> GetAllMemberships()
    {
        var memberships = await _service.GetAllAsync();
        return Results.Ok(memberships);
    }

    [HttpPost]
    public async Task<IActionResult> CreateMembership([FromBody] CreateMembershipRequest request)
    {
        var result = await _service.CreateAsync(request);

        return result.Match(
            membership => Results.Created($"/api/gym/memberships/{membership.Id}", membership),
            validationError => Results.BadRequest(validationError)
        );
    }
}

// Service Implementation
public class GymMembershipService : IGymMembershipService
{
    private readonly Dictionary<int, Membership> _memberships = new();
    private int _nextId = 1;

    public Task<OneOf<Membership, ValidationError>> CreateAsync(CreateMembershipRequest request)
    {
        var errors = new List<string>();

        if (string.IsNullOrWhiteSpace(request.MemberName))
            errors.Add("MemberName is required");

        if (string.IsNullOrWhiteSpace(request.Email))
            errors.Add("Email is required");

        if (string.IsNullOrWhiteSpace(request.PlanType))
            errors.Add("PlanType is required");

        if (errors.Count > 0)
            return Task.FromResult(OneOf<Membership, ValidationError>.FromT1(new ValidationError("Validation failed", errors.ToArray())));

        var membership = new Membership(
            _nextId++,
            request.MemberName,
            request.Email,
            DateTime.UtcNow,
            null,
            request.PlanType
        );

        _memberships[membership.Id] = membership;

        return Task.FromResult(OneOf<Membership, ValidationError>.FromT0(membership));
    }

    public Task<OneOf<Membership, MembershipNotFound>> GetByIdAsync(int id)
    {
        if (_memberships.TryGetValue(id, out var membership))
        {
            return Task.FromResult(OneOf<Membership, MembershipNotFound>.FromT0(membership));
        }

        return Task.FromResult(OneOf<Membership, MembershipNotFound>.FromT1(new MembershipNotFound(id)));
    }

    public Task<IEnumerable<Membership>> GetAllAsync()
    {
        return Task.FromResult(_memberships.Values.AsEnumerable());
    }
}

