public class CreateMembershipCommandValidator : AbstractValidator<CreateMembershipCommand>
{
    public CreateMembershipCommandValidator()
    {
        RuleFor(x => x.FirstName)
            .NotEmpty().WithMessage("First name is required")
            .Length(2, 50).WithMessage("First name must be between 2 and 50 characters");

        RuleFor(x => x.LastName)
            .NotEmpty().WithMessage("Last name is required")
            .Length(2, 50).WithMessage("Last name must be between 2 and 50 characters");

        RuleFor(x => x.Email)
            .NotEmpty().WithMessage("Email is required")
            .EmailAddress().WithMessage("Invalid email format");

        RuleFor(x => x.PhoneNumber)
            .NotEmpty().WithMessage("Phone number is required")
            .Matches(@"^\d{10}$").WithMessage("Phone number must be exactly 10 digits");

        RuleFor(x => x.DateOfBirth)
            .Must(BeAtLeast16YearsOld).WithMessage("Member must be at least 16 years old");

        RuleFor(x => x.MembershipType)
            .NotEmpty().WithMessage("Membership type is required")
            .Must(t => new[] { "Basic", "Premium", "Elite" }.Contains(t))
            .WithMessage("Membership type must be Basic, Premium, or Elite");

        RuleFor(x => x.DurationMonths)
            .Must(d => new[] { 1, 3, 6, 12 }.Contains(d))
            .WithMessage("Duration must be 1, 3, 6, or 12 months");
    }

    private static bool BeAtLeast16YearsOld(DateTime dateOfBirth)
    {
        var today = DateTime.Today;
        var age = today.Year - dateOfBirth.Year;
        if (dateOfBirth.Date > today.AddYears(-age)) age--;
        return age >= 16;
    }
}

public interface IMembershipService
{
    Task<OneOf<MembershipCreated, MembershipConflict, MemberCreationFailed>> CreateMembershipAsync(
        CreateMembershipCommand command,
        CancellationToken cancellationToken = default);
}

public class MembershipService : IMembershipService
{
    private static readonly HashSet<string> _existingEmails = new();

    public async Task<OneOf<MembershipCreated, MembershipConflict, MemberCreationFailed>> CreateMembershipAsync(
        CreateMembershipCommand command,
        CancellationToken cancellationToken = default)
    {
        await Task.Delay(10, cancellationToken);

        if (_existingEmails.Contains(command.Email))
        {
            return new MembershipConflict(command.Email, "A membership with this email already exists");
        }

        try
        {
            _existingEmails.Add(command.Email);

            var startDate = DateTime.Today;
            var endDate = startDate.AddMonths(command.DurationMonths);
            var id = Random.Shared.Next(1, 100000);

            return new MembershipCreated(
                id,
                command.FirstName,
                command.LastName,
                command.Email,
                command.MembershipType,
                startDate,
                endDate
            );
        }
        catch (Exception ex)
        {
            return new MemberCreationFailed($"Failed to create membership: {ex.Message}");
        }
    }
}

public static class Program
{
    public static void Main(string[] args)
    {
        var builder = WebApplication.CreateBuilder(args);

        builder.Services.AddValidatorsFromAssemblyContaining<CreateMembershipCommandValidator>();
        builder.Services.AddScoped<IMembershipService, MembershipService>();

        var app = builder.Build();

        app.UseExceptionHandler(err => err.Run(async ctx =>
        {
            ctx.Response.ContentType = "application/problem+json";
            await ctx.Response.WriteAsJsonAsync(new ProblemDetails
            {
                Title = "Server Error",
                Status = 500,
                Detail = "Unexpected error occurred"
            });
        }));

        app.MapPost("/memberships", async (
            CreateMembershipCommand command,
            IValidator<CreateMembershipCommand> validator,
            IMembershipService membershipService,
            CancellationToken cancellationToken) =>
        {
            var validationResult = await validator.ValidateAsync(command, cancellationToken);

            if (!validationResult.IsValid)
            {
                var errors = validationResult.Errors
                    .GroupBy(e => e.PropertyName)
                    .ToDictionary(
                        g => g.Key,
                        g => g.Select(e => e.ErrorMessage).ToArray()
                    );

                return Results.ValidationProblem(errors);
            }

            var result = await membershipService.CreateMembershipAsync(command, cancellationToken);

            return result.Match<IResult>(
                created => Results.Created($"/memberships/{created.Id}", created),
                conflict => Results.Conflict(new ProblemDetails
                {
                    Title = "Membership Conflict",
                    Status = 409,
                    Detail = conflict.Message,
                    Instance = $"/memberships?email={conflict.Email}"
                }),
                failed => Results.Problem(
                    detail: failed.Detail,
                    statusCode: 500,
                    title: "Membership Creation Failed"
                )
            );
        });

        app.Run();
    }
}

