// Repository Implementation
public class MemberRepository : IMemberRepository
{
    private static readonly ConcurrentDictionary<Guid, GymMember> _members = new();

    public Task<GymMember?> GetByIdAsync(Guid id)
    {
        _members.TryGetValue(id, out var member);
        return Task.FromResult(member);
    }

    public Task<GymMember?> GetByEmailAsync(string email)
    {
        var member = _members.Values.FirstOrDefault(m => 
            m.Email.Equals(email, StringComparison.OrdinalIgnoreCase));
        return Task.FromResult(member);
    }

    public Task<IEnumerable<GymMember>> GetAllAsync()
    {
        return Task.FromResult(_members.Values.AsEnumerable());
    }

    public Task<GymMember> CreateAsync(GymMember member)
    {
        var newMember = member with { Id = member.Id == Guid.Empty ? Guid.NewGuid() : member.Id };
        _members.TryAdd(newMember.Id, newMember);
        return Task.FromResult(newMember);
    }

    public Task<GymMember> UpdateAsync(GymMember member)
    {
        _members[member.Id] = member;
        return Task.FromResult(member);
    }

    public Task<bool> DeleteAsync(Guid id)
    {
        return Task.FromResult(_members.TryRemove(id, out _));
    }
}

// Authentication Middleware
public class ApiKeyAuthMiddleware
{
    private readonly RequestDelegate _next;
    private const string ApiKeyHeader = "X-Api-Key";
    private const string EmailHeader = "X-Email";
    private static readonly HashSet<string> ValidApiKeys = new() { "gym-admin-2024", "gym-trainer-2024", "gym-member-2024" };

    public ApiKeyAuthMiddleware(RequestDelegate next) => _next = next;

    public async Task InvokeAsync(HttpContext context, IMemberRepository memberRepository)
    {
        var path = context.Request.Path.Value ?? "";

        if (path.StartsWith("/health") || path.StartsWith("/swagger"))
        {
            await _next(context);
            return;
        }

        if (!context.Request.Headers.TryGetValue(ApiKeyHeader, out var apiKeyValues) ||
            !context.Request.Headers.TryGetValue(EmailHeader, out var emailValues))
        {
            await WriteProblemAsync(context, 401, "Unauthorized", "Missing API key or email header");
            return;
        }

        var apiKey = apiKeyValues.ToString();
        var email = emailValues.ToString();

        if (!IsValidApiKey(apiKey))
        {
            await WriteProblemAsync(context, 401, "Unauthorized", "Invalid API key");
            return;
        }

        var member = await memberRepository.GetByEmailAsync(email);
        var roles = DetermineRoles(email, member);

        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, email),
            new(ClaimTypes.Email, email)
        };

        foreach (var role in roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        var identity = new ClaimsIdentity(claims, "ApiKey");
        context.User = new ClaimsPrincipal(identity);

        context.Items["Member"] = member;
        context.Items["MemberRole"] = DetermineMemberRole(email);

        await _next(context);
    }

    private static bool IsValidApiKey(string apiKey) => 
        !string.IsNullOrWhiteSpace(apiKey) && ValidApiKeys.Contains(apiKey);

    private static List<string> DetermineRoles(string email, GymMember? member)
    {
        var roles = new List<string>();

        if (member != null)
        {
            roles.Add("Member");
            if (member.Tier >= MembershipTier.Gold)
                roles.Add("Premium");
        }

        if (email.Contains("admin", StringComparison.OrdinalIgnoreCase))
            roles.Add("Admin");
        else if (email.Contains("trainer", StringComparison.OrdinalIgnoreCase))
            roles.Add("Trainer");

        return roles;
    }

    private static MemberRole DetermineMemberRole(string email)
    {
        if (email.Contains("admin", StringComparison.OrdinalIgnoreCase))
            return MemberRole.Admin;
        if (email.Contains("trainer", StringComparison.OrdinalIgnoreCase))
            return MemberRole.Trainer;
        return MemberRole.Member;
    }

    private static async Task WriteProblemAsync(HttpContext context, int status, string title, string detail)
    {
        context.Response.StatusCode = status;
        context.Response.ContentType = "application/problem+json";
        await context.Response.WriteAsJsonAsync(new ProblemDetails
        {
            Status = status,
            Title = title,
            Detail = detail
        });
    }
}

