// Service Implementations
public class SupplierService : ISupplierService
{
    private readonly Dictionary<int, Supplier> _suppliers = new();
    private int _nextId = 1;

    public SupplierService()
    {
        _suppliers[1] = new Supplier(1, "Acme Corporation", 1, true);
        _suppliers[2] = new Supplier(2, "Global Supplies Inc", 2, true);
        _suppliers[3] = new Supplier(3, "Premium Parts Ltd", 1, true);
        _nextId = 4;
    }

    public Task<OneOf<Supplier, NotFound>> GetSupplierAsync(int id)
    {
        if (_suppliers.TryGetValue(id, out var supplier))
            return Task.FromResult<OneOf<Supplier, NotFound>>(supplier);

        return Task.FromResult<OneOf<Supplier, NotFound>>(new NotFound(id));
    }

    public Task<OneOf<Supplier, ValidationError>> CreateSupplierAsync(CreateSupplierRequest request)
    {
        var errors = new List<string>();

        if (string.IsNullOrWhiteSpace(request.Name))
            errors.Add("Supplier name is required");

        if (request.Name?.Length > 100)
            errors.Add("Supplier name must not exceed 100 characters");

        if (request.Tier < 1 || request.Tier > 3)
            errors.Add("Tier must be between 1 and 3");

        if (errors.Count > 0)
            return Task.FromResult<OneOf<Supplier, ValidationError>>(new ValidationError(errors.ToArray()));

        var supplier = new Supplier(_nextId++, request.Name, request.Tier, request.IsActive);
        _suppliers[supplier.SupplierId] = supplier;

        return Task.FromResult<OneOf<Supplier, ValidationError>>(supplier);
    }

    public Task<IEnumerable<Supplier>> GetAllSuppliersAsync()
    {
        return Task.FromResult(_suppliers.Values.AsEnumerable());
    }

    public Task<OneOf<Supplier, NotFound, ValidationError>> UpdateSupplierAsync(int id, CreateSupplierRequest request)
    {
        if (!_suppliers.TryGetValue(id, out _))
            return Task.FromResult<OneOf<Supplier, NotFound, ValidationError>>(new NotFound(id));

        var errors = new List<string>();

        if (string.IsNullOrWhiteSpace(request.Name))
            errors.Add("Supplier name is required");

        if (request.Name?.Length > 100)
            errors.Add("Supplier name must not exceed 100 characters");

        if (request.Tier < 1 || request.Tier > 3)
            errors.Add("Tier must be between 1 and 3");

        if (errors.Count > 0)
            return Task.FromResult<OneOf<Supplier, NotFound, ValidationError>>(new ValidationError(errors.ToArray()));

        var updated = new Supplier(id, request.Name, request.Tier, request.IsActive);
        _suppliers[id] = updated;

        return Task.FromResult<OneOf<Supplier, NotFound, ValidationError>>(updated);
    }
}

