public record ProcurementLineItem(
    string Sku,
    int Quantity,
    decimal UnitPrice
);

public record ProcurementCommand(
    Guid RequestId,
    string SupplierCode,
    string WarehouseId,
    List<ProcurementLineItem> Items,
    DateTimeOffset RequestedDeliveryDate,
    decimal TotalValue
);

public record ProcurementSuccess(Guid RequestId, string Message, DateTimeOffset ProcessedAt);
public record ProcurementBusinessError(string Code, string Message);
public record ProcurementNotFoundError(string Resource, string Identifier);

public class ProcurementLineItemValidator : AbstractValidator<ProcurementLineItem>
{
    public ProcurementLineItemValidator()
    {
        RuleFor(x => x.Sku)
            .NotEmpty().WithMessage("Sku is required")
            .Length(10).WithMessage("Sku must be exactly 10 characters");

        RuleFor(x => x.Quantity)
            .InclusiveBetween(1, 10000).WithMessage("Quantity must be between 1 and 10000");

        RuleFor(x => x.UnitPrice)
            .GreaterThan(0).WithMessage("UnitPrice must be positive")
            .Must(HasMaxTwoDecimalPlaces).WithMessage("UnitPrice must have a maximum of 2 decimal places");
    }

    private static bool HasMaxTwoDecimalPlaces(decimal value)
    {
        return decimal.Round(value, 2) == value;
    }
}

public class ProcurementCommandValidator : AbstractValidator<ProcurementCommand>
{
    public ProcurementCommandValidator()
    {
        RuleFor(x => x.RequestId)
            .NotEmpty().WithMessage("RequestId is required");

        RuleFor(x => x.SupplierCode)
            .NotEmpty().WithMessage("SupplierCode is required")
            .MaximumLength(20).WithMessage("SupplierCode must not exceed 20 characters");

        RuleFor(x => x.WarehouseId)
            .NotEmpty().WithMessage("WarehouseId is required")
            .Length(8).WithMessage("WarehouseId must be exactly 8 characters");

        RuleFor(x => x.Items)
            .NotNull().WithMessage("Items collection is required")
            .Must(items => items != null && items.Count >= 1).WithMessage("At least one item is required");

        RuleFor(x => x.RequestedDeliveryDate)
            .NotEmpty().WithMessage("RequestedDeliveryDate is required")
            .Must(date => date > DateTimeOffset.UtcNow).WithMessage("RequestedDeliveryDate must be in the future");

        RuleFor(x => x.TotalValue)
            .GreaterThan(0).WithMessage("TotalValue must be positive");

        RuleForEach(x => x.Items).SetValidator(new ProcurementLineItemValidator());
    }
}

public interface IProcurementService
{
    Task<OneOf<ProcurementSuccess, ProcurementBusinessError, ProcurementNotFoundError>> ProcessAsync(
        ProcurementCommand command,
        CancellationToken cancellationToken = default);
}

public class ProcurementService : IProcurementService
{
    public async Task<OneOf<ProcurementSuccess, ProcurementBusinessError, ProcurementNotFoundError>> ProcessAsync(
        ProcurementCommand command,
        CancellationToken cancellationToken = default)
    {
        await Task.Delay(50, cancellationToken);

        if (command.SupplierCode.StartsWith("INACTIVE", StringComparison.OrdinalIgnoreCase))
        {
            return new ProcurementBusinessError("SUPPLIER_INACTIVE", "The supplier account is currently inactive");
        }

        if (command.WarehouseId == "WH000000")
        {
            return new ProcurementNotFoundError("Warehouse", command.WarehouseId);
        }

        if (command.TotalValue > 1000000)
        {
            return new ProcurementBusinessError("VALUE_LIMIT_EXCEEDED", "Procurement value exceeds maximum allowed limit");
        }

        return new ProcurementSuccess(command.RequestId, "Procurement request processed successfully", DateTimeOffset.UtcNow);
    }
}

public class Program
{
    public static void Main(string[] args)
    {
        var builder = WebApplication.CreateBuilder(args);

        builder.Services.AddValidatorsFromAssemblyContaining<ProcurementCommandValidator>();
        builder.Services.AddScoped<IProcurementService, ProcurementService>();

        var app = builder.Build();

        app.UseExceptionHandler(err => err.Run(async ctx =>
        {
            ctx.Response.ContentType = "application/problem+json";
            await ctx.Response.WriteAsJsonAsync(new ProblemDetails
            {
                Title = "Server Error",
                Status = 500,
                Detail = "Unexpected error occurred"
            });
        }));

        app.MapPost("/api/procurements", async (
            ProcurementCommand command,
            IValidator<ProcurementCommand> validator,
            IProcurementService service,
            CancellationToken cancellationToken) =>
        {
            var validationResult = await validator.ValidateAsync(command, cancellationToken);

            if (!validationResult.IsValid)
            {
                var errors = validationResult.Errors
                    .GroupBy(e => e.PropertyName)
                    .ToDictionary(g => g.Key, g => g.Select(e => e.ErrorMessage).ToArray());

                return Results.ValidationProblem(errors);
            }

            var result = await service.ProcessAsync(command, cancellationToken);

            return result.Match<IResult>(
                success => Results.Created($"/api/procurements/{success.RequestId}", success),
                businessError => Results.BadRequest(businessError),
                notFound => Results.NotFound(notFound)
            );
        });

        app.Run();
    }
}

