    BackstagePass = 2
}

public record Ticket(
    Guid Id,
    [Required][StringLength(200)] string EventName,
    [Required][StringLength(150)] string Venue,
    DateTime EventDate,
    [Range(0.01, double.MaxValue)] decimal Price,
    TicketCategory Category,
    bool IsAvailable,
    DateTime CreatedAt
);

public record PagedResult<T>(
    IReadOnlyList<T> Items,
    int TotalCount,
    int PageNumber,
    int PageSize,
    int TotalPages
);

public record TicketQueryParameters(
    int PageNumber = 1,
    int PageSize = 10,
    string? EventName = null,
    string? Venue = null,
    TicketCategory? Category = null,
    bool? IsAvailable = null,
    string? SortBy = null,
    string? SortOrder = "asc"
);

public record CreateTicketRequest(
    [Required][StringLength(200)] string EventName,
    [Required][StringLength(150)] string Venue,
    DateTime EventDate,
    [Range(0.01, double.MaxValue)] decimal Price,
    TicketCategory Category,
    bool IsAvailable = true
);

public record UpdateTicketRequest(
    [Required][StringLength(200)] string EventName,
    [Required][StringLength(150)] string Venue,
    DateTime EventDate,
    [Range(0.01, double.MaxValue)] decimal Price,
    TicketCategory Category,
    bool IsAvailable
);

public record NotFoundResult(string Message = "Resource not found");

public record ValidationError(Dictionary<string, string[]> Errors);

public interface ITicketService
{
    Task<OneOf<Ticket, NotFoundResult>> GetByIdAsync(Guid id);
    Task<PagedResult<Ticket>> GetPagedAsync(TicketQueryParameters parameters);
    Task<OneOf<Ticket, ValidationError>> CreateAsync(CreateTicketRequest request);
    Task<OneOf<Ticket, NotFoundResult, ValidationError>> UpdateAsync(Guid id, UpdateTicketRequest request);
    Task<OneOf<bool, NotFoundResult>> DeleteAsync(Guid id);
}

public class TicketService : ITicketService
{
    private readonly List<Ticket> _tickets = new();

    public Task<OneOf<Ticket, NotFoundResult>> GetByIdAsync(Guid id)
    {
        var ticket = _tickets.FirstOrDefault(t => t.Id == id);
        return Task.FromResult(ticket is not null
            ? OneOf<Ticket, NotFoundResult>.FromT0(ticket)
            : OneOf<Ticket, NotFoundResult>.FromT1(new NotFoundResult("Ticket not found")));
    }

    public Task<PagedResult<Ticket>> GetPagedAsync(TicketQueryParameters parameters)
    {
        var query = _tickets.AsEnumerable();

        if (!string.IsNullOrEmpty(parameters.EventName))
            query = query.Where(t => t.EventName.Contains(parameters.EventName, StringComparison.OrdinalIgnoreCase));

        if (!string.IsNullOrEmpty(parameters.Venue))
            query = query.Where(t => t.Venue.Contains(parameters.Venue, StringComparison.OrdinalIgnoreCase));

        if (parameters.Category.HasValue)
            query = query.Where(t => t.Category == parameters.Category.Value);

        if (parameters.IsAvailable.HasValue)
            query = query.Where(t => t.IsAvailable == parameters.IsAvailable.Value);

        query = parameters.SortBy?.ToLower() switch
        {
            "eventname" => parameters.SortOrder?.ToLower() == "desc"
                ? query.OrderByDescending(t => t.EventName)
                : query.OrderBy(t => t.EventName),
            "venue" => parameters.SortOrder?.ToLower() == "desc"
                ? query.OrderByDescending(t => t.Venue)
                : query.OrderBy(t => t.Venue),
            "eventdate" => parameters.SortOrder?.ToLower() == "desc"
                ? query.OrderByDescending(t => t.EventDate)
                : query.OrderBy(t => t.EventDate),
            "price" => parameters.SortOrder?.ToLower() == "desc"
                ? query.OrderByDescending(t => t.Price)
                : query.OrderBy(t => t.Price),
            "createdat" => parameters.SortOrder?.ToLower() == "desc"
                ? query.OrderByDescending(t => t.CreatedAt)
                : query.OrderBy(t => t.CreatedAt),
            _ => query.OrderBy(t => t.CreatedAt)
        };

        var totalCount = query.Count();
        var totalPages = (int)Math.Ceiling(totalCount / (double)parameters.PageSize);

        var items = query
            .Skip((parameters.PageNumber - 1) * parameters.PageSize)
            .Take(parameters.PageSize)
            .ToList();

        return Task.FromResult(new PagedResult<Ticket>(items, totalCount, parameters.PageNumber, parameters.PageSize, totalPages));
    }

    public Task<OneOf<Ticket, ValidationError>> CreateAsync(CreateTicketRequest request)
    {
        var ticket = new Ticket(
            Guid.NewGuid(),
            request.EventName,
            request.Venue,
            request.EventDate,
            request.Price,
            request.Category,
            request.IsAvailable,
            DateTime.UtcNow
        );

        _tickets.Add(ticket);
        return Task.FromResult(OneOf<Ticket, ValidationError>.FromT0(ticket));
    }

    public Task<OneOf<Ticket, NotFoundResult, ValidationError>> UpdateAsync(Guid id, UpdateTicketRequest request)
    {
        var existingTicket = _tickets.FirstOrDefault(t => t.Id == id);
        if (existingTicket is null)
            return Task.FromResult(OneOf<Ticket, NotFoundResult, ValidationError>.FromT1(new NotFoundResult("Ticket not found")));

        var updatedTicket = existingTicket with
        {
            EventName = request.EventName,
            Venue = request.Venue,
            EventDate = request.EventDate,
            Price = request.Price,
            Category = request.Category,
            IsAvailable = request.IsAvailable
        };

        var index = _tickets.IndexOf(existingTicket);
        _tickets[index] = updatedTicket;

        return Task.FromResult(OneOf<Ticket, NotFoundResult, ValidationError>.FromT0(updatedTicket));
    }

    public Task<OneOf<bool, NotFoundResult>> DeleteAsync(Guid id)
    {
        var ticket = _tickets.FirstOrDefault(t => t.Id == id);
        if (ticket is null)
            return Task.FromResult(OneOf<bool, NotFoundResult>.FromT1(new NotFoundResult("Ticket not found")));

        _tickets.Remove(ticket);
        return Task.FromResult(OneOf<bool, NotFoundResult>.FromT0(true));
    }
}

