public interface IPrescriptionService
{
    OneOf<Prescription, PrescriptionNotFound> GetById(Guid id);
    OneOf<Prescription, PrescriptionNotFound> Create(CreatePrescriptionRequest request);
    OneOf<Prescription, PrescriptionNotFound> Update(Guid id, UpdatePrescriptionRequest request);
    OneOf<bool, PrescriptionNotFound> Delete(Guid id);
    OneOf<Prescription, PrescriptionNotFound> Dispense(Guid id);
    OneOf<Prescription, PrescriptionNotFound> Cancel(Guid id);
    IEnumerable<Prescription> GetAll();
}

public class PrescriptionService : IPrescriptionService
{
    private readonly Dictionary<Guid, Prescription> _prescriptions = new();

    public OneOf<Prescription, PrescriptionNotFound> GetById(Guid id)
    {
        if (_prescriptions.TryGetValue(id, out var prescription))
        {
            return prescription;
        }
        return new PrescriptionNotFound(id);
    }

    public OneOf<Prescription, PrescriptionNotFound> Create(CreatePrescriptionRequest request)
    {
        var prescription = new Prescription
        {
            Id = Guid.NewGuid(),
            PatientName = request.PatientName,
            MedicationName = request.MedicationName,
            DosageMg = request.DosageMg,
            Quantity = request.Quantity,
            PrescribedDate = DateTime.UtcNow,
            PrescriberId = request.PrescriberId,
            Status = PrescriptionStatus.Pending
        };

        _prescriptions[prescription.Id] = prescription;
        return prescription;
    }

    public OneOf<Prescription, PrescriptionNotFound> Update(Guid id, UpdatePrescriptionRequest request)
    {
        if (!_prescriptions.TryGetValue(id, out var existing))
        {
            return new PrescriptionNotFound(id);
        }

        var updated = existing with
        {
            DosageMg = request.DosageMg,
            Quantity = request.Quantity
        };

        _prescriptions[id] = updated;
        return updated;
    }

    public OneOf<bool, PrescriptionNotFound> Delete(Guid id)
    {
        if (!_prescriptions.ContainsKey(id))
        {
            return new PrescriptionNotFound(id);
        }

        _prescriptions.Remove(id);
        return true;
    }

    public OneOf<Prescription, PrescriptionNotFound> Dispense(Guid id)
    {
        if (!_prescriptions.TryGetValue(id, out var existing))
        {
            return new PrescriptionNotFound(id);
        }

        if (existing.Status != PrescriptionStatus.Pending)
        {
            return new PrescriptionNotFound(id);
        }

        var updated = existing with { Status = PrescriptionStatus.Dispensed };
        _prescriptions[id] = updated;
        return updated;
    }

    public OneOf<Prescription, PrescriptionNotFound> Cancel(Guid id)
    {
        if (!_prescriptions.TryGetValue(id, out var existing))
        {
            return new PrescriptionNotFound(id);
        }

        if (existing.Status == PrescriptionStatus.Dispensed)
        {
            return new PrescriptionNotFound(id);
        }

        var updated = existing with { Status = PrescriptionStatus.Cancelled };
        _prescriptions[id] = updated;
        return updated;
    }

    public IEnumerable<Prescription> GetAll()
    {
        return _prescriptions.Values;
    }
}

