// Record types
public record Book(int Id, string Title, string Author, bool IsAvailable);
public record Loan(int Id, int BookId, string BorrowerName, DateTime BorrowedDate, DateTime? ReturnedDate);
public record NotFound(int Id);
public record BookNotAvailable(int BookId);
public record ValidationError(string Message);

// Request DTOs
public record CreateLoanRequest(int BookId, string BorrowerName);

// Service Interface
public interface ILoanService
{
    OneOf<Loan, NotFound, BookNotAvailable> CreateLoan(int bookId, string borrowerName);
    OneOf<Loan, NotFound, ValidationError> ReturnBook(int loanId);
    OneOf<Loan, NotFound> GetLoan(int loanId);
    OneOf<List<Loan>, NotFound> GetLoansByBook(int bookId);
    OneOf<Book, NotFound> GetBook(int bookId);
    IEnumerable<Book> GetAllBooks();
}

// Service Implementation
public class LoanService : ILoanService
{
    private readonly Dictionary<int, Book> _books = new();
    private readonly Dictionary<int, Loan> _loans = new();
    private int _nextLoanId = 1;

    public LoanService()
    {
        _books[1] = new Book(1, "The Great Gatsby", "F. Scott Fitzgerald", true);
        _books[2] = new Book(2, "1984", "George Orwell", true);
        _books[3] = new Book(3, "To Kill a Mockingbird", "Harper Lee", false);
    }

    public OneOf<Loan, NotFound, BookNotAvailable> CreateLoan(int bookId, string borrowerName)
    {
        if (!_books.TryGetValue(bookId, out var book))
        {
            return new NotFound(bookId);
        }

        if (!book.IsAvailable)
        {
            return new BookNotAvailable(bookId);
        }

        var loan = new Loan(_nextLoanId++, bookId, borrowerName, DateTime.UtcNow, null);
        _loans[loan.Id] = loan;
        _books[bookId] = book with { IsAvailable = false };

        return loan;
    }

    public OneOf<Loan, NotFound, ValidationError> ReturnBook(int loanId)
    {
        if (!_loans.TryGetValue(loanId, out var loan))
        {
            return new NotFound(loanId);
        }

        if (loan.ReturnedDate.HasValue)
        {
            return new ValidationError("Book already returned");
        }

        var updatedLoan = loan with { ReturnedDate = DateTime.UtcNow };
        _loans[loanId] = updatedLoan;

        if (_books.TryGetValue(loan.BookId, out var book))
        {
            _books[loan.BookId] = book with { IsAvailable = true };
        }

        return updatedLoan;
    }

    public OneOf<Loan, NotFound> GetLoan(int loanId)
    {
        if (!_loans.TryGetValue(loanId, out var loan))
        {
            return new NotFound(loanId);
        }
        return loan;
    }

    public OneOf<List<Loan>, NotFound> GetLoansByBook(int bookId)
    {
        if (!_books.ContainsKey(bookId))
        {
            return new NotFound(bookId);
        }
        return _loans.Values.Where(l => l.BookId == bookId).ToList();
    }

    public OneOf<Book, NotFound> GetBook(int bookId)
    {
