// Service Implementation
public class LibraryService : ILibraryService
{
    private readonly List<Book> _books = new();
    private readonly List<Patron> _patrons = new();
    private readonly List<LendingRecord> _lendingRecords = new();

    // Books
    public Task<IEnumerable<Book>> GetAllBooksAsync() => Task.FromResult(_books.AsEnumerable());

    public Task<Book?> GetBookByIdAsync(Guid id) => Task.FromResult(_books.FirstOrDefault(b => b.Id == id));

    public Task<Book> CreateBookAsync(CreateBookRequest request)
    {
        var book = new Book(
            Guid.NewGuid(),
            request.Title,
            request.Author,
            request.Isbn,
            request.PublishedYear,
            true
        );
        _books.Add(book);
        return Task.FromResult(book);
    }

    public Task<OneOf<Book, NotFound>> UpdateBookAsync(Guid id, UpdateBookRequest request)
    {
        var index = _books.FindIndex(b => b.Id == id);
        if (index == -1) return Task.FromResult<OneOf<Book, NotFound>>(new NotFound("Book not found"));

        var existing = _books[index];
        var updated = existing with
        {
            Title = request.Title ?? existing.Title,
            Author = request.Author ?? existing.Author,
            Isbn = request.Isbn ?? existing.Isbn,
            PublishedYear = request.PublishedYear ?? existing.PublishedYear,
            IsAvailable = request.IsAvailable ?? existing.IsAvailable
        };
        _books[index] = updated;
        return Task.FromResult<OneOf<Book, NotFound>>(updated);
    }

    public Task<OneOf<NotFound, NoContent>> DeleteBookAsync(Guid id)
    {
        var book = _books.FirstOrDefault(b => b.Id == id);
        if (book == null) return Task.FromResult<OneOf<NotFound, NoContent>>(new NotFound("Book not found"));

        _books.Remove(book);
        return Task.FromResult<OneOf<NotFound, NoContent>>(new NoContent());
    }

    // Patrons
    public Task<IEnumerable<Patron>> GetAllPatronsAsync() => Task.FromResult(_patrons.AsEnumerable());

    public Task<Patron?> GetPatronByIdAsync(Guid id) => Task.FromResult(_patrons.FirstOrDefault(p => p.Id == id));

    public Task<Patron> CreatePatronAsync(CreatePatronRequest request)
    {
        var patron = new Patron(
            Guid.NewGuid(),
            request.FirstName,
            request.LastName,
            request.Email,
            request.MaxBorrowLimit
        );
        _patrons.Add(patron);
        return Task.FromResult(patron);
    }

    public Task<OneOf<Patron, NotFound>> UpdatePatronAsync(Guid id, string firstName, string lastName, string email, int maxBorrowLimit)
    {
        var index = _patrons.FindIndex(p => p.Id == id);
        if (index == -1) return Task.FromResult<OneOf<Patron, NotFound>>(new NotFound("Patron not found"));

        var updated = _patrons[index] with
        {
            FirstName = firstName,
            LastName = lastName,
            Email = email,
            MaxBorrowLimit = maxBorrowLimit
        };
        _patrons[index] = updated;
        return Task.FromResult<OneOf<Patron, NotFound>>(updated);
    }

    public Task<OneOf<NotFound, NoContent>> DeletePatronAsync(Guid id)
    {
        var patron = _patrons.FirstOrDefault(p => p.Id == id);
        if (patron == null) return Task.FromResult<OneOf<NotFound, NoContent>>(new NotFound("Patron not found"));

        _patrons.Remove(patron);
        return Task.FromResult<OneOf<NotFound, NoContent>>(new NoContent());
    }

    // Lending
    public Task<IEnumerable<LendingRecord>> GetAllLendingRecordsAsync() => Task.FromResult(_lendingRecords.AsEnumerable());

    public Task<OneOf<LendingRecord, NotFound, BadRequest>> BorrowBookAsync(BorrowBookRequest request)
    {
        var book = _books.FirstOrDefault(b => b.Id == request.BookId);
        if (book == null) return Task.FromResult<OneOf<LendingRecord, NotFound, BadRequest>>(new NotFound("Book not found"));

        var patron = _patrons.FirstOrDefault(p => p.Id == request.PatronId);
        if (patron == null) return Task.FromResult<OneOf<LendingRecord, NotFound, BadRequest>>(new NotFound("Patron not found"));

        if (!book.IsAvailable)
            return Task.FromResult<OneOf<LendingRecord, NotFound, BadRequest>>(new BadRequest("Book is not available for borrowing"));

        var activeLoans = _lendingRecords.Count(lr => lr.PatronId == patron.Id && lr.ReturnedDate == null);
        if (activeLoans >= patron.MaxBorrowLimit)
            return Task.FromResult<OneOf<LendingRecord, NotFound, BadRequest>>(new BadRequest("Patron has reached maximum borrow limit"));

        var record = new LendingRecord(
            Guid.NewGuid(),
            request.BookId,
            request.PatronId,
            DateTime.UtcNow,
            null
        );
        _lendingRecords.Add(record);

        var bookIndex = _books.FindIndex(b => b.Id == request.BookId);
        _books[bookIndex] = book with { IsAvailable = false };

        return Task.FromResult<OneOf<LendingRecord, NotFound, BadRequest>>(record);
    }

    public Task<OneOf<LendingRecord, NotFound, BadRequest>> ReturnBookAsync(Guid bookId)
    {
        var record = _lendingRecords.FirstOrDefault(lr => lr.BookId == bookId && lr.ReturnedDate == null);
        if (record == null) return Task.FromResult<OneOf<LendingRecord, NotFound, BadRequest>>(new NotFound("No active lending record found for this book"));

        var index = _lendingRecords.FindIndex(lr => lr.Id == record.Id);
        _lendingRecords[index] = record with { ReturnedDate = DateTime.UtcNow };

        var book = _books.FirstOrDefault(b => b.Id == bookId);
        if (book != null)
        {
            var bookIndex = _books.FindIndex(b => b.Id == bookId);
            _books[bookIndex] = book with { IsAvailable = true };
        }

        return Task.FromResult<OneOf<LendingRecord, NotFound, BadRequest>>(_lendingRecords[index]);
    }

    public Task<IEnumerable<LendingRecord>> GetPatronActiveLoansAsync(Guid patronId)
    {
        return Task.FromResult(_lendingRecords.Where(lr => lr.PatronId == patronId && lr.ReturnedDate == null).AsEnumerable());
    }
}

// OneOf implementation
public readonly struct OneOf<T0, T1>
{
    private readonly T0? _value0;
    private readonly T1? _value1;
    private readonly int _index;

    private OneOf(T0 value) { _value0 = value; _value1 = default; _index = 0; }
    private OneOf(T1 value) { _value0 = default; _value1 = value; _index = 1; }

    public static implicit operator OneOf<T0, T1>(T0 value) => new(value);
    public static implicit operator OneOf<T0, T1>(T1 value) => new(value);

    public TResult Match<TResult>(Func<T0, TResult> f0, Func<T1, TResult> f1) =>
        _index switch
        {
            0 => f0(_value0!),
            1 => f1(_value1!),
            _ => throw new InvalidOperationException()
        };
}

public readonly struct OneOf<T0, T1, T2>
{
    private readonly T0? _value0;
    private readonly T1? _value1;
    private readonly T2? _value2;
    private readonly int _index;

    private OneOf(T0 value) { _value0 = value; _value1 = default; _value2 = default; _index = 0; }
    private OneOf(T1 value) { _value0 = default; _value1 = value; _value2 = default; _index = 1; }
    private OneOf(T2 value) { _value0 = default; _value1 = default; _value2 = value; _index = 2; }

    public static implicit operator OneOf<T0, T1, T2>(T0 value) => new(value);
    public static implicit operator OneOf<T0, T1, T2>(T1 value) => new(value);
    public static implicit operator OneOf<T0, T1, T2>(T2 value) => new(value);

    public TResult Match<TResult>(Func<T0, TResult> f0, Func<T1, TResult> f1, Func<T2, TResult> f2) =>
        _index switch
        {
            0 => f0(_value0!),
            1 => f1(_value1!),
            2 => f2(_value2!),
            _ => throw new InvalidOperationException()
        };
}

