// Service Implementation
public class BookService : IBookService
{
    private readonly List<Book> _books = new();

    public Task<OneOf<Book, BookNotFound>> GetBookByIdAsync(Guid id)
    {
        var book = _books.FirstOrDefault(b => b.Id == id);
        return Task.FromResult(book is not null
            ? OneOf<Book, BookNotFound>.FromT0(book)
            : OneOf<Book, BookNotFound>.FromT1(new BookNotFound(id)));
    }

    public Task<PagedResult<Book>> GetBooksAsync(BookFilter filter)
    {
        var query = _books.AsQueryable();

        // Apply filters
        if (!string.IsNullOrEmpty(filter.Title))
            query = query.Where(b => b.Title.Contains(filter.Title, StringComparison.OrdinalIgnoreCase));

        if (!string.IsNullOrEmpty(filter.Author))
            query = query.Where(b => b.Author.Contains(filter.Author, StringComparison.OrdinalIgnoreCase));

        if (!string.IsNullOrEmpty(filter.Genre))
            query = query.Where(b => b.Genre.Equals(filter.Genre, StringComparison.OrdinalIgnoreCase));

        if (filter.IsAvailable.HasValue)
            query = query.Where(b => b.IsAvailable == filter.IsAvailable.Value);

        // Apply sorting
        if (!string.IsNullOrEmpty(filter.SortBy))
        {
            query = filter.SortBy.ToLowerInvariant() switch
            {
                "title" => filter.SortDescending
                    ? query.OrderByDescending(b => b.Title)
                    : query.OrderBy(b => b.Title),
                "author" => filter.SortDescending
                    ? query.OrderByDescending(b => b.Author)
                    : query.OrderBy(b => b.Author),
                "genre" => filter.SortDescending
                    ? query.OrderByDescending(b => b.Genre)
                    : query.OrderBy(b => b.Genre),
                "publisheddate" => filter.SortDescending
                    ? query.OrderByDescending(b => b.PublishedDate)
                    : query.OrderBy(b => b.PublishedDate),
                "totalcopies" => filter.SortDescending
                    ? query.OrderByDescending(b => b.TotalCopies)
                    : query.OrderBy(b => b.TotalCopies),
                "availablecopies" => filter.SortDescending
                    ? query.OrderByDescending(b => b.AvailableCopies)
                    : query.OrderBy(b => b.AvailableCopies),
                _ => query.OrderBy(b => b.Title)
            };
        }

        var totalCount = query.Count();

        var items = query
            .Skip((filter.PageNumber - 1) * filter.PageSize)
            .Take(filter.PageSize)
            .ToList();

        return Task.FromResult(new PagedResult<Book>(items, totalCount, filter.PageNumber, filter.PageSize));
    }

