// Command Model
public record CheckoutBookCommand(
    Guid BookId,
    Guid PatronId,
    string LibraryCardNumber,
    DateTime DueDate
);

// FluentValidator
public class CheckoutBookCommandValidator : AbstractValidator<CheckoutBookCommand>
{
    public CheckoutBookCommandValidator()
    {
        RuleFor(x => x.BookId)
            .NotEqual(Guid.Empty)
            .WithMessage("BookId must not be empty");

        RuleFor(x => x.PatronId)
            .NotEqual(Guid.Empty)
            .WithMessage("PatronId must not be empty");

        RuleFor(x => x.LibraryCardNumber)
            .NotEmpty().WithMessage("LibraryCardNumber must not be empty")
            .Length(8, 16).WithMessage("LibraryCardNumber must be between 8 and 16 characters")
            .Matches(@"^LIB\d+$").WithMessage("LibraryCardNumber must start with 'LIB' followed by digits only");

        RuleFor(x => x.DueDate)
            .Must(dueDate => dueDate > DateTime.UtcNow)
            .WithMessage("DueDate must be greater than current date/time")
            .Must(dueDate => dueDate <= DateTime.UtcNow.AddDays(30))
            .WithMessage("DueDate must be no more than 30 days from now");
    }
}

