using System.Security.Claims;

// Domain Models
public record User(Guid Id, string Username, string Email, UserRole Role, DateTime CreatedAt);
public record Book(Guid Id, string Title, string Author, string Isbn, int TotalCopies, int AvailableCopies);
public record Loan(Guid Id, Guid BookId, Guid UserId, DateTime BorrowedAt, DateTime? ReturnedAt);
public record AuthToken(string Value, DateTime ExpiresAt, Guid UserId);

public enum UserRole { Member, Librarian, Administrator }

// OneOf Result Types
public record AuthenticationFailed(string Reason);
public record BookNotAvailable(string Message);
public record UserLimitExceeded(string Message);
public record Unauthorized(string Message);
public record BookNotFound(Guid BookId);

public class AuthenticationResult : OneOfBase<User, AuthenticationFailed>
{
    public AuthenticationResult(OneOf<User, AuthenticationFailed> input) : base(input) { }
    public static implicit operator AuthenticationResult(User user) => new(user);
    public static implicit operator AuthenticationResult(AuthenticationFailed failed) => new(failed);
}

public class LendingResult : OneOfBase<Loan, BookNotAvailable, UserLimitExceeded, Unauthorized>
{
    public LendingResult(OneOf<Loan, BookNotAvailable, UserLimitExceeded, Unauthorized> input) : base(input) { }
    public static implicit operator LendingResult(Loan loan) => new(loan);
    public static implicit operator LendingResult(BookNotAvailable error) => new(error);
    public static implicit operator LendingResult(UserLimitExceeded error) => new(error);
    public static implicit operator LendingResult(Unauthorized error) => new(error);
}

public class BookResult : OneOfBase<Book, BookNotFound>
{
    public BookResult(OneOf<Book, BookNotFound> input) : base(input) { }
    public static implicit operator BookResult(Book book) => new(book);
    public static implicit operator BookResult(BookNotFound error) => new(error);
}

// Interfaces
public interface IUserRepository
{
    Task<User?> GetByIdAsync(Guid id);
    Task<User?> GetByUsernameAsync(string username);
    Task<User> CreateAsync(string username, string email, UserRole role);
    Task<IEnumerable<User>> GetAllAsync();
}

public interface IBookRepository
{
    Task<Book?> GetByIdAsync(Guid id);
    Task<Book?> GetByIsbnAsync(string isbn);
    Task<IEnumerable<Book>> GetAllAsync();
    Task<Book> CreateAsync(string title, string author, string isbn, int totalCopies);
    Task<Book> UpdateAsync(Book book);
}

public interface ILoanRepository
{
    Task<Loan?> GetByIdAsync(Guid id);
    Task<IEnumerable<Loan>> GetByUserIdAsync(Guid userId);
    Task<IEnumerable<Loan>> GetActiveLoansAsync();
    Task<Loan> CreateAsync(Guid bookId, Guid userId);
    Task<Loan> ReturnAsync(Guid loanId);
    Task<int> GetActiveLoanCountForUserAsync(Guid userId);
}

public interface IAuthService
{
    Task<AuthToken> GenerateTokenAsync(User user);
    Task<AuthenticationResult> ValidateTokenAsync(string tokenValue);
    Task<AuthenticationResult> AuthenticateAsync(string username, string email);
}

public interface ILendingService
{
    Task<LendingResult> BorrowBookAsync(Guid bookId, Guid userId);
    Task<LendingResult> ReturnBookAsync(Guid loanId, Guid userId);
    Task<IEnumerable<Loan>> GetUserLoansAsync(Guid userId);
}

// Repository Implementations
public class InMemoryUserRepository : IUserRepository
{
    private readonly Dictionary<Guid, User> _users = new();
    private readonly Dictionary<string, User> _usersByUsername = new();

    public Task<User?> GetByIdAsync(Guid id) => 
        Task.FromResult(_users.TryGetValue(id, out var user) ? user : null);

    public Task<User?> GetByUsernameAsync(string username) =>
        Task.FromResult(_usersByUsername.TryGetValue(username, out var user) ? user : null);

    public Task<User> CreateAsync(string username, string email, UserRole role)
    {
        var user = new User(Guid.NewGuid(), username, email, role, DateTime.UtcNow);
        _users[user.Id] = user;
        _usersByUsername[username] = user;
        return Task.FromResult(user);
    }

    public Task<IEnumerable<User>> GetAllAsync() => Task.FromResult(_users.Values.AsEnumerable());
}

public class InMemoryBookRepository : IBookRepository
{
    private readonly Dictionary<Guid, Book> _books = new();
    private readonly Dictionary<string, Book> _booksByIsbn = new();

    public Task<Book?> GetByIdAsync(Guid id) =>
        Task.FromResult(_books.TryGetValue(id, out var book) ? book : null);

    public Task<Book?> GetByIsbnAsync(string isbn) =>
        Task.FromResult(_booksByIsbn.TryGetValue(isbn, out var book) ? book : null);

    public Task<IEnumerable<Book>> GetAllAsync() => Task.FromResult(_books.Values.AsEnumerable());

    public Task<Book> CreateAsync(string title, string author, string isbn, int totalCopies)
    {
        var book = new Book(Guid.NewGuid(), title, author, isbn, totalCopies, totalCopies);
        _books[book.Id] = book;
        _booksByIsbn[isbn] = book;
        return Task.FromResult(book);
    }

    public Task<Book> UpdateAsync(Book book)
    {
        _books[book.Id] = book;
        _booksByIsbn[book.Isbn] = book;
        return Task.FromResult(book);
    }
}

public class InMemoryLoanRepository : ILoanRepository
{
    private readonly Dictionary<Guid, Loan> _loans = new();

    public Task<Loan?> GetByIdAsync(Guid id) =>
        Task.FromResult(_loans.TryGetValue(id, out var loan) ? loan : null);

    public Task<IEnumerable<Loan>> GetByUserIdAsync(Guid userId) =>
        Task.FromResult(_loans.Values.Where(l => l.UserId == userId));

    public Task<IEnumerable<Loan>> GetActiveLoansAsync() =>
        Task.FromResult(_loans.Values.Where(l => l.ReturnedAt == null));

    public Task<Loan> CreateAsync(Guid bookId, Guid userId)
    {
        var loan = new Loan(Guid.NewGuid(), bookId, userId, DateTime.UtcNow, null);
        _loans[loan.Id] = loan;
        return Task.FromResult(loan);
    }

    public Task<Loan> ReturnAsync(Guid loanId)
    {
        var loan = _loans[loanId];
        var returned = loan with { ReturnedAt = DateTime.UtcNow };
        _loans[loanId] = returned;
        return Task.FromResult(returned);
    }

    public Task<int> GetActiveLoanCountForUserAsync(Guid userId) =>
        Task.FromResult(_loans.Values.Count(l => l.UserId == userId && l.ReturnedAt == null));
}

// Service Implementations
public class AuthService : IAuthService
{
    private readonly IUserRepository _userRepository;
    private readonly Dictionary<string, AuthToken> _tokens = new();

    public AuthService(IUserRepository userRepository) => _userRepository = userRepository;

    public Task<AuthToken> GenerateTokenAsync(User user)
    {
        var token = new AuthToken(Guid.NewGuid().ToString("N"), DateTime.UtcNow.AddDays(7), user.Id);
        _tokens[token.Value] = token;
        return Task.FromResult(token);
    }

    public async Task<AuthenticationResult> ValidateTokenAsync(string tokenValue)
    {
        if (!_tokens.TryGetValue(tokenValue, out var token))
            return new AuthenticationFailed("Invalid token");

        if (token.ExpiresAt < DateTime.UtcNow)
            return new AuthenticationFailed("Token expired");

        var user = await _userRepository.GetByIdAsync(token.UserId);
        if (user == null)
            return new AuthenticationFailed("User not found");

        return user;
    }

    public async Task<AuthenticationResult> AuthenticateAsync(string username, string email)
    {
        var user = await _userRepository.GetByUsernameAsync(username);
        if (user == null)
            return new AuthenticationFailed("User not found");

        if (user.Email != email)
            return new AuthenticationFailed("Email mismatch");

        return user;
    }
}

public class LendingService : ILendingService
{
    private readonly IBookRepository _bookRepository;
    private readonly ILoanRepository _loanRepository;
    private const int MaxLoansPerUser = 5;

    public LendingService(IBookRepository bookRepository, ILoanRepository loanRepository)
    {
        _bookRepository = bookRepository;
        _loanRepository = loanRepository;
    }

    public async Task<LendingResult> BorrowBookAsync(Guid bookId, Guid userId)
    {
        var book = await _bookRepository.GetByIdAsync(bookId);
        if (book == null)
            return new BookNotAvailable("Book not found");

        if (book.AvailableCopies <= 0)
            return new BookNotAvailable("No copies available");

        var activeLoans = await _loanRepository.GetActiveLoanCountForUserAsync(userId);
        if (activeLoans >= MaxLoansPerUser)
            return new UserLimitExceeded($"Maximum {MaxLoansPerUser} active loans allowed");

        var loan = await _loanRepository.CreateAsync(bookId, userId);
        var updatedBook = book with { AvailableCopies = book.AvailableCopies - 1 };
        await _bookRepository.UpdateAsync(updatedBook);

        return loan;
    }

    public async Task<LendingResult> ReturnBookAsync(Guid loanId, Guid userId)
    {
        var loan = await _loanRepository.GetByIdAsync(loanId);
        if (loan == null)
            return new Unauthorized("Loan not found");

        if (loan.UserId != userId)
            return new Unauthorized("You can only return your own loans");

        if (loan.ReturnedAt != null)
            return new Unauthorized("Book already returned");

        var returnedLoan = await _loanRepository.ReturnAsync(loanId);
        var book = await _bookRepository.GetByIdAsync(loan.BookId);
        if (book != null)
        {
            var updatedBook = book with { AvailableCopies = book.AvailableCopies + 1 };
            await _bookRepository.UpdateAsync(updatedBook);
        }

        return returnedLoan;
    }

    public async Task<IEnumerable<Loan>> GetUserLoansAsync(Guid userId) =>
        await _loanRepository.GetByUserIdAsync(userId);
}

// Authentication Middleware
public class AuthenticationMiddleware
{
    private readonly RequestDelegate _next;
    private readonly IAuthService _authService;

    public AuthenticationMiddleware(RequestDelegate next, IAuthService authService)
    {
        _next = next;
        _authService = authService;
    }

    public async Task InvokeAsync(HttpContext context)
    {
        var path = context.Request.Path.Value ?? "";

        if (ShouldSkipAuthentication(path))
        {
            await _next(context);
            return;
        }

        var authHeader = context.Request.Headers.Authorization.ToString();
        if (string.IsNullOrEmpty(authHeader) || !authHeader.StartsWith("Bearer "))
        {
            await WriteProblemResponse(context, 401, "Unauthorized", "Authentication required");
            return;
        }

        var token = authHeader["Bearer ".Length..].Trim();
        var result = await _authService.ValidateTokenAsync(token);

        await result.Switch(
            async user =>
            {
                var claims = new List<Claim>
                {
                    new(ClaimTypes.NameIdentifier, user.Id.ToString()),
                    new(ClaimTypes.Name, user.Username),
                    new(ClaimTypes.Role, user.Role.ToString())
                };
                var identity = new ClaimsIdentity(claims, "Bearer");
                context.User = new ClaimsPrincipal(identity);
                context.Items["User"] = user;
                await _next(context);
            },
            async failed =>
            {
                await WriteProblemResponse(context, 401, "Authentication Failed", failed.Reason);
            }
        );
    }

    private static bool ShouldSkipAuthentication(string path) =>
        path.StartsWith("/api/auth", StringComparison.OrdinalIgnoreCase) ||
        path.StartsWith("/swagger", StringComparison.OrdinalIgnoreCase) ||
        path == "/health";

    private static async Task WriteProblemResponse(HttpContext context, int status, string title, string detail)
    {
        context.Response.ContentType = "application/problem+json";
        context.Response.StatusCode = status;
        await context.Response.WriteAsJsonAsync(new ProblemDetails
        {
            Title = title,
            Status = status,
            Detail = detail
        });
    }
}

// Authorization Middleware
public class AuthorizationMiddleware
{
    private readonly RequestDelegate _next;

    public AuthorizationMiddleware(RequestDelegate next) => _next = next;

    public async Task InvokeAsync(HttpContext context)
    {
        var endpoint = context.GetEndpoint();
        var requiredRoles = endpoint?.Metadata.GetMetadata<RequiredRolesAttribute>();

        if (requiredRoles == null)
        {
            await _next(context);
            return;
        }

        var userRole = context.User.FindFirst(ClaimTypes.Role)?.Value;
        if (string.IsNullOrEmpty(userRole) || !requiredRoles.Roles.Contains(userRole))
        {
            await WriteProblemResponse(context, 403, "Forbidden", 
                $"Role '{userRole ?? "none"}' is not authorized. Required: {string.Join(", ", requiredRoles.Roles)}");
            return;
        }

        await _next(context);
    }

    private static async Task WriteProblemResponse(HttpContext context, int status, string title, string detail)
    {
        context.Response.ContentType = "application/problem+json";
        context.Response.StatusCode = status;
        await context.Response.WriteAsJsonAsync(new ProblemDetails
        {
            Title = title,
            Status = status,
            Detail = detail
        });
    }
}

[AttributeUsage(AttributeTargets.Method | AttributeTargets.Class)]
public class RequiredRolesAttribute : Attribute
{
    public string[] Roles { get; }

    public RequiredRolesAttribute(params string[] roles) => Roles = roles;
}

// Program
public class Program
{
    public static async Task Main(string[] args)
    {
        var builder = WebApplication.CreateBuilder(args);

        builder.Services.AddScoped<IUserRepository, InMemoryUserRepository>();
        builder.Services.AddScoped<IBookRepository, InMemoryBookRepository>();
        builder.Services.AddScoped<ILoanRepository, InMemoryLoanRepository>();
        builder.Services.AddScoped<IAuthService, AuthService>();
        builder.Services.AddScoped<ILendingService, LendingService>();

        var app = builder.Build();

        app.UseMiddleware<AuthenticationMiddleware>();
        app.UseMiddleware<AuthorizationMiddleware>();

        app.UseExceptionHandler(err => err.Run(async ctx =>
        {
            ctx.Response.ContentType = "application/problem+json";
            await ctx.Response.WriteAsJsonAsync(new ProblemDetails
            {
                Title = "Server Error",
                Status = 500,
                Detail = "An unexpected error occurred"
            });
        }));

        // Auth endpoints (no authentication required)
        app.MapPost("/api/auth/login", async (LoginRequest req, IAuthService auth) =>
        {
            var result = await auth.AuthenticateAsync(req.Username, req.Email);
            return await result.Match(
                async user =>
                {
                    var token = await auth.GenerateTokenAsync(user);
                    return Results.Ok(new { Token = token.Value, ExpiresAt = token.ExpiresAt, User = user });
                },
                failed => Task.FromResult(Results.Unauthorized())
            );
        });

        app.MapPost("/api/auth/token/validate", async (ValidateTokenRequest req, IAuthService auth) =>
        {
            var result = await auth.ValidateTokenAsync(req.Token);
            return result.Match(
                user => Results.Ok(new { Valid = true, User = user }),
                failed => Results.Ok(new { Valid = false, Error = failed.Reason })
            );
        });

        // Book endpoints
        app.MapGet("/api/books", async (IBookRepository repo) =>
            Results.Ok(await repo.GetAllAsync()));

        app.MapGet("/api/books/{id:guid}", async (Guid id, IBookRepository repo) =>
        {
            var book = await repo.GetByIdAsync(id);
            return book != null ? Results.Ok(book) : Results.NotFound();
        });

        app.MapPost("/api/books", [RequiredRoles("Librarian", "Administrator")] async (
            CreateBookRequest req, IBookRepository repo) =>
        {
            var book = await repo.CreateAsync(req.Title, req.Author, req.Isbn, req.TotalCopies);
            return Results.Created($"/api/books/{book.Id}", book);
        });

        // Loan endpoints
        app.MapPost("/api/loans/borrow", async (BorrowRequest req, HttpContext ctx, ILendingService lending) =>
        {
            var userId = GetUserId(ctx);
            if (userId == null) return Results.Unauthorized();

            var result = await lending.BorrowBookAsync(req.BookId, userId.Value);
            return result.Match<Loan, BookNotAvailable, UserLimitExceeded, Unauthorized, IResult>(
                loan => Results.Ok(loan),
                error => Results.BadRequest(error.Message),
                error => Results.BadRequest(error.Message),
                error => Results.Unauthorized()
            );
        });

        app.MapPost("/api/loans/return", async (ReturnRequest req, HttpContext ctx, ILendingService lending) =>
        {
            var userId = GetUserId(ctx);
            if (userId == null) return Results.Unauthorized();

            var result = await lending.ReturnBookAsync(req.LoanId, userId.Value);
            return result.Match<Loan, BookNotAvailable, UserLimitExceeded, Unauthorized, IResult>(
                loan => Results.Ok(loan),
                error => Results.BadRequest(error.Message),
                error => Results.BadRequest(error.Message),
                error => Results.Unauthorized()
            );
        });

        app.MapGet("/api/loans/my", async (HttpContext ctx, ILendingService lending) =>
        {
            var userId = GetUserId(ctx);
            if (userId == null) return Results.Unauthorized();

            var loans = await lending.GetUserLoansAsync(userId.Value);
            return Results.Ok(loans);
        });

        // Admin endpoints
        app.MapGet("/api/admin/users", [RequiredRoles("Administrator")] async (IUserRepository repo) =>
            Results.Ok(await repo.GetAllAsync()));

        app.MapPost("/api/admin/users", [RequiredRoles("Administrator")] async (
            CreateUserRequest req, IUserRepository repo) =>
        {
            var user = await repo.CreateAsync(req.Username, req.Email, req.Role);
            return Results.Created($"/api/admin/users/{user.Id}", user);
        });

        // Seed data
        await SeedData(app.Services);

        app.Run();
    }

    private static Guid? GetUserId(HttpContext ctx)
    {
        var userIdClaim = ctx.User.FindFirst(ClaimTypes.NameIdentifier)?.Value;
        return userIdClaim != null ? Guid.Parse(userIdClaim) : null;
    }

    private static async Task SeedData(IServiceProvider services)
    {
        using var scope = services.CreateScope();

using Microsoft.AspNetCore.Mvc;
using OneOf;
using System.ComponentModel.DataAnnotations;

// Enums
public enum BookingStatus
{
    Pending,
    Confirmed,
    Cancelled
}

// Domain Models
public record FlightBooking(
    Guid Id,
    string FlightNumber,
    string PassengerName,
    string Origin,
    string Destination,
    DateTime DepartureTime,
    decimal Price,
    BookingStatus Status
);

public record BookingCreated(FlightBooking Booking);
public record BookingNotFound(Guid BookingId);
public record FlightFullError(string FlightNumber, int AvailableSeats);
public record ValidationError(string Message);

// Request DTOs
public record CreateBookingRequest(
    [Required] string FlightNumber,
    [Required] string PassengerName,
    [Required] string Origin,
    [Required] string Destination,
    [Required] DateTime DepartureTime,
    [Range(0, double.MaxValue)] decimal Price
);

public record UpdateBookingRequest(
    [Required] string PassengerName
);

// Service Interface
public interface IFlightBookingService
{
    Task<OneOf<BookingCreated, ValidationError, FlightFullError>> CreateBookingAsync(CreateBookingRequest request);
    Task<OneOf<FlightBooking, BookingNotFound>> GetBookingAsync(Guid id);
    Task<OneOf<FlightBooking, BookingNotFound>> ConfirmBookingAsync(Guid id);
    Task<OneOf<FlightBooking, BookingNotFound>> CancelBookingAsync(Guid id);
    Task<IEnumerable<FlightBooking>> GetAllBookingsAsync();
    Task<OneOf<FlightBooking, BookingNotFound, ValidationError>> UpdateBookingAsync(Guid id, UpdateBookingRequest request);
}

// Service Implementation
public class FlightBookingService : IFlightBookingService
{
    private readonly Dictionary<Guid, FlightBooking> _bookings = new();
    private readonly Dictionary<string, int> _flightCapacity = new()
    {
        ["FL001"] = 2,
        ["FL002"] = 180,
        ["FL003"] = 250
    };

    public Task<OneOf<BookingCreated, ValidationError, FlightFullError>> CreateBookingAsync(CreateBookingRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.FlightNumber))
            return Task.FromResult<OneOf<BookingCreated, ValidationError, FlightFullError>>(
                new ValidationError("Flight number is required"));

        if (string.IsNullOrWhiteSpace(request.PassengerName))
            return Task.FromResult<OneOf<BookingCreated, ValidationError, FlightFullError>>(
                new ValidationError("Passenger name is required"));

        if (string.IsNullOrWhiteSpace(request.Origin))
            return Task.FromResult<OneOf<BookingCreated, ValidationError, FlightFullError>>(
                new ValidationError("Origin is required"));

        if (string.IsNullOrWhiteSpace(request.Destination))
            return Task.FromResult<OneOf<BookingCreated, ValidationError, FlightFullError>>(
                new ValidationError("Destination is required"));

        var availableSeats = GetAvailableSeats(request.FlightNumber);
        if (availableSeats <= 0)
            return Task.FromResult<OneOf<BookingCreated, ValidationError, FlightFullError>>(
                new FlightFullError(request.FlightNumber, 0));

        var booking = new FlightBooking(
            Guid.NewGuid(),
            request.FlightNumber,
            request.PassengerName,
            request.Origin,
            request.Destination,
            request.DepartureTime,
            request.Price,
            BookingStatus.Pending
        );

        _bookings[booking.Id] = booking;
        return Task.FromResult<OneOf<BookingCreated, ValidationError, FlightFullError>>(
            new BookingCreated(booking));
    }

    public Task<OneOf<FlightBooking, BookingNotFound>> GetBookingAsync(Guid id)
    {
        if (_bookings.TryGetValue(id, out var booking))
            return Task.FromResult<OneOf<FlightBooking, BookingNotFound>>(booking);

        return Task.FromResult<OneOf<FlightBooking, BookingNotFound>>(new BookingNotFound(id));
    }

    public Task<OneOf<FlightBooking, BookingNotFound>> ConfirmBookingAsync(Guid id)
    {
        if (!_bookings.TryGetValue(id, out var booking))
            return Task.FromResult<OneOf<FlightBooking, BookingNotFound>>(new BookingNotFound(id));

        var confirmed = booking with { Status = BookingStatus.Confirmed };
        _bookings[id] = confirmed;
        return Task.FromResult<OneOf<FlightBooking, BookingNotFound>>(confirmed);
    }

    public Task<OneOf<FlightBooking, BookingNotFound>> CancelBookingAsync(Guid id)
    {
        if (!_bookings.TryGetValue(id, out var booking))
            return Task.FromResult<OneOf<FlightBooking, BookingNotFound>>(new BookingNotFound(id));

        var cancelled = booking with { Status = BookingStatus.Cancelled };
        _bookings[id] = cancelled;
        return Task.FromResult<OneOf<FlightBooking, BookingNotFound>>(cancelled);
    }

    public Task<IEnumerable<FlightBooking>> GetAllBookingsAsync()
    {
        return Task.FromResult(_bookings.Values.AsEnumerable());
    }

    public Task<OneOf<FlightBooking, BookingNotFound, ValidationError>> UpdateBookingAsync(Guid id, UpdateBookingRequest request)
    {
        if (!_bookings.TryGetValue(id, out var booking))
            return Task.FromResult<OneOf<FlightBooking, BookingNotFound, ValidationError>>(new BookingNotFound(id));

        if (string.IsNullOrWhiteSpace(request.PassengerName))
            return Task.FromResult<OneOf<FlightBooking, BookingNotFound, ValidationError>>(
                new ValidationError("Passenger name is required"));

        var updated = booking with { PassengerName = request.PassengerName };
        _bookings[id] = updated;
        return Task.FromResult<OneOf<FlightBooking, BookingNotFound, ValidationError>>(updated);
    }

    private int GetAvailableSeats(string flightNumber)
    {
        if (!_flightCapacity.TryGetValue(flightNumber, out var capacity))
            return 10;

        var booked = _bookings.Values.Count(b => b.FlightNumber == flightNumber && b.Status != BookingStatus.Cancelled);
        return Math.Max(0, capacity - booked);
    }
}

// Controller
[ApiController]
[Route("api/[controller]")]
public class FlightBookingsController : ControllerBase
{
    private readonly IFlightBookingService _bookingService;

    public FlightBookingsController(IFlightBookingService bookingService)
    {
        _bookingService = bookingService;
    }

    [HttpGet("{id:guid}")]
    public async Task<IActionResult> GetBooking(Guid id)
    {
        var result = await _bookingService.GetBookingAsync(id);
        return result.Match(
            booking => Results.Ok(booking),
            notFound => Results.NotFound(new ProblemDetails
            {
                Title = "Booking Not Found",
                Status = StatusCodes.Status404NotFound,
                Detail = $"Booking with ID {notFound.BookingId} was not found"
            })
        );
    }

    [HttpGet]
    public async Task<IActionResult> GetAllBookings()
    {
        var bookings = await _bookingService.GetAllBookingsAsync();
        return Results.Ok(bookings);
    }

    [HttpPost]
    public async Task<IActionResult> CreateBooking([FromBody] CreateBookingRequest request)
    {
        var result = await _bookingService.CreateBookingAsync(request);
        return result.Match(
            created => Results.Created($"/api/flightbookings/{created.Booking.Id}", created.Booking),
            validationError => Results.BadRequest(new ProblemDetails
            {
                Title = "Validation Error",
                Status = StatusCodes.Status400BadRequest,
                Detail = validationError.Message
            }),
            flightFullError => Results.Problem(
                detail: $"Flight {flightFullError.FlightNumber} has no available seats. Available: {flightFullError.AvailableSeats}",
                statusCode: StatusCodes.Status409Conflict,
                title: "Flight Full"
            )
        );
    }

    [HttpPut("{id:guid}/confirm")]
    public async Task<IActionResult> ConfirmBooking(Guid id)
    {
        var result = await _bookingService.ConfirmBookingAsync(id);
        return result.Match(
            booking => Results.Ok(booking),
            notFound => Results.NotFound(new ProblemDetails
            {
                Title = "Booking Not Found",
                Status = StatusCodes.Status404NotFound,
                Detail = $"Booking with ID {notFound.BookingId} was not found"
            })
        );
    }

    [HttpPut("{id:guid}/cancel")]
    public async Task<IActionResult> CancelBooking(Guid id)
    {
        var result = await _bookingService.CancelBookingAsync(id);
        return result.Match(
            booking => Results.Ok(booking),
            notFound => Results.NotFound(new ProblemDetails
            {
                Title = "Booking Not Found",
                Status = StatusCodes.Status404NotFound,
                Detail = $"Booking with ID {notFound.BookingId} was not found"
            })
        );
    }

    [HttpPut("{id:guid}")]
    public async Task<IActionResult> UpdateBooking(Guid id, [FromBody] UpdateBookingRequest request)
    {
        var result = await _bookingService.UpdateBookingAsync(id, request);
        return result.Match(
            booking => Results.Ok(booking),
            notFound => Results.NotFound(new ProblemDetails
            {
                Title = "Booking Not Found",
