// Service Implementations
public class UserService : IUserService
{
    private readonly Dictionary<Guid, User> _users = new();
    private readonly Dictionary<string, string> _passwords = new();
    private readonly Dictionary<string, Guid> _emailIndex = new();

    private static readonly HashSet<string> ValidRoles = new() { "Admin", "Agent", "Customer" };

    public OneOf<User, UserAlreadyExists> RegisterUser(string email, string password, string role)
    {
        if (!ValidRoles.Contains(role))
            return new InvalidRole();

        if (_emailIndex.ContainsKey(email))
            return new UserAlreadyExists(email);

        var user = new User(Guid.NewGuid(), email, role);
        _users[user.Id] = user;
        _passwords[email] = password;
        _emailIndex[email] = user.Id;

        return user;
    }

    public OneOf<User, InvalidCredentials> ValidateUser(string email, string password)
    {
        if (!_emailIndex.TryGetValue(email, out var userId))
            return new InvalidCredentials();

        if (!_passwords.TryGetValue(email, out var storedPassword) || storedPassword != password)
            return new InvalidCredentials();

        return _users[userId];
    }

    public OneOf<User, UserNotFound> GetUserById(Guid id)
    {
        if (_users.TryGetValue(id, out var user))
            return user;
        return new UserNotFound(id);
    }
}

public class FlightService : IFlightService
{
    private readonly Dictionary<Guid, Flight> _flights = new();

    public Flight CreateFlight(FlightRequest request)
    {
        var flight = new Flight(Guid.NewGuid(), request.FlightNumber, request.Origin, request.Destination, request.DepartureTime, request.Capacity, request.BasePrice);
        _flights[flight.Id] = flight;
        return flight;
    }

    public OneOf<Flight, FlightNotFound> GetFlight(Guid id)
    {
        if (_flights.TryGetValue(id, out var flight))
            return flight;
        return new FlightNotFound(id);
    }

    public IEnumerable<Flight> GetAllFlights() => _flights.Values;

    public OneOf<Flight, FlightNotFound> UpdateFlight(Guid id, FlightRequest request)
    {
        if (!_flights.TryGetValue(id, out var existing))
            return new FlightNotFound(id);

        var updated = existing with
        {
            FlightNumber = request.FlightNumber,
            Origin = request.Origin,
            Destination = request.Destination,
            DepartureTime = request.DepartureTime,
            Capacity = request.Capacity,
            BasePrice = request.BasePrice
        };
        _flights[id] = updated;
        return updated;
    }

    public OneOf<Flight, FlightNotFound> UpdateCapacity(Guid id, int seatsBooked)
    {
        if (!_flights.TryGetValue(id, out var flight))
            return new FlightNotFound(id);

        var updated = flight with { Capacity = flight.Capacity - seatsBooked };
        _flights[id] = updated;
        return updated;
    }
}

public class BookingService : IBookingService
{
    private readonly Dictionary<Guid, Booking> _bookings = new();
    private readonly IFlightService _flightService;

    private static readonly HashSet<string> ValidStatuses = new() { "Pending", "Confirmed", "Cancelled" };

    public BookingService(IFlightService flightService)
    {
        _flightService = flightService;
    }

    public OneOf<Booking, FlightNotFound, InsufficientSeats> CreateBooking(Guid userId, BookingRequest request)
    {
        var flightResult = _flightService.GetFlight(request.FlightId);

        if (flightResult.IsT1)
            return new FlightNotFound(request.FlightId);

        var flight = flightResult.AsT0;

        if (flight.Capacity < request.SeatsBooked)
            return new InsufficientSeats(request.SeatsBooked, flight.Capacity);

        var totalPrice = request.SeatsBooked * flight.BasePrice;
        var booking = new Booking(
            Guid.NewGuid(),
            request.FlightId,
            userId,
            request.PassengerName,
            request.SeatsBooked,
            totalPrice,
            DateTime.UtcNow,
            "Pending"
        );

        _bookings[booking.Id] = booking;
        _flightService.UpdateCapacity(request.FlightId, request.SeatsBooked);

        return booking;
    }

    public OneOf<Booking, BookingNotFound> GetBooking(Guid id)
    {
        if (_bookings.TryGetValue(id, out var booking))
            return booking;
        return new BookingNotFound(id);
    }

    public OneOf<Booking, BookingNotFound, UnauthorizedAccess> CancelBooking(Guid bookingId, Guid userId)
    {
        if (!_bookings.TryGetValue(bookingId, out var booking))
            return new BookingNotFound(bookingId);

        if (booking.UserId != userId)
            return new UnauthorizedAccess();

        var cancelled = booking with { Status = "Cancelled" };
        _bookings[bookingId] = cancelled;

        return cancelled;
    }

    public OneOf<Booking, BookingNotFound> UpdateBookingStatus(Guid bookingId, string status)
    {
        if (!ValidStatuses.Contains(status))
            return new BookingNotFound(bookingId);

        if (!_bookings.TryGetValue(bookingId, out var booking))
            return new BookingNotFound(bookingId);

        var updated = booking with { Status = status };
        _bookings[bookingId] = updated;
        return updated;
    }

    public IEnumerable<Booking> GetUserBookings(Guid userId) =>
        _bookings.Values.Where(b => b.UserId == userId);

    public IEnumerable<Booking> GetAllBookings() => _bookings.Values;
}

public class JwtService : IJwtService
{
    private readonly IConfiguration _configuration;

    public JwtService(IConfiguration configuration)
    {
        _configuration = configuration;
    }

    public AuthToken GenerateToken(User user)
    {
        var jwtSettings = _configuration.GetSection("Jwt");
        var secretKey = jwtSettings["SecretKey"] ?? "DefaultSecretKeyForDevelopment12345678";
        var issuer = jwtSettings["Issuer"] ?? "AirlineBooking";
        var audience = jwtSettings["Audience"] ?? "AirlineBookingUsers";
        var expirationHours = int.Parse(jwtSettings["ExpirationHours"] ?? "24");

        var key = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(secretKey));
        var credentials = new SigningCredentials(key, SecurityAlgorithms.HmacSha256);

        var claims = new[]
        {
            new Claim(ClaimTypes.NameIdentifier, user.Id.ToString()),
            new Claim(ClaimTypes.Email, user.Email),
            new Claim(ClaimTypes.Role, user.Role)
        };

        var token = new JwtSecurityToken(
            issuer: issuer,
            audience: audience,
            claims: claims,
            expires: DateTime.UtcNow.AddHours(expirationHours),
            signingCredentials: credentials
        );

        var tokenString = new JwtSecurityTokenHandler().WriteToken(token);

        return new AuthToken(tokenString, user.Email, user.Role, token.ValidTo);
    }

    public ClaimsPrincipal? ValidateToken(string token)
    {
        var jwtSettings = _configuration.GetSection("Jwt");
        var secretKey = jwtSettings["SecretKey"] ?? "DefaultSecretKeyForDevelopment12345678";
        var issuer = jwtSettings["Issuer"] ?? "AirlineBooking";
        var audience = jwtSettings["Audience"] ?? "AirlineBookingUsers";

        var key = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(secretKey));

        try
        {
            var handler = new JwtSecurityTokenHandler();
            var validationParameters = new TokenValidationParameters
            {
                ValidateIssuer = true,
                ValidateAudience = true,
                ValidateLifetime = true,
                ValidateIssuerSigningKey = true,
                ValidIssuer = issuer,
                ValidAudience = audience,
                IssuerSigningKey = key
            };

            var principal = handler.ValidateToken(token, validationParameters, out _);
            return principal;
        }
        catch
        {
            return null;
        }
    }
}

