public class Example
{
    private readonly AppDbContext _context;

    public Example(AppDbContext context)
    {
        _context = context;
    }

    public List<UserOrderDto> GetUsersWithOrdersLeftJoin()
    {
        // EF Core 10 - New LeftJoin syntax
        var query = _context.Users
            .LeftJoin(
                _context.Orders,
                user => user.Id,
                order => order.UserId,
                (user, order) => new UserOrderDto
                {
                    UserName = user.Name,
                    OrderTotal = order != null ? order.Total : null
                }
            );

        return query.ToList();
    }

    public List<UserOrderDto> GetUsersWithOrdersLeftJoinWithOrderSelector()
    {
        // EF Core 10 - LeftJoin with result selector
        var query = from user in _context.Users
                    join order in _context.Orders
                        on user.Id equals order.UserId into orders
                    from order in orders.DefaultIfEmpty()
                    select new UserOrderDto
                    {
                        UserName = user.Name,
                        OrderTotal = order != null ? order.Total : null
                    };

        return query.ToList();
    }

    public List<UserOrderDto> GetUsersWithOrdersLeftJoinMultipleKeys()
    {
        // EF Core 10 - LeftJoin with composite key
        var query = _context.Users
            .LeftJoin(
                _context.Orders,
                user => new { user.Id, Active = true },
                order => new { Id = order.UserId, Active = order.Total > 0 },
                (user, order) => new UserOrderDto
                {
                    UserName = user.Name,
                    OrderTotal = order != null ? order.Total : null
                }
            );

        return query.ToList();
    }
}

