public class IoTDbContext : DbContext
{
    public DbSet<Sensor> Sensors { get; set; } = null!;
    public DbSet<SensorReading> SensorReadings { get; set; } = null!;
    public DbSet<SensorAlert> SensorAlerts { get; set; } = null!;

    public IoTDbContext(DbContextOptions<IoTDbContext> options) : base(options) { }

    protected override void OnModelCreating(ModelBuilder builder)
    {
        builder.Entity<Sensor>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.SerialNumber).IsRequired().HasMaxLength(50);
            entity.Property(e => e.Name).IsRequired().HasMaxLength(100);
            entity.Property(e => e.Location).IsRequired().HasMaxLength(200);
            entity.Property(e => e.Type).IsRequired();
            entity.Property(e => e.IsActive).HasDefaultValue(true);
            entity.Property(e => e.CreatedAt).HasDefaultValueSql("GETUTCDATE()");

            entity.HasMany(e => e.Readings)
                .WithOne(r => r.Sensor)
                .HasForeignKey(r => r.SensorId)
                .OnDelete(DeleteBehavior.Cascade);
        });

        builder.Entity<SensorReading>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Metadata).HasJsonConversion();
            entity.HasOne(e => e.Sensor)
                .WithMany(s => s.Readings)
                .HasForeignKey(e => e.SensorId)
                .OnDelete(DeleteBehavior.Cascade);
        });

        builder.Entity<SensorAlert>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.AlertType).IsRequired().HasMaxLength(50);
            entity.Property(e => e.Message).IsRequired().HasMaxLength(500);
            entity.Property(e => e.IsAcknowledged).HasDefaultValue(false);

            entity.HasOne(e => e.Sensor)
                .WithMany()
                .HasForeignKey(e => e.SensorId)
                .OnDelete(DeleteBehavior.Cascade);
        });
    }
}

