        public ApplicationDbContext(DbContextOptions<ApplicationDbContext> options)
            : base(options)
        {
        }

        protected override void OnModelCreating(ModelBuilder modelBuilder)
        {
            base.OnModelCreating(modelBuilder);

            // Configure Customer entity
            modelBuilder.Entity<Customer>(entity =>
            {
                entity.HasKey(e => e.Id);
                entity.Property(e => e.Name).IsRequired().HasMaxLength(100);

                // Complex type is automatically mapped to JSON column in EF Core 10
                entity.ComplexProperty(e => e.Contact);
            });

            // Configure Order entity
            modelBuilder.Entity<Order>(entity =>
            {
                entity.HasKey(e => e.Id);
                entity.Property(e => e.OrderNumber).IsRequired().HasMaxLength(50);

                entity.HasOne(e => e.Customer)
                    .WithMany(c => c.Orders)
                    .HasForeignKey(e => e.CustomerId)
                    .OnDelete(DeleteBehavior.SetNull);

                // Complex type mapped to JSON column
                entity.ComplexProperty(e => e.Metadata);
            });

            // Configure Product entity
            modelBuilder.Entity<Product>(entity =>
            {
                entity.HasKey(e => e.Id);
                entity.Property(e => e.Name).IsRequired().HasMaxLength(200);
            });

            // Configure OrderDetail entity
            modelBuilder.Entity<OrderDetail>(entity =>
            {
                entity.HasKey(e => e.Id);

                entity.HasOne(e => e.Order)
                    .WithMany()
                    .HasForeignKey(e => e.OrderId)
                    .OnDelete(DeleteBehavior.Cascade);

                entity.HasOne(e => e.Product)
                    .WithMany()
                    .HasForeignKey(e => e.ProductId)
                    .OnDelete(DeleteBehavior.Restrict);
            });
        }
    }

    public class OrderService
    {
        private readonly ApplicationDbContext _context;

        public OrderService(ApplicationDbContext context)
        {
            _context = context;
        }

        // Left Join - New EF Core 10 syntax
        public IEnumerable<OrderWithCustomerDto> GetOrdersWithCustomers()
        {
            var query = _context.Orders
                .LeftJoin(
                    _context.Customers,
                    order => order.CustomerId,
                    customer => customer.Id,
                    (order, customer) => new OrderWithCustomerDto
                    {
                        OrderId = order.Id,
                        OrderNumber = order.OrderNumber,
                        TotalAmount = order.TotalAmount,
                        OrderDate = order.OrderDate,
                        CustomerId = order.CustomerId,
                        CustomerName = customer == null ? "N/A" : customer.Name,
                        CustomerEmail = customer == null ? "N/A" : customer.Contact.Email
                    });

            return query.ToList();
        }

        // Left Join with additional filtering
        public IEnumerable<OrderWithCustomerDto> GetRecentOrdersWithCustomers(int daysBack = 30)
        {
            var cutoffDate = DateTime.UtcNow.AddDays(-daysBack);

            var query = _context.Orders
                .Where(o => o.OrderDate >= cutoffDate)
                .LeftJoin(
                    _context.Customers,
                    order => order.CustomerId,
                    customer => customer.Id,
                    (order, customer) => new OrderWithCustomerDto
                    {
                        OrderId = order.Id,
                        OrderNumber = order.OrderNumber,
                        TotalAmount = order.TotalAmount,
                        OrderDate = order.OrderDate,
                        Status = order.Status.ToString(),
                        CustomerId = order.CustomerId,
                        CustomerName = customer == null ? "Walk-in Customer" : customer.Name,
                        CustomerEmail = customer == null ? string.Empty : customer.Contact.Email,
                        CustomerCity = customer == null ? string.Empty : customer.Contact.Address.City
                    });

            return query.OrderByDescending(x => x.OrderDate).ToList();
        }

        // Multiple Left Joins
        public IEnumerable<OrderSummaryDto> GetOrderSummaries()
        {
            var query = _context.Orders
                .LeftJoin(
                    _context.Customers,
                    order => order.CustomerId,
                    customer => customer.Id,
                    (order, customer) => new { order, customer }
                )
                .LeftJoin(
                    _context.OrderDetails,
                    oc => oc.order.Id,
                    detail => detail.OrderId,
                    (oc, detail) => new { oc.order, oc.customer, detail }
                )
                .GroupBy(x => new { x.order.Id, x.order.OrderNumber, x.customer })
                .Select(g => new OrderSummaryDto
                {
                    OrderId = g.Key.Id,
                    OrderNumber = g.Key.OrderNumber,
                    CustomerName = g.Key.customer == null ? "N/A" : g.Key.customer.Name,
                    TotalItems = g.Sum(x => x.detail.Quantity),
                    TotalValue = g.Sum(x => x.detail.Quantity * x.detail.UnitPrice)
                });

            return query.ToList();
        }

        // Query with Complex Type filtering
        public IEnumerable<Customer> GetCustomersByCity(string city)
        {
            return _context.Customers
                .Where(c => c.Contact.Address.City == city)
                .ToList();
        }

        // Query with Complex Type nested property
        public IEnumerable<Customer> GetCustomersByCountry(string country)
        {
            return _context.Customers
                .Where(c => c.Contact.Address.Country == country)
                .OrderBy(c => c.Contact.Address.State)
                .ThenBy(c => c.Contact.Address.City)
                .ToList();
        }

        // Create order with complex type
        public Order CreateOrder(string orderNumber, int? customerId, decimal totalAmount, 
            string source, string campaign, List<string> tags)
        {
            var order = new Order
            {
                OrderNumber = orderNumber,
                CustomerId = customerId,
                TotalAmount = totalAmount,
                OrderDate = DateTime.UtcNow,
                Status = OrderStatus.Pending,
                Metadata = new OrderMetadata
                {
                    Source = source,
                    Campaign = campaign,
                    Tags = tags
                }
            };

            _context.Orders.Add(order);
            _context.SaveChanges();

            return order;
        }

        // Create customer with complex type
        public Customer CreateCustomer(string name, string email, string phone, 
            string street, string city, string state, string zipCode, string country)
        {
            var customer = new Customer
            {
                Name = name,
                Contact = new ContactInfo
                {
                    Email = email,
                    Phone = phone,
                    Address = new Address
                    {
                        Street = street,
                        City = city,
                        State = state,
                        ZipCode = zipCode,
                        Country = country
                    }
                }
            };

            _context.Customers.Add(customer);
            _context.SaveChanges();

            return customer;
        }

        // Update complex type properties
        public void UpdateCustomerAddress(int customerId, Address newAddress)
        {
            var customer = _context.Customers.Find(customerId);
            if (customer != null)
            {
                customer.Contact.Address = newAddress;
                _context.SaveChanges();
            }
        }

        // Query orders by metadata tags (JSON column query)
        public IEnumerable<Order> GetOrdersByTag(string tag)
        {
            return _context.Orders
                .Where(o => o.Metadata.Tags.Contains(tag))
                .ToList();
        }

        // Left join with aggregation
        public IEnumerable<CustomerOrderStatsDto> GetCustomerOrderStatistics()
        {
            var query = _context.Customers
                .LeftJoin(
                    _context.Orders,
                    customer => customer.Id,
                    order => order.CustomerId,
                    (customer, order) => new { customer, order }
                )
                .GroupBy(x => x.customer)
                .Select(g => new CustomerOrderStatsDto
                {
                    CustomerId = g.Key.Id,
                    CustomerName = g.Key.Name,
                    TotalOrders = g.Count(x => x.order != null),
                    TotalSpent = g.Where(x => x.order != null).Sum(x => x.order.TotalAmount),
                    LastOrderDate = g.Where(x => x.order != null)
                        .Max(x => (DateTime?)x.order.OrderDate)
                });

            return query.ToList();
        }
    }

