    public EnrollmentDbContext(DbContextOptions<EnrollmentDbContext> options) : base(options) { }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Student>(builder =>
        {
            builder.HasKey(s => s.Id);
            builder.Property(s => s.FirstName).IsRequired().HasMaxLength(100);
            builder.Property(s => s.LastName).IsRequired().HasMaxLength(100);
            builder.Property(s => s.Email).IsRequired().HasMaxLength(255);
            builder.Property(s => s.IsActive).HasDefaultValue(true);
            builder.Property(s => s.Summary).HasJsonConversion();
        });

        modelBuilder.Entity<Course>(builder =>
        {
            builder.HasKey(c => c.Id);
            builder.Property(c => c.Title).IsRequired().HasMaxLength(200);
            builder.Property(c => c.Department).IsRequired().HasMaxLength(100);
            builder.Property(c => c.Credits);
            builder.Property(c => c.IsOpen).HasDefaultValue(true);
        });

        modelBuilder.Entity<Enrollment>(builder =>
        {
            builder.HasKey(e => e.Id);
            builder.Property(e => e.Status).IsRequired();

            builder.HasOne(e => e.Student)
                .WithMany(s => s.Enrollments)
                .HasForeignKey(e => e.StudentId)
                .OnDelete(DeleteBehavior.Cascade);

            builder.HasOne(e => e.Course)
                .WithMany(c => c.Enrollments)
                .HasForeignKey(e => e.CourseId)
                .OnDelete(DeleteBehavior.Cascade);
        });
    }
}

