        db.Customers.Add(new Customer { Id = 1, Name = "Alice" });
        db.Customers.Add(new Customer { Id = 2, Name = "Bob" });
        db.Orders.Add(new Order { Id = 1, CustomerId = 1, Total = 100 });
        db.Orders.Add(new Order { Id = 2, CustomerId = 1, Total = 200 });
        db.Orders.Add(new Order { Id = 3, CustomerId = null, Total = 50 });
        db.SaveChanges();

        // EF Core 10 Left Join
        var query = db.Orders
            .LeftJoin(
                db.Customers,
                order => order.CustomerId,
                customer => customer.Id,
                (order, customer) => new OrderResult
                {
                    OrderId = order.Id,
                    Total = order.Total,
                    CustomerName = customer != null ? customer.Name : "No Customer"
                });

        var results = query.ToList();

        foreach (var r in results)
        {
            System.Console.WriteLine($"Order {r.OrderId}: ${r.Total} - Customer: {r.CustomerName}");
        }
    }
}

