// Component demonstrating render modes and streaming SSR
public partial class ProductListComponent : ComponentBase
{
    [Inject]
    private IProductService ProductService { get; set; } = default!;

    [Inject]
    private ProtectedLocalStorage LocalStorage { get; set; } = default!;

    [Parameter]
    public string? Category { get; set; }

    [SupplyParameterFromQuery]
    public int Page { get; set; } = 1;

    [CascadingParameter]
    private Task<AuthenticationState>? AuthState { get; set; }

    private IEnumerable<Product>? products;
    private bool isLoading = true;
    private string? persistentPreference;

    protected override async Task OnInitializedAsync()
    {
        // Streaming SSR - content renders incrementally
        products = await ProductService.GetProductsAsync(Category, Page);
        isLoading = false;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            // Persistent state across prerendering
            var result = await LocalStorage.GetAsync<string>("viewPreference");
            persistentPreference = result.Success ? result.Value : "grid";
            StateHasChanged();
        }
    }

    private async Task SavePreferenceAsync(string preference)
    {
        await LocalStorage.SetAsync("viewPreference", preference);
        persistentPreference = preference;
    }

    private RenderFragment RenderProductList() => builder =>
    {
        if (isLoading)
        {
            builder.AddContent(0, "<p>Loading products...</p>");
            return;
        }

        if (products == null || !products.Any())
        {
            builder.AddContent(1, "<p>No products found.</p>");
            return;
        }

        foreach (var product in products)
        {
            builder.OpenElement(2, "div");
            builder.AddAttribute(3, "class", "product-card");
            builder.AddContent(4, product.Name);
            builder.CloseElement();
        }
    };
}

