@code {
    [SupplyParameterFromPersistentComponentState]
    public CartState? CartState { get; set; }

    [Parameter]
    public string? Category { get; set; }

    private List<Product>? products;
    private List<CartItem> cartItems = new();

    protected override async Task OnInitializedAsync()
    {
        // Restore cart state from persistent storage
        if (CartState is not null)
        {
            cartItems = CartState.Items ?? new List<CartItem>();
        }

        // Simulate async data loading (streaming SSR will show content incrementally)
        products = await ProductService.GetProductsAsync(Category);
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // Persist cart state for prerender
            var state = new CartState { Items = cartItems };
            PersistentState.PersistAsJson(nameof(CartState), state);
        }
    }

    private void AddToCart(Product product)
    {
        var existingItem = cartItems.FirstOrDefault(i => i.ProductId == product.Id);
        if (existingItem is not null)
        {
            existingItem.Quantity++;
        }
        else
        {
            cartItems.Add(new CartItem 
            { 
                ProductId = product.Id, 
                ProductName = product.Name, 
                Price = product.Price, 
                Quantity = 1 
            });
        }
    }

    private decimal GetCartTotal()
    {
        return cartItems.Sum(i => i.Price * i.Quantity);
    }

    private string GetCurrentRenderMode()
    {
        return RendererInfo.Name switch
        {
            "InteractiveServer" => "Server (SignalR)",
            "InteractiveWebAssembly" => "WebAssembly",
            "InteractiveAuto" => "Auto",
            _ => RendererInfo.Name
        };
    }
}

