[StreamRendering]
public class OrderList : ComponentBase
{
    [Inject] public IOrderService? Orders { get; set; }
    [SupplyParameterFromPersistentComponentState]
    public OrderListState? State { get; set; }

    private IEnumerable<Order>? _orders;

    protected override async Task OnInitializedAsync()
    {
        if (State?.Orders != null)
        {
            _orders = State.Orders;
        }
        else if (Orders != null)
        {
            _orders = await Orders.GetOrdersAsync();
        }
    }

    protected override void BuildRenderTree(RenderTreeBuilder builder)
    {
        builder.OpenElement(0, "div");
        builder.AddAttribute(1, "class", Theme?.IsDarkMode == true ? "dark-theme" : "light-theme");

        builder.OpenElement(2, "h2");
        builder.AddContent(3, "Orders");
        builder.CloseElement();

        if (_orders == null)
        {
            builder.OpenElement(4, "p");
            builder.AddContent(5, "Loading...");
            builder.CloseElement();
        }
        else
        {
            foreach (var order in _orders)
            {
                builder.OpenElement(6, "div");
                builder.AddAttribute(7, "key", order.Id);

                builder.OpenElement(8, "p");
                builder.AddContent(9, $"{order.ProductName} - Qty: {order.Quantity} - ${order.TotalPrice}");
                builder.CloseElement();

                builder.CloseElement();
            }
        }

        builder.CloseElement();
    }

    [CascadingParameter] public ThemeState? Theme { get; set; }
}

