    // Component Parameters
    [Parameter]
    public string Category { get; set; } = string.Empty;

    [Parameter]
    public int PageSize { get; set; } = 10;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    // Persistent State across prerender
    [SupplyParameterFromPersistentComponentState]
    public ProductListState? State { get; set; }

    // Cascading values
    [CascadingParameter]
    public UserContext? UserContext { get; set; }

    // Injected services
    [Inject]
    public IProductService ProductService { get; set; } = default!;

    [Inject]
    public PersistentComponentState PersistentState { get; set; } = default!;

    private List<Product>? products;
    private bool isLoading = true;

    protected override async Task OnInitializedAsync()
    {
        if (State != null)
        {
            products = State.Products;
            isLoading = false;
        }
        else
        {
            await LoadProductsAsync();
        }
    }

    private async Task LoadProductsAsync()
    {
        isLoading = true;

        try
        {
            products = await ProductService.GetProductsAsync(Category, PageSize);

            // Persist state for prerender
            PersistentState.PersistAsJson(nameof(ProductListState), 
                new ProductListState { Products = products });
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleProductClick(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }
}

