            @if (overdueBooks.Any())
            {
                <div class="table-container">
                    <table class="data-table overdue-table">
                        <thead>
                            <tr>
                                <th>Title</th>
                                <th>Author</th>
                                <th>ISBN</th>
                                <th>Due Date</th>
                                <th>Days Overdue</th>
                                <th>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var book in overdueBooks)
                            {
                                var daysOverdue = (int)(DateTime.Today - book.DueDate!.Value).TotalDays;
                                <tr class="@(daysOverdue > 7 ? "critical-overdue" : "")">
                                    <td>@book.Title</td>
                                    <td>@book.Author</td>
                                    <td><code>@book.ISBN</code></td>
                                    <td>@book.DueDate?.ToString("MMM dd, yyyy")</td>
                                    <td><span class="days-overdue">@daysOverdue days</span></td>
                                    <td>
                                        <button class="btn btn-sm btn-primary" 
                                                @onclick="() => HandleReturnBookAsync(book.Id)"
                                                disabled="isProcessingBook == book.Id">
                                            @if (isProcessingBook == book.Id)
                                            {
                                                <span class="spinner"></span>
                                            }
                                            else
                                            {
                                                <span>Mark Returned</span>
                                            }
                                        </button>
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <div class="empty-state">
                    <p>🎉 No overdue books!</p>
                </div>
            }
        </section>

        <!-- Recent Transactions Section -->
        <section class="transactions-section">
            <div class="section-header">
                <h2>Recent Transactions</h2>
                <button class="btn btn-secondary btn-sm" @onclick="LoadDataAsync" disabled="isLoading">
                    @if (isLoading)
                    {
                        <span>Refreshing...</span>
                    }
                    else
                    {
                        <span>🔄 Refresh</span>
                    }
                </button>
            </div>
            @if (recentTransactions.Any())
            {
                <div class="table-container">
                    <table class="data-table transactions-table">
                        <thead>
                            <tr>
                                <th>Type</th>
                                <th>Book ID</th>
                                <th>Patron ID</th>
                                <th>Date</th>
                                <th>Status</th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var transaction in recentTransactions)
                            {
                                <tr class="@GetTransactionRowClass(transaction.Type)">
                                    <td>
                                        <span class="transaction-type @transaction.Type.ToString().ToLower()">
                                            @GetTransactionIcon(transaction.Type) @transaction.Type
                                        </span>
                                    </td>
                                    <td><code>@transaction.BookId.ToString()[..8]...</code></td>
                                    <td><code>@transaction.PatronId.ToString()[..8]...</code></td>
                                    <td>@transaction.CheckoutDate.ToString("MMM dd, yyyy HH:mm")</td>
                                    <td>
                                        @if (transaction.ReturnDate.HasValue)
                                        {
                                            <span class="status completed">Completed</span>
                                        }
                                        else
                                        {
                                            <span class="status active">Active</span>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <div class="empty-state">
                    <p>No recent transactions</p>
                </div>
            }
        </section>

        <!-- Quick Actions Panel -->
        <section class="quick-actions">
            <h2>Quick Actions</h2>
            <div class="action-forms">
                <div class="form-group">
                    <h3>Checkout Book</h3>
                    <div class="form-row">
                        <input type="text" placeholder="Book ID" @bind="checkoutBookId" @bind:event="oninput" />
                        <input type="text" placeholder="Patron ID" @bind="checkoutPatronId" @bind:event="oninput" />
                        <button class="btn btn-primary" @onclick="HandleCheckoutAsync" 
                                disabled="string.IsNullOrEmpty(checkoutBookId) || string.IsNullOrEmpty(checkoutPatronId) || isProcessingCheckout">
                            @if (isProcessingCheckout)
                            {
                                <span>Processing...</span>
                            }
                            else
                            {
                                <span>Checkout</span>
                            }
                        </button>
                    </div>
                    @if (!string.IsNullOrEmpty(checkoutMessage))
                    {
                        <p class="form-message @checkoutSuccess">@checkoutMessage</p>
                    }
                </div>
            </div>
        </section>
    </div>
</div>

