    // Basic component example
    public class CounterComponent : ComponentBase
    {
        protected int currentCount = 0;

        [Parameter]
        public int IncrementAmount { get; set; } = 1;

        [Parameter]
        public EventCallback<int> CountChanged { get; set; }

        [SupplyParameterFromQuery]
        public string? InitialValue { get; set; }

        [CascadingParameter]
        public ThemeInfo? Theme { get; set; }

        protected override void OnInitialized()
        {
            if (int.TryParse(InitialValue, out var value))
            {
                currentCount = value;
            }
        }

        protected override async Task OnInitializedAsync()
        {
            await Task.Delay(100);
        }

        protected override void OnParametersSet()
        {
            if (IncrementAmount <= 0)
                IncrementAmount = 1;
        }

        protected override async Task OnParametersSetAsync()
        {
            await Task.CompletedTask;
        }

        protected override void OnAfterRender(bool firstRender)
        {
            if (firstRender)
            {
                Console.WriteLine("First render complete");
            }
        }

        protected override async Task OnAfterRenderAsync(bool firstRender)
        {
            if (firstRender)
            {
                await Task.Delay(50);
            }
        }

        protected override bool ShouldRender()
        {
            return true;
        }

        protected void IncrementCount()
        {
            currentCount += IncrementAmount;
            CountChanged.InvokeAsync(currentCount);
        }

        protected override void BuildRenderTree(RenderTreeBuilder builder)
        {
            builder.OpenElement(0, "div");
            builder.AddAttribute(1, "class", "counter");
            builder.AddContent(2, $"Current count: {currentCount}");
            builder.CloseElement();
        }
    }

