    public class JsInteropExample : ComponentBase, IAsyncDisposable
    {
        [Inject]
        public required IJSRuntime JS { get; set; }

        private IJSObjectReference? module;

        protected override async Task OnAfterRenderAsync(bool firstRender)
        {
            if (firstRender)
            {
                module = await JS.InvokeAsync<IJSObjectReference>("import", "./js/example.js");
            }
        }

        protected async Task ShowAlertAsync(string message)
        {
            await JS.InvokeVoidAsync("alert", message);
        }

        protected async Task<string> PromptAsync(string message)
        {
            return await JS.InvokeAsync<string>("prompt", message) ?? string.Empty;
        }

        protected async Task<T?> CallModuleFunctionAsync<T>(string identifier, params object[] args)
        {
            if (module is not null)
            {
                return await module.InvokeAsync<T>(identifier, args);
            }
            return default;
        }

        public async ValueTask DisposeAsync()
        {
            if (module is not null)
            {
                try
                {
                    await module.DisposeAsync();
                }
                catch (JSDisconnectedException)
                {
                    // Circuit already disconnected
                }
            }
        }
    }

