@code {
    private IEnumerable<JobApplication>? _applications;
    private DashboardStatistics? _statistics;
    private JobApplication? _selectedApplication;
    private string _notesBuffer = "";
    private readonly List<StatusUpdate> _recentUpdates = new();
    private readonly Dictionary<Guid, Action<StatusUpdate>> _subscriptions = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && _applications != null)
        {
            foreach (var app in _applications)
            {
                var appId = app.Id;
                Action<StatusUpdate> callback = HandleStatusUpdate;
                _subscriptions[appId] = callback;
                await NotificationService.SubscribeToUpdatesAsync(appId, callback);
            }
        }
    }

    private async Task LoadDataAsync()
    {
        _applications = await Repository.GetAllAsync();
        _statistics = await NotificationService.GetStatisticsAsync();
        StateHasChanged();
    }

    private async void HandleStatusUpdate(StatusUpdate update)
    {
        _recentUpdates.Add(update);

        if (_applications != null)
        {
            var app = _applications.FirstOrDefault(a => a.Id == update.ApplicationId);
            if (app != null)
            {
                var updatedApp = app with { Status = update.NewStatus, LastUpdated = update.Timestamp };
                _applications = _applications.Select(a => a.Id == update.ApplicationId ? updatedApp : a);
            }
        }

        _statistics = await NotificationService.GetStatisticsAsync();
        await InvokeAsync(StateHasChanged);
    }

    private async Task HandleStatusChange(JobApplication application, ChangeEventArgs e)
    {
        if (e.Value != null && Enum.TryParse<ApplicationStatus>(e.Value.ToString(), out var newStatus))
        {
            await Repository.UpdateStatusAsync(application.Id, newStatus, "CurrentUser");
            var update = new StatusUpdate(application.Id, newStatus, DateTime.UtcNow, "CurrentUser");
            HandleStatusUpdate(update);
        }
    }

    private void ShowNotes(JobApplication application)
    {
        _selectedApplication = application;
        _notesBuffer = application.RecruiterNotes;
    }

    private async Task SaveNotes()
    {
        if (_selectedApplication != null)
        {
            var updatedApp = _selectedApplication with { RecruiterNotes = _notesBuffer, LastUpdated = DateTime.UtcNow };
            await Repository.UpdateAsync(updatedApp);
            _applications = await Repository.GetAllAsync();
            _selectedApplication = null;
            _notesBuffer = "";
            StateHasChanged();
        }
    }

    private void CloseModal()
    {
        _selectedApplication = null;
        _notesBuffer = "";
    }

    private static string GetStatusClass(ApplicationStatus status) => status switch
    {
        ApplicationStatus.Submitted => "status-submitted",
        ApplicationStatus.UnderReview => "status-review",
        ApplicationStatus.InterviewScheduled => "status-interview-scheduled",
        ApplicationStatus.InterviewCompleted => "status-interview-completed",
        ApplicationStatus.OfferExtended => "status-offer",
        ApplicationStatus.Hired => "status-hired",
        ApplicationStatus.Rejected => "status-rejected",
        _ => ""
    };

    public async ValueTask DisposeAsync()
    {
        foreach (var subscription in _subscriptions)
        {
            await NotificationService.UnsubscribeAsync(subscription.Key, subscription.Value);
        }
    }

    public enum ApplicationStatus
    {
        Submitted,
        UnderReview,
        InterviewScheduled,
        InterviewCompleted,
        OfferExtended,
        Hired,
        Rejected
    }

    public record JobApplication(
        Guid Id,
        string CandidateName,
        string Position,
        string Department,
        ApplicationStatus Status,
        DateTime AppliedDate,
        DateTime? LastUpdated,
        string RecruiterNotes
    );

    public record StatusUpdate(
        Guid ApplicationId,
        ApplicationStatus NewStatus,
        DateTime Timestamp,
        string UpdatedBy
    );

    public record DashboardStatistics(
        int TotalApplications,
        int PendingReview,
        int InInterview,
        int OffersExtended,
        int Hired,
        int Rejected
    );

    public interface IApplicationNotificationService
    {
        Task SubscribeToUpdatesAsync(Guid applicationId, Action<StatusUpdate> callback);
        Task UnsubscribeAsync(Guid applicationId, Action<StatusUpdate> callback);
        Task<DashboardStatistics> GetStatisticsAsync();
    }

    public interface IJobApplicationRepository
    {
        Task<IEnumerable<JobApplication>> GetAllAsync();
        Task<JobApplication?> GetByIdAsync(Guid id);
        Task UpdateStatusAsync(Guid id, ApplicationStatus status, string updatedBy);
        Task UpdateAsync(JobApplication application);
    }
}

