public class OrderConsumerDefinition : ConsumerDefinition<OrderConsumer>
{

using MassTransit;
using Microsoft.Extensions.DependencyInjection;
using System;
using System.Threading.Tasks;

public record OrderPlaced(Guid OrderId);
public record OrderProcessed(Guid OrderId);

public class OrderConsumer : IConsumer<OrderPlaced>
{
    public async Task Consume(ConsumeContext<OrderPlaced> context)
    {
        var msg = context.Message;
        await context.Publish(new OrderProcessed(msg.OrderId));
    }
}

public class OrderConsumerDefinition : ConsumerDefinition<OrderConsumer>
{
    public OrderConsumerDefinition()
    {
        // Limit the number of concurrent messages consumed
        ConcurrentMessageLimit = 4;
    }

    protected override void ConfigureConsumer(IReceiveEndpointConfigurator endpointConfigurator, IConsumerConfigurator<OrderConsumer> consumerConfigurator, IRegistrationContext context)
    {
        // Configure retry policy
        endpointConfigurator.UseMessageRetry(r => r.Intervals(
            TimeSpan.FromSeconds(1), 
            TimeSpan.FromSeconds(2), 
            TimeSpan.FromSeconds(5)));

        // Configure In-Memory Outbox
        endpointConfigurator.UseInMemoryOutbox(context);
    }
}

public static class ServiceCollectionExtensions
{
    public static void ConfigureMassTransit(this IServiceCollection services)
    {
        services.AddMassTransit(x =>
        {
            x.AddConsumer<OrderConsumer, OrderConsumerDefinition>();

            x.UsingInMemory((context, cfg) =>
            {
                cfg.ConfigureEndpoints(context);
            });
        });
    }
}

