using MassTransit;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using System;
using System.Threading.Tasks;

namespace MassTransitExample
{
    // Message Contracts
    public interface SubmitOrder
    {
        Guid OrderId { get; }
        string CustomerId { get; }
        DateTime OrderDate { get; }
    }

    public interface OrderSubmitted
    {
        Guid OrderId { get; }
        string CustomerId { get; }
        DateTime OrderDate { get; }
    }

    public interface CheckOrderStatus
    {
        Guid OrderId { get; }
    }

    public interface OrderStatusResult
    {
        Guid OrderId { get; }
        string Status { get; }
    }

    // Consumer
    public class SubmitOrderConsumer : IConsumer<SubmitOrder>
    {
        public async Task Consume(ConsumeContext<SubmitOrder> context)
        {
            var message = context.Message;

            Console.WriteLine($"Processing order {message.OrderId} for customer {message.CustomerId}");

            await context.Publish<OrderSubmitted>(new
            {
                message.OrderId,
                message.CustomerId,
                message.OrderDate
            });

            Console.WriteLine($"Order {message.OrderId} submitted successfully");
        }
    }

    public class OrderStatusConsumer : IConsumer<CheckOrderStatus>
    {
        public async Task Consume(ConsumeContext<CheckOrderStatus> context)
        {
            var message = context.Message;

            await context.RespondAsync<OrderStatusResult>(new
            {
                OrderId = message.OrderId,
                Status = "Processing"
            });
        }
    }

    // Saga State Machine
    public class OrderState : SagaStateMachineInstance
    {
        public Guid CorrelationId { get; set; }
        public string CurrentState { get; set; }
        public string CustomerId { get; set; }
        public DateTime OrderDate { get; set; }
    }

    public class OrderStateMachine : MassTransitStateMachine<OrderState>
    {
        public OrderStateMachine()
        {
            InstanceState(x => x.CurrentState);

            Event(() => OrderSubmitted, x => x.CorrelateById(m => m.Message.OrderId));

            Initially(
                When(OrderSubmitted)
                    .Then(context =>
                    {
                        context.Instance.CustomerId = context.Data.CustomerId;
                        context.Instance.OrderDate = context.Data.OrderDate;
                    })
                    .TransitionTo(Submitted)
            );
        }

        public State Submitted { get; private set; }
        public Event<OrderSubmitted> OrderSubmitted { get; private set; }
    }

    // Program
    class Program
    {
        static async Task Main(string[] args)
        {
            var host = Host.CreateDefaultBuilder(args)
                .ConfigureServices((hostContext, services) =>
                {
                    services.AddMassTransit(x =>
                    {
                        x.AddConsumer<SubmitOrderConsumer>();
                        x.AddConsumer<OrderStatusConsumer>();

                        x.AddSagaStateMachine<OrderStateMachine, OrderState>()
                            .InMemoryRepository();

                        x.UsingRabbitMq((context, cfg) =>
                        {
                            cfg.Host("rabbitmq://localhost");

                            cfg.ReceiveEndpoint("submit-order", e =>
                            {
                                e.ConfigureConsumer<SubmitOrderConsumer>(context);
                            });

                            cfg.ReceiveEndpoint("order-status", e =>
                            {
                                e.ConfigureConsumer<OrderStatusConsumer>(context);
                            });

                            cfg.ConfigureEndpoints(context);
                        });
                    });

                    services.AddHostedService<Worker>();
                })
                .Build();

            await host.RunAsync();
        }
    }

    public class Worker : IHostedService
    {
        private readonly IBus _bus;

        public Worker(IBus bus)
        {
            _bus = bus;
        }

        public async Task StartAsync(System.Threading.CancellationToken cancellationToken)
        {
            var orderId = Guid.NewGuid();

            await _bus.Publish<SubmitOrder>(new
            {
                OrderId = orderId,
                CustomerId = "CUSTOMER-001",
                OrderDate = DateTime.UtcNow
            });

            Console.WriteLine($"Published SubmitOrder message with OrderId: {orderId}");

            var client = _bus.CreateRequestClient<CheckOrderStatus>(TimeSpan.FromSeconds(30));
            var response = await client.GetResponse<OrderStatusResult>(new { OrderId = orderId });

            Console.WriteLine($"Order Status: {response.Message.Status}");
        }

        public Task StopAsync(System.Threading.CancellationToken cancellationToken)
        {
            return Task.CompletedTask;
        }
    }
}

