public class InMemoryShipmentRepository : IShipmentRepository
{
    private readonly Dictionary<Guid, ShipmentEntity> _shipments = new();

    public Task CreateAsync(ShipmentEntity shipment)
    {
        _shipments[shipment.ShipmentId] = shipment;
        return Task.CompletedTask;
    }

    public Task UpdateStatusAsync(Guid shipmentId, string status, string location, DateTime timestamp)
    {
        if (_shipments.TryGetValue(shipmentId, out var shipment))
        {
            shipment.Status = status;
            shipment.CurrentLocation = location;
            shipment.LastUpdated = timestamp;
        }
        return Task.CompletedTask;
    }

    public Task MarkAsArrivedAsync(Guid shipmentId, string destinationWarehouse, DateTime arrivedAt)
    {
        if (_shipments.TryGetValue(shipmentId, out var shipment))
        {
            shipment.Status = "Arrived";
            shipment.CurrentLocation = destinationWarehouse;
            shipment.LastUpdated = arrivedAt;
        }
        return Task.CompletedTask;
    }
}

